-- Poems batch 27
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('4ca69275-b6e0-4ba4-b6bb-15c60e2755d8','同樂天中秋夜洛河翫月二首 二','裴夷直','唐','唐诗','tang','','[]','不熱不寒三五夕，晴川明月正相臨。',64,'全唐诗/poet.tang.27000.json','["不熱不寒三五夕，晴川明月正相臨。", "千珠競沒蒼龍頷，一鏡高懸白帝心。", "幾處淒涼緣地遠，有時惆悵值雲陰。", "如何清洛如清晝，共見初升又見沈。"]'),
('39a9c5be-5c56-4a01-9634-3f20c87910f4','和邢郎中病中重陽強遊樂遊原','裴夷直','唐','唐诗','tang','','[]','嘉晨令節共陶陶，風景牽情並不勞。',64,'全唐诗/poet.tang.27000.json','["嘉晨令節共陶陶，風景牽情並不勞。", "曉日整冠蘭室靜，秋原騎馬菊花高。", "晴光一一呈金剎，詩思浸浸逼水曹。", "何必銷憂憑外物，祗將清韻敵春醪。"]'),
('8d9d4cb8-12a4-4302-9e2d-97518ef94a2c','觀淬龍泉劒','裴夷直','唐','唐诗','tang','','[]','歐冶將成器，風胡幸見逢。',72,'全唐诗/poet.tang.27000.json','["歐冶將成器，風胡幸見逢。", "發硎思剸玉，投水化爲龍。", "詎肯藏深匣，終朝用刜鐘。", "蓮花生寶鍔，秋日勵霜鋒。", "鍊質纔三尺，吹毛過百重。", "擊磨如不倦，提握願長從。"]'),
('9880bab3-5a87-4657-a6f4-c66ce5931fb5','春色滿皇州','裴夷直','唐','唐诗','tang','','[]','寒銷山水地，春遍帝王州。',72,'全唐诗/poet.tang.27000.json','["寒銷山水地，春遍帝王州。", "北闕晴光動，南山喜氣浮。", "夭紅粧暖樹，急綠走陰溝。", "思婦開香閣，王孫上玉樓。", "氛氳直城北，駘蕩曲江頭。", "今日靈臺下，翻然却是愁。"]'),
('a929a248-6353-4d90-9a93-d68c1906a77b','亞夫碎玉斗','裴夷直','唐','唐诗','tang','','[]','雄謀竟不決，寶玉終不愛。',72,'全唐诗/poet.tang.27000.json','["雄謀竟不決，寶玉終不愛。", "倏爾霜刃揮，颯然春冰碎。", "飛光動旗幟，散響驚環珮。", "霜灑繡障前，星流錦筵內。", "圖王業已失，爲虜言空悔。", "獨有青史中，英風觀千載。"]'),
('72ba6026-1a1a-45e5-9cda-3f2f7658d3c3','水亭','裴夷直','唐','唐诗','tang','','[]','歲律行將變，君恩竟未回。',24,'全唐诗/poet.tang.27000.json','["歲律行將變，君恩竟未回。", "門前即潮水，朝去暮常來。"]'),
('e3dfda23-2574-40f6-a9f6-7b959ec7e6a9','揚州寄諸子','裴夷直','唐','唐诗','tang','','[]','千里隔烟波，孤舟宿何處？遙思耿不眠，淮南夜風雨。',24,'全唐诗/poet.tang.27000.json','["千里隔烟波，孤舟宿何處？遙思耿不眠，淮南夜風雨。"]'),
('4869e77e-9503-47b5-aaeb-0dabb8044034','酬盧郎中遊寺見招不遇','裴夷直','唐','唐诗','tang','','[]','偶出送山客，不知遊梵宮。',24,'全唐诗/poet.tang.27000.json','["偶出送山客，不知遊梵宮。", "秋光古松下，誰伴一仙翁。"]'),
('0383802f-8df0-48e7-8b03-a5fe917219b8','寓言','裴夷直','唐','唐诗','tang','','[]','秋樹却逢暖，未凋能幾時。',24,'全唐诗/poet.tang.27000.json','["秋樹却逢暖，未凋能幾時。", "何須尚松桂，搖動暫青枝。"]'),
('13b17855-ecdd-4c6b-bc27-3e3058342d95','唁人喪侍兒','裴夷直','唐','唐诗','tang','','[]','夜情河耿耿，春恨草綿綿。',24,'全唐诗/poet.tang.27000.json','["夜情河耿耿，春恨草綿綿。", "唯有嫦娥月，從今照墓田。"]'),
('740f7f75-3cd3-40b3-9db0-193d38ba6427','席上夜別張主簿','裴夷直','唐','唐诗','tang','','[]','紅燭剪還明，綠尊添又滿。',24,'全唐诗/poet.tang.27000.json','["紅燭剪還明，綠尊添又滿。", "不愁前路長，只畏今宵短。"]'),
('949f2149-80c4-4124-b7d2-62385bc304b0','方丈泉','裴夷直','唐','唐诗','tang','','[]','循涯不知淺，見底似非深。',24,'全唐诗/poet.tang.27000.json','["循涯不知淺，見底似非深。", "永日無波浪，澄澄照我心。"]'),
('f5f6a6a7-b517-4a68-9943-1b38e7e64443','晚望','裴夷直','唐','唐诗','tang','','[]','日下夕陰長，前山凝積翠。',24,'全唐诗/poet.tang.27000.json','["日下夕陰長，前山凝積翠。", "白鳥一行飛，聯聯粉書字。"]'),
('5c917902-e58b-4003-bc0b-49566ea06222','前山','裴夷直','唐','唐诗','tang','','[]','只謂一蒼翠，不知猶數重。',24,'全唐诗/poet.tang.27000.json','["只謂一蒼翠，不知猶數重。", "晚來雲映處，更見兩三峰。"]'),
('df1d6ea3-1664-4261-a5ae-36efee30fbd7','發交州日留題解鍊師房','裴夷直','唐','唐诗','tang','','[]','久喜房廊接，今成道路賒。',24,'全唐诗/poet.tang.27000.json','["久喜房廊接，今成道路賒。", "明朝回首處，此地是天涯。"]'),
('906f6ab4-fdda-41f8-91d9-d20f60ae6bb3','令和州買松','裴夷直','唐','唐诗','tang','','[]','好覓凌霜質，仍須帶雨栽。',24,'全唐诗/poet.tang.27000.json','["好覓凌霜質，仍須帶雨栽。", "須知剖竹日，便是看松來。"]'),
('de128788-7eef-4d87-a60c-5152856bd7f4','題斷金集後','裴夷直','唐','唐诗','tang','','[]','一覽斷金集，再悲埋玉人。',24,'全唐诗/poet.tang.27000.json','["一覽斷金集，再悲埋玉人。", "牙弦千古絕，珠淚萬行新。"]'),
('b82f94fe-d45c-460e-b3fb-2561a407f4ec','晚涼','裴夷直','唐','唐诗','tang','','[]','簷前蔽日多高樹，竹下添池有小渠。',32,'全唐诗/poet.tang.27000.json','["簷前蔽日多高樹，竹下添池有小渠。", "山客野僧歸去後，晚涼移案獨臨書。"]'),
('88dc28ce-3d20-4cd7-868a-7b2bfcca3409','和周侍御洛城雪','裴夷直','唐','唐诗','tang','','[]','天街飛轡踏瓊英，四顧全疑在玉京。',32,'全唐诗/poet.tang.27000.json','["天街飛轡踏瓊英，四顧全疑在玉京。", "一種相如抽祕思，兔園那比鳳凰城。"]'),
('f9bd587e-9af3-49a9-a0ff-7addb0037627','奉和大梁相公送人二首 一','裴夷直','唐','唐诗','tang','','[]','謝公日日傷離別，又向西堂送阿連。',32,'全唐诗/poet.tang.27000.json','["謝公日日傷離別，又向西堂送阿連。", "想到越中秋已盡，鏡河應羨月團圓。"]'),
('6f8a6d72-8e29-4466-b249-f4c80165ed15','奉和大梁相公送人二首 二','裴夷直','唐','唐诗','tang','','[]','北津楊柳迎烟綠，南岸闌干映水紅。',32,'全唐诗/poet.tang.27000.json','["北津楊柳迎烟綠，南岸闌干映水紅。", "君到襄陽渡江處，始應回首憶羊公。"]'),
('5fd0402b-5e34-4b02-937b-4bcbf3368b12','酬唐仁烈相別後喜阻風未發見寄','裴夷直','唐','唐诗','tang','','[]','離心一起淚雙流，春浪無情也白頭。',32,'全唐诗/poet.tang.27000.json','["離心一起淚雙流，春浪無情也白頭。", "風若有知須放去，莫教重別又重愁。"]'),
('ebf1be33-e0ab-4659-9d0c-5e3ef6c6c06e','秦中臥病思歸','裴夷直','唐','唐诗','tang','','[]','索索涼風滿樹頭，破窗殘月五更秋。',32,'全唐诗/poet.tang.27000.json','["索索涼風滿樹頭，破窗殘月五更秋。", "病身歸處吳江上，一寸心中萬里愁。"]'),
('e9d6c3ff-165e-4e52-a810-63d544b9afea','送王繢','裴夷直','唐','唐诗','tang','','[]','翠羽長將玉樹期，偶然飛下肯多時。',32,'全唐诗/poet.tang.27000.json','["翠羽長將玉樹期，偶然飛下肯多時。", "翩翩一路嵐陰晚，却入青葱宿舊枝。"]'),
('eb90f26f-4c0f-4d55-a65c-aa23ed550ef6','贈美人琴絃','裴夷直','唐','唐诗','tang','','[]','應從玉指到金徽，萬態千情料可知。',32,'全唐诗/poet.tang.27000.json','["應從玉指到金徽，萬態千情料可知。", "今夜燈前湘水怨，殷勤封在七條絲。"]'),
('267b9325-1630-4ee9-bd02-d24b45af8338','病中知皇子陂荷花盛發寄王繢','裴夷直','唐','唐诗','tang','','[]','十里蓮塘路不賒，病來簾外是天涯。',32,'全唐诗/poet.tang.27000.json','["十里蓮塘路不賒，病來簾外是天涯。", "煩君四句遙相寄，應得詩中便看花。"]'),
('88e8dc78-b2ca-48a3-a980-dfed27b83bd1','戲唐仁烈','裴夷直','唐','唐诗','tang','','[]','自知年幾偏應少，先把屠蘇不讓春。',32,'全唐诗/poet.tang.27000.json','["自知年幾偏應少，先把屠蘇不讓春。", "儻更數年逢此日，還應惆悵羨他人。"]'),
('a93800bc-9f72-4a28-b6e9-559244a382c8','上下七盤二首 一','裴夷直','唐','唐诗','tang','','[]','斗回山路掩皇州，二載歡娛一望休。',32,'全唐诗/poet.tang.27000.json','["斗回山路掩皇州，二載歡娛一望休。", "從此萬重青嶂合，無因更得重回頭。"]'),
('0905ae6f-f389-4d57-91d6-f1013f5ce8fd','上下七盤二首 二','裴夷直','唐','唐诗','tang','','[]','商山半月雨漫漫，偶值新晴下七盤。',32,'全唐诗/poet.tang.27000.json','["商山半月雨漫漫，偶值新晴下七盤。", "山似換來天似洗，可憐風日到長安。"]'),
('22b4e3e6-44af-4666-8316-1293c3daa861','八月十五日夜','裴夷直','唐','唐诗','tang','','[]','去年今夜在商州，還爲清光上驛樓。',32,'全唐诗/poet.tang.27000.json','["去年今夜在商州，還爲清光上驛樓。", "宛是依依舊顏色，自憐人換幾般愁。"]'),
('4707beb7-4039-41f6-a587-21d15b54358f','南詔朱藤杖','裴夷直','唐','唐诗','tang','','[]','六節南藤色似朱，拄行階砌勝人扶。',32,'全唐诗/poet.tang.27000.json','["六節南藤色似朱，拄行階砌勝人扶。", "會須將入深山去，倚看雲泉作老夫。"]'),
('e386882b-d0cd-480a-8c38-08ad675c36f8','夜意','裴夷直','唐','唐诗','tang','','[]','蕭疎盡地林無影，浩蕩連天月有波。',32,'全唐诗/poet.tang.27000.json','["蕭疎盡地林無影，浩蕩連天月有波。", "獨立空亭人睡後，洛橋風便水聲多。"]'),
('ffd11ad7-83bd-45e1-824a-44767f23f200','漫作','裴夷直','唐','唐诗','tang','','[]','月色莫來孤寢處，春風又向別人家。',32,'全唐诗/poet.tang.27000.json','["月色莫來孤寢處，春風又向別人家。", "梁園桃李雖無數，斷定今年不看花。"]'),
('fc6f8268-7565-4789-9e03-bca065508f47','訪劉君','裴夷直','唐','唐诗','tang','','[]','擾擾馳蹄又走輪，五更飛盡九衢塵。',32,'全唐诗/poet.tang.27000.json','["擾擾馳蹄又走輪，五更飛盡九衢塵。", "靈芝破觀深松院，還有齋時未起人。"]'),
('dac1571e-697d-44bb-9e4d-d10febd20d3b','楊柳枝詞','裴夷直','唐','唐诗','tang','','[]','已作綠絲籠曉日，又成飛絮撲晴波。',32,'全唐诗/poet.tang.27000.json','["已作綠絲籠曉日，又成飛絮撲晴波。", "隋家不合栽楊柳，長遣行人春恨多。"]'),
('81763d8b-d9a8-446e-8abf-c33ebb1bb604','寄杭州崔使君','裴夷直','唐','唐诗','tang','','[]','朝下歸來只閉關，羨君高步出人寰。',32,'全唐诗/poet.tang.27000.json','["朝下歸來只閉關，羨君高步出人寰。", "三年不見塵中事，滿眼江濤送雪山。"]'),
('2b84a089-3498-4aa7-9249-8a6390b0b631','窮冬曲江閑步','裴夷直','唐','唐诗','tang','','[]','雪盡南坡鴈北飛，草根春意勝春暉。',32,'全唐诗/poet.tang.27000.json','["雪盡南坡鴈北飛，草根春意勝春暉。", "曲江永日無人到，獨遶寒池又獨歸。"]'),
('f168ea1d-968d-464a-b7b0-1fc9bd1b0b5b','省中題新植雙松','裴夷直','唐','唐诗','tang','','[]','端坐高宮起遠心，雲高水闊共幽沈。',32,'全唐诗/poet.tang.27000.json','["端坐高宮起遠心，雲高水闊共幽沈。", "更堂寓直將誰語，自種雙松伴夜吟。"]'),
('568b1483-0cc5-44d9-b0b1-a8c56462dc28','崇山郡','裴夷直','唐','唐诗','tang','','[]','地盡炎荒瘴海頭，聖朝今又放驩兜。',32,'全唐诗/poet.tang.27000.json','["地盡炎荒瘴海頭，聖朝今又放驩兜。", "交州已在南天外，更過交州四五州。"]'),
('a5dc4fdc-10ec-4d67-8b84-a94d039a23e7','臨水','裴夷直','唐','唐诗','tang','','[]','一見心原斷百憂，益知身世兩悠悠。',32,'全唐诗/poet.tang.27000.json','["一見心原斷百憂，益知身世兩悠悠。", "江亭獨倚闌干處，人亦無言水自流。"]'),
('e8eeefaa-8d04-47d0-b1a8-3b6bb7568e55','題江上柳寄李使君','裴夷直','唐','唐诗','tang','','[]','桂江南渡無楊柳，見此令人眼暫明。',32,'全唐诗/poet.tang.27000.json','["桂江南渡無楊柳，見此令人眼暫明。", "應學郡中賢太守，依依相向許多情。"]'),
('7a638998-267d-4ec3-b561-706e818cadd5','江上見月懷古','裴夷直','唐','唐诗','tang','','[]','月上江平夜不風，伏波遺跡半成空。',32,'全唐诗/poet.tang.27000.json','["月上江平夜不風，伏波遺跡半成空。", "今宵倍欲悲陵谷，銅柱分明在水中。"]'),
('64c5e24c-c5d3-47c5-98fd-8eb5961e1f78','鸚鵡','裴夷直','唐','唐诗','tang','','[]','勸爾莫移禽鳥性，翠毛紅觜任天真。',32,'全唐诗/poet.tang.27000.json','["勸爾莫移禽鳥性，翠毛紅觜任天真。", "如今漫學人言巧，解語終須累爾身。"]'),
('11c1842c-f5ee-4737-816d-b4849264e56f','寄婺州李給事二首 一','裴夷直','唐','唐诗','tang','','[]','心盡玉皇恩已遠，跡留江郡宦應孤。',32,'全唐诗/poet.tang.27000.json','["心盡玉皇恩已遠，跡留江郡宦應孤。", "不知壯氣今何似，猶得凌雲貫日無。"]'),
('ff034545-4628-48e5-807e-b50583f8c907','寄婺州李給事二首 二','裴夷直','唐','唐诗','tang','','[]','瘴鬼翻能念直心，五年相遇不相侵。',32,'全唐诗/poet.tang.27000.json','["瘴鬼翻能念直心，五年相遇不相侵。", "目前唯有思君病，無底滄溟未是深。"]'),
('f00b6726-356f-4788-a808-e1183268d964','秋日','裴夷直','唐','唐诗','tang','','[]','六眸龜北涼應早，三足烏南日正長。',32,'全唐诗/poet.tang.27000.json','["六眸龜北涼應早，三足烏南日正長。", "常記京關怨搖落，如今目斷滿林霜。"]'),
('3ae868cd-3210-4e46-89c8-034fb2ec3bc5','遣意','裴夷直','唐','唐诗','tang','','[]','梧桐墜露悲先朽，松桂凌霜倚後枯。',32,'全唐诗/poet.tang.27000.json','["梧桐墜露悲先朽，松桂凌霜倚後枯。", "不是世間長在物，蹔分貞脆竟何殊。"]'),
('f380223e-fb6e-415c-bf49-96719507967e','戲酬惟賞上人','裴夷直','唐','唐诗','tang','','[]','師是浮雲無著身，我居塵網敢相親。',32,'全唐诗/poet.tang.27000.json','["師是浮雲無著身，我居塵網敢相親。", "應從海上秋風便，偶自飛來不爲人。"]'),
('e090d81a-0753-4556-a91b-1f78e3c87df9','寓言','裴夷直','唐','唐诗','tang','','[]','流水頹陽不暫停，東流西落兩無情。',32,'全唐诗/poet.tang.27000.json','["流水頹陽不暫停，東流西落兩無情。", "不是世間人自老，古來華髮此中生。"]'),
('96797f24-909e-4fbd-88a8-4576d3bd6a14','憶家','裴夷直','唐','唐诗','tang','','[]','天海相連無盡處，夢魂來往尚應難。',32,'全唐诗/poet.tang.27000.json','["天海相連無盡處，夢魂來往尚應難。", "誰言南海無霜雪，試向愁人兩鬢看。"]'),
('ca25d9b3-ed25-44d9-9976-700b5475edd2','留客','裴夷直','唐','唐诗','tang','','[]','青梅欲熟笋初長，嫩綠新陰遶砌涼。',32,'全唐诗/poet.tang.27000.json','["青梅欲熟笋初長，嫩綠新陰遶砌涼。", "湖館翛然無俗客，白衣居士且匡牀。"]'),
('c1d8d427-9ddb-47dd-9702-f1ddbda34bd7','別蘄春王判官','裴夷直','唐','唐诗','tang','','[]','四十年來[真]久故，三千里外暫相逢。',34,'全唐诗/poet.tang.27000.json','["四十年來[真]久故，三千里外暫相逢。", "今日一杯成遠別，烟波眇眇恨重重。"]'),
('8eb0d609-7145-40c2-a553-1890da2c70ec','將發循州社日於所居館宴送','裴夷直','唐','唐诗','tang','','[]','浪花如雪疊江風，社過高秋萬恨中。',32,'全唐诗/poet.tang.27000.json','["浪花如雪疊江風，社過高秋萬恨中。", "明日便隨江燕去，依依俱是故巢空。"]'),
('028b1794-eae0-4142-aef7-d25b2cc2afc6','泛溪','朱慶餘','唐','唐诗','tang','','[]','曲渚迴花舫，生衣臥向風。',48,'全唐诗/poet.tang.27000.json','["曲渚迴花舫，生衣臥向風。", "鳥飛溪色裏，人語棹聲中。", "餘卉纔分影，新蒲自作叢。", "前灣更幽絕，雖淺去猶通。"]'),
('3f206dce-b488-46c6-8ec7-ffd730373db9','宿陳處士書齋','朱慶餘','唐','唐诗','tang','','[]','結茅當此地，下馬見高情。',48,'全唐诗/poet.tang.27000.json','["結茅當此地，下馬見高情。", "菰葉寒塘晚，杉陰白石明。", "向爐新茗色，隔雪遠鐘聲。", "閑得相逢少，吟多寐不成。"]'),
('dcf41cfc-d052-44b3-8f5c-e52eee610cda','上宣州沈大夫','朱慶餘','唐','唐诗','tang','','[]','科名繼世古來稀，高步何年下紫微。',64,'全唐诗/poet.tang.27000.json','["科名繼世古來稀，高步何年下紫微。", "帝命幾曾移重鎮，時清猶望領春闈。", "登朝舊友常思見，開幕賢人併望歸。", "今日得遊風化地，却回滄海有光輝。"]'),
('b1147a91-a65d-4449-a3c0-e6b177b511c9','杭州送蕭寶校書','朱慶餘','唐','唐诗','tang','','[]','馬識青山路，人隨白浪船。',24,'全唐诗/poet.tang.27000.json','["馬識青山路，人隨白浪船。", "別君猶有淚，學道謾經年。"]'),
('996a613d-4623-416f-925f-7b3b4034f997','送盛長史','朱慶餘','唐','唐诗','tang','','[]','莫辭東路遠，此別豈閑行。',48,'全唐诗/poet.tang.27000.json','["莫辭東路遠，此別豈閑行。", "職處中軍要，官兼上佐榮。", "野亭楓葉暗，秋水藕花明。", "拜省期將近，孤舟促去程。"]'),
('02836fc6-a0f8-4b4a-8bc2-d4ac59990067','宿道士觀','朱慶餘','唐','唐诗','tang','','[]','堂閉僊人影，空壇月露初。',24,'全唐诗/poet.tang.27000.json','["堂閉僊人影，空壇月露初。", "閑聽道家子，盥漱讀靈書。"]'),
('c45eef97-a07f-4999-9f67-e863e9828310','湖州韓使君置宴','朱慶餘','唐','唐诗','tang','','[]','老大成名仍足病，縱聽絲竹也無歡。',32,'全唐诗/poet.tang.27000.json','["老大成名仍足病，縱聽絲竹也無歡。", "高情太守容閑坐，借與青山盡日看。"]'),
('1e63f4cf-a078-44df-814f-8bea0929e526','題僊遊寺','朱慶餘','唐','唐诗','tang','','[]','石抱龍堂蘚石乾，山遮白日寺門寒。',32,'全唐诗/poet.tang.27000.json','["石抱龍堂蘚石乾，山遮白日寺門寒。", "長松瀑布饒奇狀，曾有仙人駐鶴看。"]'),
('ab4b1a7f-4fbe-438b-817f-9e1ed2d39f4f','宮詞','朱慶餘','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u5bab\u6028", "\u5199\u666f"]','寂寂花時閉院門，美人相並立瓊軒。',32,'全唐诗/poet.tang.27000.json','["寂寂花時閉院門，美人相並立瓊軒。", "含情欲說宮中事，鸚鵡前頭不敢言。"]'),
('2dcb7fd8-a1a6-434b-bb80-fa6923197085','公子行','朱慶餘','唐','唐诗','tang','','[]','閑從結客冶遊時，忘却紅樓薄暮期。',32,'全唐诗/poet.tang.27000.json','["閑從結客冶遊時，忘却紅樓薄暮期。", "醉上黃金堤上去，馬鞭捎斷綠楊絲。"]'),
('c6e38b16-b83d-41e0-8839-d6d29bb3bf15','送陳摽','朱慶餘','唐','唐诗','tang','','[]','滿酌勸童僕，好隨郎馬蹄。',24,'全唐诗/poet.tang.27000.json','["滿酌勸童僕，好隨郎馬蹄。", "春風慎行李，莫上白銅鞮。"]'),
('8c7e86af-7eac-43e4-95ff-e1e4c3cd9ab0','尋古觀','朱慶餘','唐','唐诗','tang','','[]','僊觀曾過知不遠，花藏石室杳難尋。',32,'全唐诗/poet.tang.27000.json','["僊觀曾過知不遠，花藏石室杳難尋。", "泉邊白鹿聞人語，看過天壇漸入深。"]'),
('8b92e129-ad6b-4fd6-a097-20aff22782bf','南嶺路','朱慶餘','唐','唐诗','tang','','[]','越嶺向南風景異，人人傳說到京城。',32,'全唐诗/poet.tang.27000.json','["越嶺向南風景異，人人傳說到京城。", "經冬來往不踏雪，盡在刺桐花下行。"]'),
('a94fee19-9e17-47d9-a9c2-7c1d6536d14b','陪江州李使君重陽宴百花亭','朱慶餘','唐','唐诗','tang','','[]','閑攜九日酒，共到百花亭。',24,'全唐诗/poet.tang.27000.json','["閑攜九日酒，共到百花亭。", "醉裏求詩境，回看島嶼青。"]'),
('a741fa0a-099c-425e-91c5-e1d67a946da2','上張水部','朱慶餘','唐','唐诗','tang','','[]','出入門闌久，兒童亦有情。',48,'全唐诗/poet.tang.27000.json','["出入門闌久，兒童亦有情。", "不忘將姓字，常說向公卿。", "每許連牀坐，仍容並馬行。", "恩深轉無語，懷抱甚分明。"]'),
('062ac841-d778-469b-ae73-3dcc872b25a9','鳳翔西池與賈島納涼','朱慶餘','唐','唐诗','tang','','[]','四面無炎氣，清池闊復深。',48,'全唐诗/poet.tang.27000.json','["四面無炎氣，清池闊復深。", "蝶飛逢草住，魚戲見人沉。", "拂石安茶器，移牀選樹陰。", "幾迴同到此，盡日得閑吟。"]'),
('6b980f56-638a-45b7-8466-99a3be06dcc7','上汴州令狐相公','朱慶餘','唐','唐诗','tang','','[]','罷相恩猶在，那容處靜司。',48,'全唐诗/poet.tang.27000.json','["罷相恩猶在，那容處靜司。", "政嚴初領節，名重更因詩。", "公事巡營外，戎裝拜勅時。", "恭聞長與善，應念出身遲。"]'),
('3ce4374a-ac10-45b6-9a47-cc5582ed76f1','送于中丞入蕃冊立','朱慶餘','唐','唐诗','tang','','[]','上馬生邊思，戎裝別衆僚。',48,'全唐诗/poet.tang.27000.json','["上馬生邊思，戎裝別衆僚。", "雙旌銜命重，空磧去程遙。", "迥沒沙中樹，孤飛雪外鵰。", "蕃庭過冊禮，幾日却回朝。"]'),
('52fef130-01f0-46c7-987a-5bd24ec02b44','送淮陰丁明府','朱慶餘','唐','唐诗','tang','','[]','之官未入境，已有愛人心。',48,'全唐诗/poet.tang.27000.json','["之官未入境，已有愛人心。", "遣吏回中路，停舟對遠林。", "島聲淮浪靜，雨色稻苗深。", "暇日公門掩，唯應伴客吟。"]'),
('dc2c5e6b-d9f7-4fdd-913b-875760551bea','送韋校書佐靈州幕','朱慶餘','唐','唐诗','tang','','[]','共知行處樂，猶惜此時分。',48,'全唐诗/poet.tang.27000.json','["共知行處樂，猶惜此時分。", "職已爲書記，官曾校典墳。", "寒城初落葉，高戍遠生雲。", "邊事何須問，深謀祗在君。"]'),
('a0487b39-8c88-4ca4-b541-f83ebfd93c3b','上江州李史君','朱慶餘','唐','唐诗','tang','','[]','起家聲望重，自古更誰過。',48,'全唐诗/poet.tang.27000.json','["起家聲望重，自古更誰過。", "得在朝廷少，還因諫諍多。", "經年愁瘴癘，幾處遇恩波。", "入境無餘事，唯聞父老歌。"]'),
('6714559c-639e-4b92-8354-b78a55e2fd27','發鳳翔後塗中懷田少府','朱慶餘','唐','唐诗','tang','','[]','識君春未半，意欲住經秋。',48,'全唐诗/poet.tang.27000.json','["識君春未半，意欲住經秋。", "見酒連詩句，逢花跋馬頭。", "別來唯獨宿，夢裏尚同游。", "所在求飱過，無因離得愁。"]'),
('446315f0-3740-4248-8cf7-1dce97d9336e','雪夜與真上人宿韓協律宅','朱慶餘','唐','唐诗','tang','','[]','斜雪微霑砌，空堂夜語清。',48,'全唐诗/poet.tang.27000.json','["斜雪微霑砌，空堂夜語清。", "逆風聽漏短，回燭向樓明。", "盥漱隨禪伴，謳吟得野情。", "此歡那敢忘，世貴丈夫名。"]'),
('54f56607-3ef1-4686-b1b6-2c9c3ff3fd48','與賈島顧非熊無可上人宿萬年姚少府宅','朱慶餘','唐','唐诗','tang','','[]','莫厭通宵坐，貧中會聚難。',48,'全唐诗/poet.tang.27000.json','["莫厭通宵坐，貧中會聚難。", "堂虛雪氣入，燈在漏聲殘。", "役思因生病，當禪豈覺寒。", "開門各有事，非不惜餘歡。"]'),
('efd28f83-a3b4-4297-9de7-80a215b4f84d','震爲蒼筤竹','朱慶餘','唐','唐诗','tang','','[]','爲擢東方秀，修然異衆筠。',72,'全唐诗/poet.tang.27000.json','["爲擢東方秀，修然異衆筠。", "青蒼纔映粉，蒙密正含春。", "嫩籜霑微雨，幽根絕細塵。", "乍憐分徑小，偏覺帶煙新。", "結實皆留鳳，垂陰似庇人。", "顧唯竿在手，深水掛頳鱗。"]'),
('ba7b4d84-d1e4-4ca1-96c1-06c5fbf84549','題青龍寺','朱慶餘','唐','唐诗','tang','','[]','寺好因崗勢，登臨值夕陽。',48,'全唐诗/poet.tang.27000.json','["寺好因崗勢，登臨值夕陽。", "青山當佛閣，紅葉滿僧廊。", "竹色連平地，蟲聲在上方。", "最憐東面靜，爲近楚城牆。"]'),
('44b4e1e8-5c87-4cd6-8bbd-9b702a9d1ab8','送滕庶子致仕歸江南','朱慶餘','唐','唐诗','tang','','[]','常懷獨往意，此日去朝簪。',48,'全唐诗/poet.tang.27000.json','["常懷獨往意，此日去朝簪。", "丹詔榮歸騎，清風滿故林。", "諸侯新起敬，遺老重相尋。", "在處饒山水，堪行慰所心。"]'),
('24066101-5b6f-4fea-9e95-bd01a687c6ed','夏日題武功姚主簿','朱慶餘','唐','唐诗','tang','','[]','亭午無公事，垂簾樹色間。',48,'全唐诗/poet.tang.27000.json','["亭午無公事，垂簾樹色間。", "僧來茶竈動，吏去印牀閑。", "傍竹行尋巷，當門立看山。", "吟詩老不倦，未省話官班。"]'),
('25bc9104-e1ed-4156-a8f0-757d015e7b8c','送張景宣下第東歸','朱慶餘','唐','唐诗','tang','','[]','歸省值花時，閑吟落第詩。',48,'全唐诗/poet.tang.27000.json','["歸省值花時，閑吟落第詩。", "高情憐道在，公論覺才遺。", "春雨連淮暗，私船過馬遲。", "離心可惆悵，爲有入城期。"]'),
('59c05369-714c-43ba-842a-76548b3f21d7','送顧非熊下第歸','朱慶餘','唐','唐诗','tang','','[]','但取詩名遠，寧論下第頻。',48,'全唐诗/poet.tang.27000.json','["但取詩名遠，寧論下第頻。", "惜爲今日別，共受幾年貧。", "聽雨宿吳寺，過江逢越人。", "知從本府薦，秋晚又辭親。"]'),
('94810bad-0859-4cac-894c-e0de17e1a50e','送韋繇校書赴浙東幕','朱慶餘','唐','唐诗','tang','','[]','丞相辟書新，秋關獨去人。',48,'全唐诗/poet.tang.27000.json','["丞相辟書新，秋關獨去人。", "官離芸閣早，名占甲科頻。", "水驛迎船火，山城候騎塵。", "湖邊寄家久，到日喜榮親。"]'),
('432dda35-564f-44cf-b5a8-a5dc9b75f544','尋賈島所居','朱慶餘','唐','唐诗','tang','','[]','求閑身未得，此日到京東。',48,'全唐诗/poet.tang.27000.json','["求閑身未得，此日到京東。", "獨在鐘聲外，相逢樹色中。", "誰言人漸老，所向意皆同。", "月上因留宿，移牀對藥叢。"]'),
('93f39a48-846f-4b29-9a0e-3b9cce64608b','題毗陵上人院','朱慶餘','唐','唐诗','tang','','[]','院深終日靜，落葉覆秋蟲。',48,'全唐诗/poet.tang.27000.json','["院深終日靜，落葉覆秋蟲。", "盥漱新齋後，修行未老中。", "映松山色遠，隔水磬聲通。", "此處宜清夜，高吟永與同。"]'),
('57c950fd-3711-48dc-8df3-09555f1d7a7c','送李侍御入蕃','朱慶餘','唐','唐诗','tang','','[]','遠使隨雙節，新官屬外臺。',48,'全唐诗/poet.tang.27000.json','["遠使隨雙節，新官屬外臺。", "戎裝非好武，書記本多才。", "移帳依泉宿，迎人帶雪來。", "心知玉關道，稀見一花開。"]'),
('65b5093e-0faf-4f93-ab77-a843168acea5','望蕭關','朱慶餘','唐','唐诗','tang','','[]','漸見風沙暗，蕭關欲到時。',48,'全唐诗/poet.tang.27000.json','["漸見風沙暗，蕭關欲到時。", "兒童能探火，婦女解縫旗。", "川絕銜魚鷺，林多帶箭麋。", "暫來戎馬地，不敢苦吟詩。"]'),
('40401dc2-a6a3-46f2-bd6f-68198b7a2309','送韓校書赴江西幕','朱慶餘','唐','唐诗','tang','','[]','從軍五湖外，終是稱詩人。',72,'全唐诗/poet.tang.27000.json','["從軍五湖外，終是稱詩人。", "酒後愁將別，塗中過却春。", "山橋槲葉暗，水館燕巢新。", "驛舫迎應遠，京書寄自頻。", "野情隨到處，公務日關身。", "久共趨名利，龍鍾獨滯秦。"]'),
('f7a50917-4a37-4197-9af5-dd104c82d60c','題寄王秘書','朱慶餘','唐','唐诗','tang','','[]','唯求買藥價，此外更無機。',48,'全唐诗/poet.tang.27000.json','["唯求買藥價，此外更無機。", "扶病看紅葉，辭官著白衣。", "斷籬通野徑，高樹蔭鄰扉。", "時復留僧宿，餘人得見稀。"]'),
('e58addbd-ee94-461a-9905-8423b62f91ac','山居','朱慶餘','唐','唐诗','tang','','[]','歸來青壁下，又見滿籬霜。',48,'全唐诗/poet.tang.27000.json','["歸來青壁下，又見滿籬霜。", "轉覺琴齋靜，閑從菊地荒。", "山泉共鹿飲，林果讓僧嘗。", "時復收新藥，隨雲過石梁。"]'),
('c01fed66-e625-4e38-b851-055447c08c02','重過惟貞上人院','朱慶餘','唐','唐诗','tang','','[]','老去唯求靜，都忘外學名。',48,'全唐诗/poet.tang.27000.json','["老去唯求靜，都忘外學名。", "掃牀秋葉滿，對客遠雲生。", "香閤閑留宿，晴階暖共行。", "窗西暮山色，依舊入詩情。"]'),
('bcb03337-0b1d-4b63-b8e1-2cb73ed4aca3','與石晝秀才過普照寺','朱慶餘','唐','唐诗','tang','','[]','問人知寺路，松竹暗春山。',48,'全唐诗/poet.tang.27000.json','["問人知寺路，松竹暗春山。", "潭黑龍應在，巢空鶴未還。", "經年爲客倦，半日與僧閑。", "更共嘗新茗，聞鐘笑語間。"]'),
('7429e111-8b2d-4626-8d4e-f6630e6734b5','題任處士幽居','朱慶餘','唐','唐诗','tang','','[]','惜與幽人別，停舟對草堂。',48,'全唐诗/poet.tang.27000.json','["惜與幽人別，停舟對草堂。", "湖雲侵臥位，杉露滴茶牀。", "山月吟時在，池花覺後香。", "生涯無一物，誰與讀書糧。"]'),
('a18165e9-9e12-4231-b2b3-19c8b0bcc87f','送僧往太原謁李司空','朱慶餘','唐','唐诗','tang','','[]','已共鄰房別，應無更住心。',48,'全唐诗/poet.tang.27000.json','["已共鄰房別，應無更住心。", "中時過野店，後夜宿寒林。", "寺去人煙遠，城連塞雪深。", "禪餘得新句，堪對上公吟。"]'),
('237b7a55-7821-44b5-b17f-4d30fa311028','將之上京別淮南書記李侍御','朱慶餘','唐','唐诗','tang','','[]','心地偶相見，語多爲別難。',48,'全唐诗/poet.tang.27000.json','["心地偶相見，語多爲別難。", "詩成公府晚，路入翠微寒。", "逢石自應坐，有花誰共看。", "身爲當去鴈，雲盡到長安。"]'),
('34f91a91-b322-4bc3-b9d1-ac8e7987cc4a','韓協律相送精舍讀書四韻奉寄呈陸補闕','朱慶餘','唐','唐诗','tang','','[]','白鶴西山別，更看上去船。',48,'全唐诗/poet.tang.27000.json','["白鶴西山別，更看上去船。", "遙知尋寺路，應念宿江煙。", "到處無閑日，迴期已隔年。", "何因陪夜坐，清論諫臣邊。"]'),
('aefce4bf-8330-4f8e-9600-ab3b575b8a02','過蘇州曉上人院','朱慶餘','唐','唐诗','tang','','[]','夏滿律當清，無中景自生。',48,'全唐诗/poet.tang.27000.json','["夏滿律當清，無中景自生。", "移松不避遠，取石亦親行。", "經案離時少，繩牀著處平。", "若將林下比，應只欠泉聲。"]'),
('38c18497-8dd9-4940-b53f-1f8c5e3bc7c4','送僧遊縉雲','朱慶餘','唐','唐诗','tang','','[]','但望青山去，何山不是緣。',48,'全唐诗/poet.tang.27000.json','["但望青山去，何山不是緣。", "寺幽堪講律，月冷稱當禪。", "水落無風夜，猨吟欲雨天。", "尋師若有路，終作緩歸年。"]'),
('866579dd-6f4f-4eb0-817a-c6cc917efcbf','贈道者','朱慶餘','唐','唐诗','tang','','[]','自識來清瘦，尋常語論真。',48,'全唐诗/poet.tang.27000.json','["自識來清瘦，尋常語論真。", "藥成休伏火，符驗不傳人。", "獨有年過鶴，曾無病到身。", "潛教問弟子，居處與誰鄰。"]'),
('00854a31-c67d-4724-b749-4d4b543d2495','杭州盧錄事山亭','朱慶餘','唐','唐诗','tang','','[]','山色滿公署，到來詩景饒。',72,'全唐诗/poet.tang.27000.json','["山色滿公署，到來詩景饒。", "解衣臨曲榭，隔竹見紅蕉。", "清漏焚香夕，輕嵐視事朝。", "靜中看鎖印，高處見迎潮。", "曳履庭蕪近，當身樹葉飄。", "傍城餘菊在，步入一僊瓢。"]'),
('ceee9e38-7bac-40f6-a79f-653de2f95342','送品上人入秦','朱慶餘','唐','唐诗','tang','','[]','獨去何人見，林塘共寂寥。',48,'全唐诗/poet.tang.27000.json','["獨去何人見，林塘共寂寥。", "生緣聞磬早，覺路出塵遙。", "江雪霑新草，秦園發故條。", "心知禪定處，石室對芭蕉。"]'),
('740f2c1c-7c58-49eb-b30e-858618452344','題薔薇花','朱慶餘','唐','唐诗','tang','','[]','四面垂條密，浮陰入夏清。',48,'全唐诗/poet.tang.27000.json','["四面垂條密，浮陰入夏清。", "綠攢傷手刺，紅墮斷腸英。", "粉著蜂鬚膩，光凝蝶翅明。", "雨中看亦好，況復值初晴。"]'),
('3e43abe1-a112-48be-b127-cb3c98ddf730','題胡氏溪亭','朱慶餘','唐','唐诗','tang','','[]','亭與溪相近，無時不有風。',48,'全唐诗/poet.tang.27000.json','["亭與溪相近，無時不有風。", "澗松生便黑，野蘚看多紅。", "雨足秋聲後，山沈夜色中。", "主人能守靜，略與客心同。"]'),
('626c0e84-2b71-4040-abb5-23eaee8b2bc8','看濤','朱慶餘','唐','唐诗','tang','','[]','不知來遠近，但見白峨峨。',48,'全唐诗/poet.tang.27000.json','["不知來遠近，但見白峨峨。", "風雨驅寒玉，魚龍迸上波。", "聲長勢未盡，曉去夕還過。", "要路橫天塹，其如造化何。"]'),
('f7a55c9e-f269-4647-abd8-5144b1d2d5c3','和劉補闕秋園寓興之什十首 一','朱慶餘','唐','唐诗','tang','','[]','閑園清氣滿，新興日堪追。',48,'全唐诗/poet.tang.27000.json','["閑園清氣滿，新興日堪追。", "隔水蟬鳴後，當簷鴈過時。", "雨餘槐穟重，霜近藥苗衰。", "不以朝簪貴，多將野客期。"]'),
('742ce4e4-6412-4efc-a47f-3d4b15dd32a2','和劉補闕秋園寓興之什十首 二','朱慶餘','唐','唐诗','tang','','[]','誰言高靜意，不異在衡茅。',48,'全唐诗/poet.tang.27000.json','["誰言高靜意，不異在衡茅。", "竹冷人離洞，天晴鶴出巢。", "深籬藏白菌，荒蔓露青匏。", "幾見中宵月，清光墜樹梢。"]'),
('5a97886d-adff-46aa-b290-53c15483b422','和劉補闕秋園寓興之什十首 三','朱慶餘','唐','唐诗','tang','','[]','逍遙人事外，杖屨入杉蘿。',48,'全唐诗/poet.tang.27000.json','["逍遙人事外，杖屨入杉蘿。", "草色寒猶在，蟲聲晚漸多。", "靜逢山鳥下，幽稱野僧過。", "幾許新開菊，閑從落葉和。"]'),
('13f57522-5598-45e2-a2fb-9a5bab404e40','和劉補闕秋園寓興之什十首 四','朱慶餘','唐','唐诗','tang','','[]','留情清景宴，朝罷有餘閑。',48,'全唐诗/poet.tang.27000.json','["留情清景宴，朝罷有餘閑。", "蝶散紅蘭外，螢飛白露間。", "牆高微見寺，林靜遠分山。", "吟足期相訪，殘陽自掩關。"]'),
('8508c729-7862-49a8-9719-4daf82d09f99','和劉補闕秋園寓興之什十首 五','朱慶餘','唐','唐诗','tang','','[]','深齋嘗獨處，詎肯厭秋聲。',48,'全唐诗/poet.tang.27000.json','["深齋嘗獨處，詎肯厭秋聲。", "翠篠寒愈靜，孤花晚更明。", "每因逢石坐，多見抱書行。", "入夜聽疎杵，遙知耿此情。"]'),
('d819d49f-09dd-475d-a058-6b91807fbd63','和劉補闕秋園寓興之什十首 六','朱慶餘','唐','唐诗','tang','','[]','蒼翠經宵在，園廬景自深。',48,'全唐诗/poet.tang.27000.json','["蒼翠經宵在，園廬景自深。", "風淒欲去燕，月思向來砧。", "碧石當莎逕，寒煙冒竹林。", "桮瓢閑寄詠，清絕是知音。"]'),
('7e03ecf1-12f3-40f5-97b9-1a01f6531da6','和劉補闕秋園寓興之什十首 七','朱慶餘','唐','唐诗','tang','','[]','門巷唯苔蘚，誰言不稱貧。',48,'全唐诗/poet.tang.27000.json','["門巷唯苔蘚，誰言不稱貧。", "臺閑人下晚，果熟鳥來頻。", "石脈潛通井，松枝靜離塵。", "殘蔬得晴後，又見一番新。"]'),
('1952331a-e5be-4fba-93f5-44fc83d86553','和劉補闕秋園寓興之什十首 八','朱慶餘','唐','唐诗','tang','','[]','捲簾天色靜，近瀨覺衣單。',48,'全唐诗/poet.tang.27000.json','["捲簾天色靜，近瀨覺衣單。", "蕉葉猶停翠，桐陰已爽寒。", "雲從高處望，琴愛靜時彈。", "正去重陽近，吟秋意未闌。"]'),
('bf1cf560-66f2-4f61-8506-91e8e6feed2e','和劉補闕秋園寓興之什十首 九','朱慶餘','唐','唐诗','tang','','[]','竹逕通鄰圃，清深稱獨遊。',48,'全唐诗/poet.tang.27000.json','["竹逕通鄰圃，清深稱獨遊。", "蟲絲交影細，藤子墜聲幽。", "積潤苔紋厚，迎寒薺葉稠。", "閑來尋古畫，未廢執茶甌。"]'),
('5dbd00e7-6f2e-4b19-8fde-03a101627155','和劉補闕秋園寓興之什十首 十','朱慶餘','唐','唐诗','tang','','[]','風物已蕭颯，晚煙生霽容。',48,'全唐诗/poet.tang.27000.json','["風物已蕭颯，晚煙生霽容。", "斜分紫陌樹，遠隔翠微鐘。", "宿客論文靜，閑燈落燼重。", "無窮林下意，真得古人風。"]'),
('d9056d4f-9c7b-47e9-ab49-0df20de7e568','上翰林蔣防舍人','朱慶餘','唐','唐诗','tang','','[]','清重可過知內制，從前禮絕外庭人。',64,'全唐诗/poet.tang.27000.json','["清重可過知內制，從前禮絕外庭人。", "看花在處多隨駕，召宴無時不及旬。", "馬自賜來騎覺穩，詩緣得後意長新。", "應憐獨在文場久，十有餘年浪過春。"]'),
('a6771f89-b3a9-4c0a-a607-a28a1c701dba','上翰林李舍人','朱慶餘','唐','唐诗','tang','','[]','記得早年曾拜識，便憐孤進賞文章。',64,'全唐诗/poet.tang.27000.json','["記得早年曾拜識，便憐孤進賞文章。", "免令汩沒慙時輩，與作聲名徹舉場。", "一自鳳池承密旨，今因世路接餘光。", "雲泥雖隔思長在，縱使無成也不忘。"]'),
('ad651546-e699-4073-9524-0c502f06b2cd','題章正字道正新居','朱慶餘','唐','唐诗','tang','','[]','獨在御樓南畔住，生涯還似舊時貧。',64,'全唐诗/poet.tang.27000.json','["獨在御樓南畔住，生涯還似舊時貧。", "全無竹可侵行逕，一半花猶屬別人。", "吟處不妨嫌鼓鬧，眼前唯稱與僧鄰。", "近來漸覺青莎巷，車馬過從已有塵。"]'),
('9134dd15-a8de-470a-9b0b-67882f053ad2','送李餘及第歸蜀','朱慶餘','唐','唐诗','tang','','[]','從得高科名轉盛，亦言歸去滿城知。',64,'全唐诗/poet.tang.27000.json','["從得高科名轉盛，亦言歸去滿城知。", "發時誰不開筵送，到處人爭與馬騎。", "劍路紅蕉明棧閣，巴村綠樹蔭神祠。", "鄉中後輩遊門館，半是來求近日詩。"]'),
('0d04cc1d-1ad6-472c-9de3-75695aae467c','送唐中丞開淘西湖夏日遊泛因書示郡人','朱慶餘','唐','唐诗','tang','','["\u897f\u6e56"]','萍岸新淘見碧霄，中流相去忽成遙。',64,'全唐诗/poet.tang.27000.json','["萍岸新淘見碧霄，中流相去忽成遙。", "空餘孤嶼來詩景，無復橫槎礙柳條。", "紅斾路幽山翠濕，錦帆風起浪花飄。", "共知浸潤同雷澤，何慮川源有旱苗。"]'),
('135f397f-79dc-4e50-8f5f-274f59c3ccf5','過舊宅','朱慶餘','唐','唐诗','tang','','[]','古巷戟門誰舊宅，早曾聞說屬官家。',64,'全唐诗/poet.tang.27000.json','["古巷戟門誰舊宅，早曾聞說屬官家。", "更無新燕來巢屋，唯有閑人去看花。", "空廐欲摧塵滿櫪，小池初涸草侵沙。", "榮華事歇皆如此，立馬踟躕到日斜。"]'),
('d76058cf-498c-4b25-bfa4-f88124a662c7','鄂渚送白舍人赴杭州','朱慶餘','唐','唐诗','tang','','[]','豈知鸚鵡洲邊路，得見鳳皇池上人。',32,'全唐诗/poet.tang.27000.json','["豈知鸚鵡洲邊路，得見鳳皇池上人。", "從此不同諸客禮，故鄉西與郡城鄰。"]'),
('2b0b920d-2e23-4075-8766-efcfb52cf365','題崔駙馬林亭','朱慶餘','唐','唐诗','tang','','[]','選居幽近御街東，易得詩人聚會同。',64,'全唐诗/poet.tang.27000.json','["選居幽近御街東，易得詩人聚會同。", "白練鳥飛深竹裏，朱弦琴在亂書中。", "亭開山色當高枕，樓靜簫聲落遠風。", "何事宦塗猶寂寞，都緣清苦道難通。"]'),
('1ae54ca9-b3d5-468c-99cd-89105be7c74d','贈韓協律','朱慶餘','唐','唐诗','tang','','[]','永日微吟在竹前，骨清唯愛漱寒泉。',64,'全唐诗/poet.tang.27000.json','["永日微吟在竹前，骨清唯愛漱寒泉。", "門閑多有投文客，身病長無買藥錢。", "嶺寺聽猨頻獨宿，湖亭避宴動經年。", "親知盡怪疎榮祿，的是將心暗學禪。"]'),
('52ed960a-431b-4146-91bf-97f54e37634e','自蕭關望臨洮','朱慶餘','唐','唐诗','tang','','[]','玉關西路出臨洮，風卷邊沙入馬毛。',64,'全唐诗/poet.tang.27000.json','["玉關西路出臨洮，風卷邊沙入馬毛。", "寺寺院中無竹樹，家家壁上有弓刀。", "惟憐戰士垂金甲，不尚游人著白袍。", "日暮獨吟秋色裏，平原一望戍樓高。"]'),
('ed92ee70-1aef-49a2-8524-3f1c45ceb69b','送崔約下第歸淮南覲省','朱慶餘','唐','唐诗','tang','','[]','遠憶拜親留不住，出門行計與誰同。',64,'全唐诗/poet.tang.27000.json','["遠憶拜親留不住，出門行計與誰同。", "程塗半是依船上，請謁多愁值雨中。", "堰水靜連隄樹綠，村橋時映野花紅。", "迴期須及來春事，莫便江邊逐釣翁。"]'),
('b7ff924e-3483-4eac-aa32-ed49102a9a08','羽林郎','朱慶餘','唐','唐诗','tang','','[]','紫髯年少奉恩初，直閤將軍盡不如。',64,'全唐诗/poet.tang.27000.json','["紫髯年少奉恩初，直閤將軍盡不如。", "酒後引兵圍百草，風前駐斾領邊書。", "宅將公主同時賜，官與中郎共日除。", "大笑魯儒年四十，腰間猶未識金魚。"]'),
('55030410-716b-4d67-a1b0-e0a4c5879e0d','歸故園','朱慶餘','唐','唐诗','tang','','[]','桑柘駢闐數畝間，門前五柳正堪攀。',64,'全唐诗/poet.tang.27000.json','["桑柘駢闐數畝間，門前五柳正堪攀。", "尊中美酒長須滿，身外浮名總是閑。", "竹逕有時風爲掃，柴門無事日常關。", "於焉已是忘機地，何用將金別買山。"]'),
('d397f9ff-61b3-4a59-896a-2ecbbb1086e0','同友人看花','朱慶餘','唐','唐诗','tang','','[]','尋花不問春深淺，縱是殘紅也入詩。',32,'全唐诗/poet.tang.27000.json','["尋花不問春深淺，縱是殘紅也入詩。", "每箇樹邊行一匝，誰家園裏最多時。"]'),
('28dc6a9c-4ddc-469b-b67c-f0644feed392','種花','朱慶餘','唐','唐诗','tang','','[]','憶昔兩京官道上，可憐桃李晝陰垂。',32,'全唐诗/poet.tang.27000.json','["憶昔兩京官道上，可憐桃李晝陰垂。", "不知誰作巡花使，空記玄宗遣種時。"]'),
('4d37ca52-f091-4b6e-974c-2b1426c9647d','早發廬江塗中遇雪寄李侍御','朱慶餘','唐','唐诗','tang','','[]','蘆葦聲多雁滿陂，濕雲連野見山稀。',32,'全唐诗/poet.tang.27000.json','["蘆葦聲多雁滿陂，濕雲連野見山稀。", "遙知將吏相逢處，半是春城賀雪歸。"]'),
('a7a69a13-5946-44c8-99d1-fb2f5871aeef','登望雲亭招友','朱慶餘','唐','唐诗','tang','','[]','日日恐無雲可望，不辭逐靜望來頻。',32,'全唐诗/poet.tang.27000.json','["日日恐無雲可望，不辭逐靜望來頻。", "共知亭下眠雲遠，解到上頭能幾人。"]'),
('e22c844d-82f0-4e04-8ccf-5315e4651e8d','劉補闕西亭晚宴','朱慶餘','唐','唐诗','tang','','[]','蟲聲已盡菊花乾，共立松陰向晚寒。',32,'全唐诗/poet.tang.27000.json','["蟲聲已盡菊花乾，共立松陰向晚寒。", "對酒看山俱惜去，不知斜月下欄干。"]'),
('f9f8b755-0cf3-4caf-8b6b-cb9e944ce223','送長安羅少府','朱慶餘','唐','唐诗','tang','','[]','科名再得年猶少，今日休官更覺賢。',64,'全唐诗/poet.tang.27000.json','["科名再得年猶少，今日休官更覺賢。", "去國已辭趨府伴，向家還入渡江船。", "雪晴新雁斜行出，潮落殘雲遠色鮮。", "在處若逢山水住，到時應不及秋前。"]'),
('3ac93167-4230-4482-b86a-252d3d3b42e2','林下招胡長官','朱慶餘','唐','唐诗','tang','','[]','語低清貌似休糧，稱著朱衣入草堂。',32,'全唐诗/poet.tang.27000.json','["語低清貌似休糧，稱著朱衣入草堂。", "銷暑近來無別物，桂陰當午滿繩牀。"]'),
('84a0479f-69ed-4692-adf0-2cfc09356831','與真上人一二禪師題玢寺主院','朱慶餘','唐','唐诗','tang','','[]','杖屨相隨任處便，不唯空寄上方眠。',32,'全唐诗/poet.tang.27000.json','["杖屨相隨任處便，不唯空寄上方眠。", "歸時亦取湖邊路，晚映楓林共上船。"]'),
('ebcb0204-5d42-4df4-bb14-899d6595524b','尋僧','朱慶餘','唐','唐诗','tang','','[]','吟背春城出草遲，天晴紫閣赴僧期。',32,'全唐诗/poet.tang.27000.json','["吟背春城出草遲，天晴紫閣赴僧期。", "山邊樹下行人少，一派新泉日午時。"]'),
('a5aa4669-250b-4f48-ba8c-bea506b3b046','題王丘長史宅','朱慶餘','唐','唐诗','tang','','[]','更無人吏在門前，不似居官似學僊。',64,'全唐诗/poet.tang.27000.json','["更無人吏在門前，不似居官似學僊。", "藥氣暗侵朝服上，花陰晚到簿書邊。", "玉琴閑把看山坐，筒簟長鋪與客眠。", "時見街中騎瘦馬，低頭只是爲詩篇。"]'),
('ef86d45a-dd2b-4fd4-b278-423814d09cb1','寄劉少府','朱慶餘','唐','唐诗','tang','','[]','唯愛圖書兼古器，在官猶自未離貧。',32,'全唐诗/poet.tang.27000.json','["唯愛圖書兼古器，在官猶自未離貧。", "更聞縣去青山近，稱與詩人作主人。"]'),
('bb702bdc-4e71-4794-b520-f32b0ce31945','哭胡遇','朱慶餘','唐','唐诗','tang','','[]','尋僧昨日尚相隨，忽見緋幡意可知。',64,'全唐诗/poet.tang.27000.json','["尋僧昨日尚相隨，忽見緋幡意可知。", "題處舊詩休更讀，買來新馬憶曾騎。", "不應隨分空營奠，終擬求人與立碑。", "每向宣陽里中過，遙聞哭臨淚先垂。"]'),
('c0cfda5e-1d17-4f80-96b6-5594df5cdc31','自述','朱慶餘','唐','唐诗','tang','','[]','詩人甘寂寞，居處遍蒼苔。',48,'全唐诗/poet.tang.27000.json','["詩人甘寂寞，居處遍蒼苔。", "後夜蟾光滿，鄰家樹影來。", "豈知蓮帳好，自愛草堂開。", "願答相思意，援毫愧不才。"]'),
('9f3d01f4-dafd-4b90-b1e8-144e6f0e39e9','省試晦日與同志昆明池泛舟','朱慶餘','唐','唐诗','tang','','[]','故人同泛處，遠色望中明。',72,'全唐诗/poet.tang.27000.json','["故人同泛處，遠色望中明。", "靜見沙痕露，微思月魄生。", "周回餘雪在，浩渺暮雲平。", "戲鳥隨蘭棹，空波盪石鯨。", "劫灰難問理，島樹偶知名。", "自省曾追賞，無如此日情。"]'),
('2adcf850-97db-4e8f-8bc8-fa473122a1c1','送崔拾遺赴闕','朱慶餘','唐','唐诗','tang','','[]','清貌淩寒玉，朝來拜拾遺。',48,'全唐诗/poet.tang.27000.json','["清貌淩寒玉，朝來拜拾遺。", "行承天子詔，去感主人知。", "劒佩分班日，風霜獨立時。", "名高住不得，非與九霄期。"]'),
('11c7f3ee-93d1-4ed0-99da-cd401181d030','酬李處士見贈','朱慶餘','唐','唐诗','tang','','[]','干上非無援，才多却累身。',48,'全唐诗/poet.tang.27000.json','["干上非無援，才多却累身。", "雲霄未得路，江海作閑人。", "久別唯謀道，相逢不話貧。", "行藏一如此，可便老風塵。"]'),
('63d45680-0b25-46ca-9d61-656bfb18f605','送僧遊溫州','朱慶餘','唐','唐诗','tang','','[]','夏滿隨所適，江湖非繫緣。',48,'全唐诗/poet.tang.27000.json','["夏滿隨所適，江湖非繫緣。", "卷經離嶠寺，隔葦上秋船。", "水落無風夜，猨啼欲雨天。", "石門期獨往，謝守有遺篇。"]'),
('21bb6db5-e3c2-448d-9258-096e0bbda95d','夢謝亭','朱慶餘','唐','唐诗','tang','','[]','夢後何人見，孤亭似舊時。',48,'全唐诗/poet.tang.27000.json','["夢後何人見，孤亭似舊時。", "褰開誠得地，冥感竟因詩。", "不往過應少，悲來下獨遲。", "顧慙非謝客，靈貺杳難追。"]'),
('6221209e-61c5-44ad-93ae-6198ffe21510','河亭','朱慶餘','唐','唐诗','tang','','[]','孤亭臨絕岸，猨鳥識幽蹊。',48,'全唐诗/poet.tang.27000.json','["孤亭臨絕岸，猨鳥識幽蹊。", "花落曾誰到，詩成獨未題。", "潮痕經雨在，石筍與杉齊。", "謝守便登陟，秋來屐齒低。"]'),
('13e0fbbf-4cf6-4435-9062-186db1e23400','送吳秀才之山西','朱慶餘','唐','唐诗','tang','','[]','澤潞西邊路，蘭橈北去人。',48,'全唐诗/poet.tang.27000.json','["澤潞西邊路，蘭橈北去人。", "出門誰恨別，投分不緣貧。", "桮酒從年少，知音在日新。", "東湖發詩意，夏卉竟如春。"]'),
('5b99d9eb-c052-4422-b5d1-245028e52f53','和處州嚴郎中遊南溪','朱慶餘','唐','唐诗','tang','','[]','四望非人境，從前洞穴深。',48,'全唐诗/poet.tang.27000.json','["四望非人境，從前洞穴深。", "潭清蒲遠岸，嵐積樹無陰。", "看草初移屐，捫蘿忽並簪。", "世嫌山水僻，誰伴謝公吟。"]'),
('0105e62d-6794-41bd-beaa-f7f52e2badad','秋宵讌別盧侍御','朱慶餘','唐','唐诗','tang','','[]','風亭弦管絕，玉漏一聲新。',48,'全唐诗/poet.tang.27000.json','["風亭弦管絕，玉漏一聲新。", "綠茗香醒酒，寒燈靜照人。", "清班無意戀，素業本來貧。", "明發青山道，誰逢去馬塵。"]'),
('7bd28681-ff10-48a6-ae7f-9b2ab52f702d','酬于訢校書見貽','朱慶餘','唐','唐诗','tang','','[]','能□得從軍，清嬴□□□。',48,'全唐诗/poet.tang.27000.json','["能□得從軍，清嬴□□□。", "綺羅徒滿目，山水不離心。", "暫別愁花老，相思倚竹陰。", "家貧無以養，未可話抽簪。"]'),
('9ec9ae57-d8b4-40bd-8db6-d2a279bbc828','送石協律歸吳興別業','朱慶餘','唐','唐诗','tang','','[]','識來無定居，此去復何如。',48,'全唐诗/poet.tang.27000.json','["識來無定居，此去復何如。", "一與耕者遇，轉將朝客疎。", "資身唯藥草，教子但詩書。", "曾許黃庭本，斯言豈合虛。"]'),
('700bbfba-a827-4381-9702-1545490581b5','同盧校書遊新興寺','朱慶餘','唐','唐诗','tang','','[]','山深雲景別，有寺亦堪過。',48,'全唐诗/poet.tang.27000.json','["山深雲景別，有寺亦堪過。", "才子將迎遠，林僧氣性和。", "潭清蒲影定，松老鶴聲多。", "豈不思公府，其如野興何。"]'),
('bff10ce6-0511-4977-b5af-593caa8027f7','送馬秀才','朱慶餘','唐','唐诗','tang','','[]','清貌不識睡，見來嘗苦吟。',48,'全唐诗/poet.tang.27000.json','["清貌不識睡，見來嘗苦吟。", "風塵歸省日，江海寄家心。", "與鶴期前島，隨僧過遠林。", "相於竟何事，無語與知音。"]'),
('1caa4d86-6876-4497-80b4-331a71d7e71b','贈律師院','朱慶餘','唐','唐诗','tang','','[]','粉壁通蓮徑，扁舟到不迷。',48,'全唐诗/poet.tang.27000.json','["粉壁通蓮徑，扁舟到不迷。", "葦聲過枕上，湖色滿窗西。", "但見修行苦，誰論夏臘低。", "閑看種來樹，已覺與身齊。"]'),
('d52c524c-0492-4b47-9833-06872932ce06','送僧往台嶽','朱慶餘','唐','唐诗','tang','','[]','五城初罷講，海上憶閑行。',48,'全唐诗/poet.tang.27000.json','["五城初罷講，海上憶閑行。", "觸雪麻衣靜，登山竹錫輕。", "天寒嶽寺出，日晚島泉清。", "坐與幽期遇，何人識此情。"]'),
('5dc1d88a-8fd6-4f39-b1a3-cea6d1b1d796','送惠雅上人西遊','朱慶餘','唐','唐诗','tang','','[]','五湖僧獨往，此去與誰期。',48,'全唐诗/poet.tang.27000.json','["五湖僧獨往，此去與誰期。", "興遠常憐鶴，禪餘肯廢詩。", "望雲回寺晚，爲講到城遲。", "還想安居日，應當後夏時。"]'),
('b1374f24-b406-4143-9b5c-22e1d3256261','將之上京留別淮南書記李侍御','朱慶餘','唐','唐诗','tang','','[]','半似無名位，門當靜處開。',48,'全唐诗/poet.tang.27000.json','["半似無名位，門當靜處開。", "人心皆向德，物色不供才。", "酒興春邊過，軍謀意外來。", "取名榮相府，却慮詔書催。"]'),
('e83f8747-d008-461c-ad9e-344166891581','送祝秀才歸衢州','朱慶餘','唐','唐诗','tang','','[]','舊隱縠溪上，憶歸年已深。',48,'全唐诗/poet.tang.27000.json','["舊隱縠溪上，憶歸年已深。", "學徒花下別，鄉路雪邊尋。", "騎吏陪春賞，江僧伴晚吟。", "高科如在意，當自惜光陰。"]'),
('902a47f7-664b-4ff9-bb26-2977375cd042','過孟浩然舊居','朱慶餘','唐','唐诗','tang','','[]','命合終山水，才非不稱時。',48,'全唐诗/poet.tang.27000.json','["命合終山水，才非不稱時。", "冢邊空有樹，身後獨無兒。", "散盡詩篇本，長存道德碑。", "平生誰見重，應只是王維。"]'),
('1db3e56f-0386-4132-87d4-c5d969e7bdb3','送虛上人遊天台','朱慶餘','唐','唐诗','tang','','[]','青冥通去路，誰見獨隨緣。',48,'全唐诗/poet.tang.27000.json','["青冥通去路，誰見獨隨緣。", "此地春前別，何山夜後禪。", "石橋隱深樹，朱闕見晴天。", "好是修行處，師當住幾年。"]'),
('2f6fd6a6-9fcc-4f91-869e-34cc83469a4f','孔尚書致仕因而有寄贈','朱慶餘','唐','唐诗','tang','','[]','高人心易足，三表乞身閑。',48,'全唐诗/poet.tang.27000.json','["高人心易足，三表乞身閑。", "與世長疎索，唯僧得往還。", "直聲留闕下，生事在林間。", "時復逢清景，乘車看遠山。"]'),
('808b90bd-cca2-4269-9726-6d73c3742f66','和處州韋使君新開南溪','朱慶餘','唐','唐诗','tang','','[]','地里光圖讖，樵人共說深。',120,'全唐诗/poet.tang.27000.json','["地里光圖讖，樵人共說深。", "悠然想高躅，坐使變荒岑。", "疏鑿因殊舊，亭臺亦自今。", "靜容猨暫下，閑與鶴同尋。", "轉斾馴禽起，褰帷瀑溜侵。", "石稀潭見底，嵐暗樹無陰。", "躋險難通屐，攀栖稱抱琴。", "雲風開物意，潭水識人心。", "攜榼巡花遍，移舟惜景沈。", "世嫌山水僻，誰伴謝公吟。"]'),
('5d60d838-c54b-4e42-957c-0e60151892d3','送羅先輩書記歸後却還閩中留別','朱慶餘','唐','唐诗','tang','','[]','同是越人從小別，忽歸鄉里見皆驚。',64,'全唐诗/poet.tang.27000.json','["同是越人從小別，忽歸鄉里見皆驚。", "湖邊訪舊知誰在，幕下留歡但覺榮。", "望嶺又生紅槿思，登車豈倦白雲程。", "況當季父承恩日，廉問南州政已成。"]'),
('1749d518-b7ef-4958-b7a8-f82c3f0e30d2','送浙東陸中丞','朱慶餘','唐','唐诗','tang','','[]','坐將文教鎮藩維，花滿東南聖主知。',64,'全唐诗/poet.tang.27000.json','["坐將文教鎮藩維，花滿東南聖主知。", "公務肯容私暫入，豐年長與德相隨。", "無賢不是朱門客，有子皆如玉樹枝。", "自愛此身居樂土，詠歌林下日忘疲。"]'),
('2d99b5dd-863a-4b50-ad3d-fe5c9ea8a8d9','送元處士遊天台','朱慶餘','唐','唐诗','tang','','[]','青冥路口絕人行，獨與僧期上赤城。',64,'全唐诗/poet.tang.27000.json','["青冥路口絕人行，獨與僧期上赤城。", "樹列煙嵐春更好，溪藏冰雪夜偏明。", "空山雉雊禾苗短，野館風來竹氣清。", "若過石橋看瀑布，不妨高處便題名。"]'),
('fd3f74e0-af6f-412a-ac49-1a5ed59a4acb','吳興新隄','朱慶餘','唐','唐诗','tang','','[]','春隄一望思無涯，樹勢還同水勢斜。',64,'全唐诗/poet.tang.27000.json','["春隄一望思無涯，樹勢還同水勢斜。", "深映菰蒲三十里，晴分功利幾千家。", "謀成既不勞人力，境遠偏宜隔浪花。", "若與青山長作固，汀洲肯恨柳絲遮。"]'),
('b1afdc43-3cc3-4a9d-bf37-845f03fbf6d6','酬蕭員外見寄','朱慶餘','唐','唐诗','tang','','[]','麥風吹雨正徘徊，忽報書從郡閤來。',80,'全唐诗/poet.tang.27000.json','["麥風吹雨正徘徊，忽報書從郡閤來。", "道薄謬應宗伯選，詩成徒費謝公才。", "九霄示路空知感，十上驚魂尚未回。", "勝寄幸容溪館宿，龍鍾慙見妓筵開。", "儻期霽後陪新興，一滴還須當一桮。"]'),
('fd222bd4-4e40-4f32-90d1-ef505a11cac7','台州鄭員外郡齋雙鶴','朱慶餘','唐','唐诗','tang','','[]','丹頂分明音響別，況聞來處隔雲濤。',64,'全唐诗/poet.tang.27000.json','["丹頂分明音響別，況聞來處隔雲濤。", "情懸碧落飛何晚，立近清池意自高。", "向夜雙栖驚玉漏，臨軒對舞拂朱袍。", "仙郎爲爾開籠早，莫慮回翔損羽毛。"]'),
('1ac43bcf-beef-4718-8823-44558246b01a','送竇秀才','朱慶餘','唐','唐诗','tang','','[]','江南才子日紛紛，少有篇章得似君。',64,'全唐诗/poet.tang.27000.json','["江南才子日紛紛，少有篇章得似君。", "清話未同山寺宿，離歌已向客亭聞。", "梅天馬上愁黃鳥，澤國帆前見白雲。", "通籍名高年又少，回頭應笑晚從軍。"]'),
('682a20c9-ff54-4cd2-8889-77725520aa47','送邵州林使君','朱慶餘','唐','唐诗','tang','','[]','軒車此去也逢時，地近湘南頗入詩。',64,'全唐诗/poet.tang.27000.json','["軒車此去也逢時，地近湘南頗入詩。", "一月計程那是遠，中年出守未爲遲。", "水邊花氣熏章服，嶺上嵐光照畫旗。", "想得化行風土變，州人應爲立生祠。"]'),
('b46c2a3b-9446-489e-893d-83d9a39a1f92','送饒州張使君','朱慶餘','唐','唐诗','tang','','[]','白頭爲郡清秋別，山水南行豈覺賒。',64,'全唐诗/poet.tang.27000.json','["白頭爲郡清秋別，山水南行豈覺賒。", "楚老只應思入境，吳兒從此去移家。", "館依高嶺分樟葉，路出重江見葦花。", "務退唯當吟詠苦，留心曾不在生涯。"]'),
('6e2d06b2-71ce-4998-80c8-5a5e8babf791','題開元寺','朱慶餘','唐','唐诗','tang','','[]','西入山門十里程，粉牆書字甚分明。',64,'全唐诗/poet.tang.27000.json','["西入山門十里程，粉牆書字甚分明。", "蕭帝壞陵深虎跡，廣師遺院閉松聲。", "長廊畫剝僧形影，石壁塵昏客姓名。", "何必更將空色遣，眼前人事是浮生。"]'),
('6545b7fb-2947-4cbb-8e58-54a3eb3d5aa0','與龐復言攜酒望洞庭','朱慶餘','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南湖春色通平遠，貪記詩情忘酒桮。',64,'全唐诗/poet.tang.27000.json','["南湖春色通平遠，貪記詩情忘酒桮。", "帆自巴陵山下過，雨從神女峽邊來。", "青蒲映水疎還密，白鳥飜空去復回。", "盡日與君同看望，了然勝見畫屏開。"]'),
('86aa3f64-8b5f-4f93-b92f-c6a5bf32c8bb','送浙東周判官','朱慶餘','唐','唐诗','tang','','[]','久聞從事滄江外，誰謂無官已白頭。',64,'全唐诗/poet.tang.27000.json','["久聞從事滄江外，誰謂無官已白頭。", "來備戎裝嘶數騎，去持丹詔入孤舟。", "蟬鳴遠驛殘陽樹，鷺起湖田片雨秋。", "到日重陪丞相宴，鏡湖新月在城樓。"]'),
('9ae49d63-b763-4c87-b7f3-a97a413b048e','塞下曲','朱慶餘','唐','唐诗','tang','','[]','萬里去長征，連年慣野營。',48,'全唐诗/poet.tang.27000.json','["萬里去長征，連年慣野營。", "入羣來擇馬，拋伴去擒生。", "箭撚雕翎闊，弓盤鵲角輕。", "問看行近遠，西過受降城。"]'),
('7b18a5e2-6bf7-4ec7-82c7-a637082395a4','送僧','朱慶餘','唐','唐诗','tang','','[]','客行皆有爲，師去是閑遊。',48,'全唐诗/poet.tang.27000.json','["客行皆有爲，師去是閑遊。", "野望攜金策，禪棲寄石樓。", "山深松翠冷，潭靜菊花秋。", "幾處題青壁，袈裟濺瀑流。"]'),
('c4f9a0ca-0711-4034-8bbb-243ab2db8089','望早日','朱慶餘','唐','唐诗','tang','','[]','窗下聞雞後，蒼茫映遠林。',48,'全唐诗/poet.tang.27000.json','["窗下聞雞後，蒼茫映遠林。", "纔分天地色，便禁虎狼心。", "是處程塗遠，何山洞府深。", "此時堪竚望，萬象豁塵襟。"]'),
('87f011af-0982-4eb7-afe9-52056720f955','旅中秋月有懷','朱慶餘','唐','唐诗','tang','','[]','久客未還鄉，中秋倍可傷。',48,'全唐诗/poet.tang.27000.json','["久客未還鄉，中秋倍可傷。", "暮天飛旅鴈，故國在衡陽。", "島外歸雲迥，林間墜葉黃。", "數宵千里夢，時見舊書堂。"]'),
('c551a9b5-7f99-41ba-987b-e9913b4f461b','十六夜月','朱慶餘','唐','唐诗','tang','','[]','昨夜忽已過，冰輪始覺虧。',48,'全唐诗/poet.tang.27000.json','["昨夜忽已過，冰輪始覺虧。", "孤光猶不定，浮世更堪疑。", "影落澄江海，寒生靜路岐。", "皎然銀漢外，長有衆星隨。"]'),
('d9c65d21-b81a-429e-8c82-a1a488e9196c','行路難','朱慶餘','唐','唐诗','tang','','[]','世事澆浮後，艱難向此生。',48,'全唐诗/poet.tang.27000.json','["世事澆浮後，艱難向此生。", "人心不自足，公道爲誰平。", "德喪淳風盡，年荒蔓草盈。", "堪悲山下路，非祗客中行。"]'),
('bab1e9fc-3843-4daf-a620-8d764ad5725d','閑居冬末寄友人','朱慶餘','唐','唐诗','tang','','[]','短亭分袂後，倚檻思偏孤。',48,'全唐诗/poet.tang.27000.json','["短亭分袂後，倚檻思偏孤。", "雨雪落殘臘，輪蹄在遠塗。", "人情難故舊，草色易凋枯。", "共有男兒事，何年入帝都。"]'),
('8d6be75a-8988-4ff2-b5eb-3fb57e72a204','望九疑','朱慶餘','唐','唐诗','tang','','[]','浮生猶役役，未得便尋真。',48,'全唐诗/poet.tang.27000.json','["浮生猶役役，未得便尋真。", "白日如無路，青山豈有人。", "煙收遙岫小，雨過晚川新。", "倚杖何凝望，中宵夢往頻。"]'),
('a7b172a2-7feb-4eeb-8841-20743489010b','贈陳逸人','朱慶餘','唐','唐诗','tang','','[]','樂道辭榮祿，安居桂水東。',48,'全唐诗/poet.tang.27000.json','["樂道辭榮祿，安居桂水東。", "得閑多事外，知足少年中。", "藥圃無凡草，松庭有素風。", "朝昏吟步處，琴酒與誰同。"]'),
('488a2521-03b3-4764-9014-68bc23f55ca4','湖中閑夜遣興','朱慶餘','唐','唐诗','tang','','[]','釣艇同琴酒，良宵背水濱。',48,'全唐诗/poet.tang.27000.json','["釣艇同琴酒，良宵背水濱。", "風波不起處，星月盡隨身。", "浦迥湘煙卷，林香嶽氣春。", "誰知此中興，寧羨五湖人。"]'),
('1c025561-8e38-4a43-bb1b-103e2caab179','題娥皇廟','朱慶餘','唐','唐诗','tang','','[]','娥皇揮涕處，東望九疑天。',48,'全唐诗/poet.tang.27000.json','["娥皇揮涕處，東望九疑天。", "往事難重問，孤峰尚慘然。", "夜深寒峒響，秋近碧蘿鮮。", "未省明君意，遺蹤萬古傳。"]'),
('dd228c0b-0c2e-4029-b701-1a28a3fdb1de','送友人赴舉','朱慶餘','唐','唐诗','tang','','[]','世路□□久，嗟君進取身。',48,'全唐诗/poet.tang.27000.json','["世路□□久，嗟君進取身。", "十年雖苦志，萬里託何人。", "處困非乖道，求名本爲親。", "惟應□□意，先與化龍鱗。"]'),
('02663621-0eb3-4a54-a3cc-d8093e02d35d','中秋月','朱慶餘','唐','唐诗','tang','','[]','自古分功定，唯應缺又盈。',48,'全唐诗/poet.tang.27000.json','["自古分功定，唯應缺又盈。", "一宵當皎潔，四海盡澄清。", "靜覺風微起，寒過雪乍傾。", "孤高稀此遇，吟賞倍牽情。"]'),
('53da8995-85e6-450b-bcef-1f1434c6152a','宿山居','朱慶餘','唐','唐诗','tang','','[]','山店燈前客，醻身未有媒。',48,'全唐诗/poet.tang.27000.json','["山店燈前客，醻身未有媒。", "鄉關貧後別，風雨夜深來。", "上國求丹桂，衡門長綠苔。", "堪驚雙鬢雪，不待歲寒催。"]'),
('376d8569-1634-4549-9e2a-4f5ae128a1dd','夏末留別洞庭知己','朱慶餘','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','清秋時節近，分袂獨淒然。',48,'全唐诗/poet.tang.27000.json','["清秋時節近，分袂獨淒然。", "此地折高柳，何門聽暮蟬。", "浪搖湖外日，山背楚南天。", "空感迢迢事，榮歸在幾年。"]'),
('aa9589ad-2b7a-40d5-9486-8c865d1b884d','過洞庭','朱慶餘','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','帆挂狂風起，茫茫既往時。',48,'全唐诗/poet.tang.27000.json','["帆挂狂風起，茫茫既往時。", "波濤如未息，舟楫亦堪疑。", "旅鴈投孤島，長天下四維。", "前程有平處，誰敢與心期。"]'),
('4b804d84-a944-450e-84c5-dcf889b2b47b','旅中過重陽','朱慶餘','唐','唐诗','tang','','[]','一歲重陽至，羈遊在異鄉。',48,'全唐诗/poet.tang.27000.json','["一歲重陽至，羈遊在異鄉。", "登高思舊友，滿目是窮荒。", "草際飛雲片，天涯落鴈行。", "故山籬畔菊，今日爲誰黃。"]'),
('3a8492d4-bf1f-494b-a473-51093ac68abf','送人下第歸','朱慶餘','唐','唐诗','tang','','[]','獨立身難達，新春與志違。',48,'全唐诗/poet.tang.27000.json','["獨立身難達，新春與志違。", "異鄉青草長，故國白頭歸。", "岸闊湖波溢，程遙楚岫微。", "高秋期再會，此去莫忘機。"]'),
('77e543f8-132e-491a-abe9-c1501f07c210','敘吟','朱慶餘','唐','唐诗','tang','','[]','雅道辛勤久，潛疑鬢雪侵。',48,'全唐诗/poet.tang.27000.json','["雅道辛勤久，潛疑鬢雪侵。", "未能酬片善，難更免孤吟。", "有景皆牽思，無愁不到心。", "遙天一輪月，幾夜見西沈。"]'),
('1a68da77-b66a-4d2c-89c2-9e0acc450006','塞下感懷','朱慶餘','唐','唐诗','tang','','[]','塞下閑爲客，鄉心豈易安。',48,'全唐诗/poet.tang.27000.json','["塞下閑爲客，鄉心豈易安。", "程塗過萬里，身事尚孤寒。", "竟日風沙急，臨秋草木殘。", "何年方致主，時拂劒塵看。"]'),
('6283bd89-92ba-44c4-8335-e5a0b2aaa225','宿江館','朱慶餘','唐','唐诗','tang','','[]','江館迢遙處，知音信漸賒。',48,'全唐诗/poet.tang.27000.json','["江館迢遙處，知音信漸賒。", "夜深鄉夢覺，窗下月明斜。", "起鴈看荒草，驚波尚白沙。", "那堪動鄉思，故國在天涯。"]'),
('8a1ef92f-b5b7-4155-a827-4195b20f2d78','早梅','朱慶餘','唐','唐诗','tang','','[]','天然根性異，萬物盡難陪。',48,'全唐诗/poet.tang.27000.json','["天然根性異，萬物盡難陪。", "自古承春早，嚴冬鬬雪開。", "豔寒宜雨露，香冷隔塵埃。", "堪把依松竹，良塗一處栽。"]'),
('0aa6d6ff-9b3a-43c5-b068-13a5e1c7ab9d','夏日訪貞上人院','朱慶餘','唐','唐诗','tang','','[]','炎夏尋靈境，高僧澹蕩中。',48,'全唐诗/poet.tang.27000.json','["炎夏尋靈境，高僧澹蕩中。", "命棊隈綠竹，盡日有清風。", "流水離經閣，閑雲入梵宮。", "此時祛萬慮，直似出塵籠。"]'),
('723e35d0-f134-4301-bf97-c344eae72f1e','春日旅次','朱慶餘','唐','唐诗','tang','','[]','林中鶯又囀，爲客恨因循。',48,'全唐诗/poet.tang.27000.json','["林中鶯又囀，爲客恨因循。", "故里遙千里，青春過數春。", "弟兄來漸少，歲月去何頻。", "早晚榮歸計，中堂會所親。"]'),
('695b9bad-19ce-4212-896c-29bf5f70e1d7','贈至寂禪師','朱慶餘','唐','唐诗','tang','','[]','處世唯披衲，禪門幾歲寒。',48,'全唐诗/poet.tang.27000.json','["處世唯披衲，禪門幾歲寒。", "法空無所染，性悟不多看。", "竟日門長掩，相逢草自殘。", "有時尋道侶，飛錫度峰巒。"]'),
('f68d3c62-8832-4d5a-aa3c-ccd33f9e1d91','閑居即事','朱慶餘','唐','唐诗','tang','','[]','深嶂多幽景，閑居野興清。',48,'全唐诗/poet.tang.27000.json','["深嶂多幽景，閑居野興清。", "滿庭秋雨過，連夜綠苔生。", "石面橫琴坐，松陰採藥行。", "超然塵事外，不似絆浮名。"]'),
('f62de444-00b3-4afa-bbbf-896f148ce8cf','廢宅花','朱慶餘','唐','唐诗','tang','','[]','數樹荒庭上，芬芳映綠苔。',48,'全唐诗/poet.tang.27000.json','["數樹荒庭上，芬芳映綠苔。", "自緣逢暖發，不是爲人開。", "色豔鶯猶在，香消蝶已回。", "相從無勝事，誰向此傾桮。"]'),
('b3bd9077-ad1c-40e8-b223-60440ac5b5af','寄友人','朱慶餘','唐','唐诗','tang','','[]','當代知音少，相思在此身。',48,'全唐诗/poet.tang.27000.json','["當代知音少，相思在此身。", "一分南北路，長問往來人。", "是處應爲客，何門許掃塵。", "憑書正惆悵，蜀魄數聲新。"]'),
('93a7537a-e725-4b7b-8670-a6c82d898c6c','塗中感懷','朱慶餘','唐','唐诗','tang','','[]','世上名利牽，塗中意慘然。',48,'全唐诗/poet.tang.27000.json','["世上名利牽，塗中意慘然。", "到家能幾日，爲客便經年。", "跡似萍隨水，情同鶴在田。", "何當功業遂，歸路下遙天。"]'),
('81b32160-4eaa-4765-8824-ef33e4ae353e','贈道者','朱慶餘','唐','唐诗','tang','','[]','獨住神仙境，門當瀑布開。',48,'全唐诗/poet.tang.27000.json','["獨住神仙境，門當瀑布開。", "地多臨水石，行不惹塵埃。", "風起松花散，琴鳴鶴翅回。", "還歸九天上，時有故人來。"]'),
('0f55a124-08bc-440e-aee3-a721e7a60b44','長安春日野中','朱慶餘','唐','唐诗','tang','','[]','青春思楚地，閑步出秦城。',48,'全唐诗/poet.tang.27000.json','["青春思楚地，閑步出秦城。", "滿眼是岐路，何年見弟兄。", "煙霞裝媚景，霄漢指前程。", "盡日徘徊處，歸鴻過玉京。"]'),
('c299babc-97c9-4c53-bfdb-be76eb96c076','長城','朱慶餘','唐','唐诗','tang','','[]','秦帝防胡虜，關心倍可嗟。',48,'全唐诗/poet.tang.27000.json','["秦帝防胡虜，關心倍可嗟。", "一人如有德，四海盡爲家。", "往事乾坤在，荒基草木遮。", "至今徒者骨，猶自哭風沙。"]'),
('f8f38d88-a7dd-41c0-ba93-020831fe7d75','酬李躔侍御','朱慶餘','唐','唐诗','tang','','[]','此去非關興，君行不當遊。',24,'全唐诗/poet.tang.27000.json','["此去非關興，君行不當遊。", "無因兩處馬，共飲一溪流。"]'),
('ffb49fbd-d3cd-45a7-9fb9-9774444eeacb','別李侍御後亭夜坐却寄','朱慶餘','唐','唐诗','tang','','[]','已作亭下別，未忘燈下情。',24,'全唐诗/poet.tang.27000.json','["已作亭下別，未忘燈下情。", "吟今欲就枕，更漏轉分明。"]'),
('7df188b7-5728-4d57-8667-4ddf221db3fa','題錢宇別墅','朱慶餘','唐','唐诗','tang','','[]','林居向晚饒清景，惜去非關戀酒桮。',64,'全唐诗/poet.tang.28000.json','["林居向晚饒清景，惜去非關戀酒桮。", "石淨每因杉露滴，地幽漸覺水禽來。", "藥蔬秋後供僧盡，竹杖吟中望月回。", "紅葉閑飄籬落迥，行人遠見草堂開。"]'),
('27ff54ab-4861-43d8-b3c1-69113d2e4e10','近試上張籍水部','朱慶餘','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u65b0\u5a5a", "\u4e03\u8a00\u7edd\u53e5", "\u8003\u8bd5"]','洞房昨夜停紅燭，待曉堂前拜舅姑。',34,'全唐诗/poet.tang.28000.json','["洞房昨夜停紅燭，待曉堂前拜舅姑。", "[妝]罷低聲問夫壻，畫眉深淺入時無。"]'),
('b58c5082-f5d7-4939-a0c5-a3f02eaecb9e','留別盧玄休歸荆門','朱慶餘','唐','唐诗','tang','','[]','江邊離別心，言罷各霑襟。',48,'全唐诗/poet.tang.28000.json','["江邊離別心，言罷各霑襟。", "以我去帆遠，知君離恨深。", "雲開孤島出，浪起白鷗沈。", "更作來年約，陽臺許伴尋。"]'),
('3a1c7ef7-c726-4910-b2e4-dfd4a5409a9c','采蓮','朱慶餘','唐','唐诗','tang','','[]','隔煙花草遠濛濛，恨箇來時路不同。',32,'全唐诗/poet.tang.28000.json','["隔煙花草遠濛濛，恨箇來時路不同。", "正是停橈相遇處，鴛鴦飛去急流中。"]'),
('c747259c-72ea-4440-b377-b71b6f399b45','都門晚望','朱慶餘','唐','唐诗','tang','','[]','綠槐花墮御溝邊，步出都門雨後天。',32,'全唐诗/poet.tang.28000.json','["綠槐花墮御溝邊，步出都門雨後天。", "日暮野人耕種罷，烽樓原上一條煙。"]'),
('70190e71-fe5c-403a-b5da-bce75cd93f7a','舜井','朱慶餘','唐','唐诗','tang','','[]','碧甃磷磷不記年，青蘿鎖在小山顛。',32,'全唐诗/poet.tang.28000.json','["碧甃磷磷不記年，青蘿鎖在小山顛。", "向來下視千山水，疑是蒼梧萬里天。"]'),
('357bfd78-344a-4c05-8c47-5efeb9da1c35','商州王中丞留喫枳殼','朱慶餘','唐','唐诗','tang','','[]','方物就中名最遠，只應愈疾味偏佳。',32,'全唐诗/poet.tang.28000.json','["方物就中名最遠，只應愈疾味偏佳。", "若交盡乞人人與，采盡商山枳殼花。"]'),
('ccbf43a1-7dda-4e2e-9092-20c1d8966ca0','登玄都閣','朱慶餘','唐','唐诗','tang','','[]','野色晴宜上閣看，樹陰遙映御溝寒。',32,'全唐诗/poet.tang.28000.json','["野色晴宜上閣看，樹陰遙映御溝寒。", "豪家舊宅無人住，空見朱門鎖牡丹。"]'),
('87b3b9b5-81f8-4e0b-8ec1-b3f7e64fa3bf','贈鳳翔柳司錄','朱慶餘','唐','唐诗','tang','','[]','杏園北寺題名日，數到如今四十年。',32,'全唐诗/poet.tang.28000.json','["杏園北寺題名日，數到如今四十年。", "點檢生涯與官職，一莖野竹在身邊。"]'),
('d28f0767-5f81-4529-9280-1dd6538a0980','啄木兒','朱慶餘','唐','唐诗','tang','','[]','丁丁向晚急還稀，啄遍庭槐未肯歸。',32,'全唐诗/poet.tang.28000.json','["丁丁向晚急還稀，啄遍庭槐未肯歸。", "終日與君除蠹害，莫嫌無事不頻飛。"]'),
('92f6364f-d21b-45dd-bf49-adce92f74435','榜曲','朱慶餘','唐','唐诗','tang','','[]','荷花明滅水煙空，惆悵來時徑不同。',32,'全唐诗/poet.tang.28000.json','["荷花明滅水煙空，惆悵來時徑不同。", "欲到前洲堪入處，鴛鴦飛出碧流中。"]'),
('cfdf3ee1-e5c0-499f-9359-d897a6ba388d','逢山人','朱慶餘','唐','唐诗','tang','','[]','星月相逢現此身，自然無跡又無塵。',32,'全唐诗/poet.tang.28000.json','["星月相逢現此身，自然無跡又無塵。", "秋來若向金天會，便是青蓮葉上人。"]'),
('01db2ff5-3041-470a-8b13-44baf31a3fab','過耶溪','朱慶餘','唐','唐诗','tang','','[]','春溪繚繞出無窮，兩岸桃花正好風。',32,'全唐诗/poet.tang.28000.json','["春溪繚繞出無窮，兩岸桃花正好風。", "恰是扁舟堪入處，鴛鴦飛起碧流中。"]'),
('c1106d2c-d783-401d-96f6-caea6112767b','賀張水部員外拜命','朱慶餘','唐','唐诗','tang','','[]','省中官最美，無似水曹郎。',48,'全唐诗/poet.tang.28000.json','["省中官最美，無似水曹郎。", "前代佳名遜，當時重姓張。", "白鬚吟麗句，紅葉吐朝陽。", "徒有歸山意，君恩未可忘。"]'),
('5f9c08bb-3a1d-4ff5-90b1-6b4092f898b5','送璧州劉使君','朱慶餘','唐','唐诗','tang','','[]','王府登朝後，巴鄉典郡新。',48,'全唐诗/poet.tang.28000.json','["王府登朝後，巴鄉典郡新。", "江分入峽路，山見採鞭人。", "舊業孤城夢，生祠幾處身。", "知君素清儉，料得却來貧。"]'),
('6a355760-3384-4229-ad39-a9b8a1e7d54d','贈江夏盧使君','朱慶餘','唐','唐诗','tang','','[]','詩人中最屈，無與使君儔。',48,'全唐诗/poet.tang.28000.json','["詩人中最屈，無與使君儔。", "白髮雖求退，明時合見收。", "登山猶自健，縱酒可多愁。", "好是能騎馬，相逢見鄂州。"]'),
('c171c454-08a8-4512-8008-1fb76713def6','送崔秀才遊江陵','朱慶餘','唐','唐诗','tang','','[]','樽前荆楚客，雲外思縈迴。',48,'全唐诗/poet.tang.28000.json','["樽前荆楚客，雲外思縈迴。", "秦野春已盡，商山花正開。", "鷗驚帆乍起，虹見雨初來。", "自有歸期在，蟬聲處處催。"]'),
('c90cee11-8d27-4537-91bc-0ff7b6ecbd57','觀濤','朱慶餘','唐','唐诗','tang','','[]','木落霜飛天地清，空江百里見潮生。',64,'全唐诗/poet.tang.28000.json','["木落霜飛天地清，空江百里見潮生。", "鮮飆出海魚龍氣，晴雪噴山雷鼓聲。", "雲日半陰川漸滿，客帆皆過浪難平。", "高樓曉望無窮意，丹葉黃花繞郡城。"]'),
('5023b104-9ff7-4b84-bb76-f9332fd06520','南湖','朱慶餘','唐','唐诗','tang','','[]','湖上微風小檻涼，翻翻菱荇滿迴塘。',64,'全唐诗/poet.tang.28000.json','["湖上微風小檻涼，翻翻菱荇滿迴塘。", "野船著岸入春草，水鳥帶波飛夕陽。", "蘆葉有聲疑露雨，浪花無際似瀟湘。", "飄然蓬艇東歸客，盡日相看憶楚鄉。"]'),
('4e944273-bee8-4763-a6bb-52e236f81ac2','鏡湖西島言事','朱慶餘','唐','唐诗','tang','','[]','慵拙幸便荒僻地，縱聞猨鳥亦何愁。',64,'全唐诗/poet.tang.28000.json','["慵拙幸便荒僻地，縱聞猨鳥亦何愁。", "偶因藥酒欺梅雨，却著寒衣過麥秋。", "歲計有餘添橡實，生涯一半在漁舟。", "世人若便無知己，應向此溪成白頭。"]'),
('1ffeb13b-7689-44ef-a101-7803ca2af52a','送劉思復南河從軍','朱慶餘','唐','唐诗','tang','','[]','七千里別寧無恨，且貴從軍樂事多。',64,'全唐诗/poet.tang.28000.json','["七千里別寧無恨，且貴從軍樂事多。", "不駐節旄先候發，偶逢山寺亦難過。", "蠻人獨放畬田火，海獸羣遊落日波。", "遠作受恩身不易，莫拋書劒近笙歌。"]'),
('9a844318-403b-47ed-9b46-99508519957a','宣武軍鎮作','王彥威','唐','唐诗','tang','','[]','天兵十萬勇如貔，正是酬恩報國時。',64,'全唐诗/poet.tang.28000.json','["天兵十萬勇如貔，正是酬恩報國時。", "汴水波瀾喧鼓角，隋堤楊柳拂旌旗。", "前驅紅斾關西將，坐間青娥趙國姬。", "寄語長安舊冠蓋，麤官到底是男兒。"]'),
('79685d1d-473c-4305-9b57-94f4a4c00429','春雪映早梅','庾敬休','唐','唐诗','tang','','[]','清晨凝雪彩，新候變庭梅。',72,'全唐诗/poet.tang.28000.json','["清晨凝雪彩，新候變庭梅。", "樹愛春榮徧，窗驚曙色催。", "寒光添粉壁，積潤履青苔。", "分明六出瑞，隱映幾枝開。", "聞笛花疑落，揮琴興轉來。", "曲成非寡和，長使思悠哉。"]'),
('8d765ff1-b81a-4cb2-922f-ac62ccbe280d','題雁塔','許玫','唐','唐诗','tang','','[]','寶輪金地壓人寰，獨坐蒼冥啓玉關。',64,'全唐诗/poet.tang.28000.json','["寶輪金地壓人寰，獨坐蒼冥啓玉關。", "北嶺風煙開魏闕，南軒氣象鎮商山。", "灞陵車馬垂楊裏，京國城池落照間。", "蹔放塵心游物外，六街鐘鼓又催還。"]'),
('d93cc379-539d-4ffa-84e7-a138a3372da8','從軍行','厲玄','唐','唐诗','tang','','[]','邊草旱不春，劒光增野塵。',48,'全唐诗/poet.tang.28000.json','["邊草旱不春，劒光增野塵。", "戰場收驥尾，清瀚怯龍鱗。", "帆色起歸越，松聲厭避秦。", "幾時逢范蠡，處處是通津。"]'),
('80299698-0d78-46be-9dbf-c7aed3e1ee79','寄婺州溫郎中','厲玄','唐','唐诗','tang','','[]','積雪沒蘭溪，鄰州望不迷。',48,'全唐诗/poet.tang.28000.json','["積雪沒蘭溪，鄰州望不迷。", "波中分鴈宿，樹杪接猨啼。", "婺女家空在，星郎手未攜。", "故山新寺額，掩泣荷重題。"]'),
('c242f755-286f-45f7-b4e6-6bf7c17ae6b0','送顧非熊及第歸茅山','厲玄','唐','唐诗','tang','','[]','故山登第去，不似舊歸難。',48,'全唐诗/poet.tang.28000.json','["故山登第去，不似舊歸難。", "帆卷江初夜，梅生洞少寒。", "採薇留客飲，折竹掃仙壇。", "名在儀曹籍，何人肯挂冠。"]'),
('152b6cb5-2853-4927-88c7-c87678194e00','送黃曄明府岳州湘陰赴任','厲玄','唐','唐诗','tang','','[]','恩霑譴雪幾人同，歸宰湘陰六月中。',64,'全唐诗/poet.tang.28000.json','["恩霑譴雪幾人同，歸宰湘陰六月中。", "商嶺馬嘶殘暑雨，席帆高挂早秋風。", "貢名頻向書闈失，飛檄曾傳朔漠空。", "西省尚嗟君宦遠，水雞啼處莫聽鴻。"]'),
('eebd9390-7301-434a-90c8-73e52adcbf46','緱山月夜聞王子晉吹笙','厲玄','唐','唐诗','tang','','[]','緱山明月夜，岑寂隔塵氛。',72,'全唐诗/poet.tang.28000.json','["緱山明月夜，岑寂隔塵氛。", "紫府參差曲，清宵次第聞。", "韻流多入洞，聲度半和雲。", "拂竹鸞驚侶，經松鶴對羣。", "蟾光聽處合，仙路望中分。", "坐惜千巖曙，遺香過汝墳。"]'),
('619def4c-884b-449f-9f38-51d971db4d71','和白敏中聖德和平致茲休運歲終功就合詠盛明呈上','魏扶','唐','唐诗','tang','','[]','蕭關新復舊山川，古戍秦原景象鮮。',64,'全唐诗/poet.tang.28000.json','["蕭關新復舊山川，古戍秦原景象鮮。", "戎虜乞降歸惠化，皇威漸被懾腥膻。", "穹廬遠戍煙塵滅，神武光揚竹帛傳。", "左袵盡知謌帝澤，從茲不更備三邊。"]'),
('30ed061e-91a8-4f5a-b247-aeb7e726b0d3','貢院題','魏扶','唐','唐诗','tang','','[]','梧桐葉落滿庭陰，鎖閉朱門試院深。',32,'全唐诗/poet.tang.28000.json','["梧桐葉落滿庭陰，鎖閉朱門試院深。", "曾是昔年辛苦地，不將今日負初心。"]'),
('b7f11624-e678-4947-99d6-9220cab527c7','賦愁','魏扶','唐','唐诗','tang','','[]','愁，逈野，深秋。',68,'全唐诗/poet.tang.28000.json','["愁，逈野，深秋。", "生枕上，起眉頭。", "閨閤危坐，風塵遠遊。", "巴猨啼不住，谷水咽還流。", "送客泊舟入浦，思鄉望月登樓。", "煙波早晚長羈旅，絃管終年樂五侯。"]'),
('ef0a15fb-477b-44e4-bff7-5ed47b249a39','登郡中銷暑樓寄東川汝士','楊漢公','唐','唐诗','tang','','[]','岧嶤下瞰霅溪流，極目煙波望梓州。',32,'全唐诗/poet.tang.28000.json','["岧嶤下瞰霅溪流，極目煙波望梓州。", "雖有清風當夏景，只能銷暑不銷憂。"]'),
('b429dece-1417-480a-b9f3-3c7d605df08e','明月樓','楊漢公','唐','唐诗','tang','','[]','吳興城闕水雲中，畫舫青簾處處通。',32,'全唐诗/poet.tang.28000.json','["吳興城闕水雲中，畫舫青簾處處通。", "溪上玉樓樓上月，清光合作水晶宮。"]'),
('64c55c5c-684b-4cb1-a755-64ca634b0f47','送閬州妓人歸老','何扶','唐','唐诗','tang','','[]','竹翠嬋娟草逕幽，佳人歸老傍汀洲。',64,'全唐诗/poet.tang.28000.json','["竹翠嬋娟草逕幽，佳人歸老傍汀洲。", "玉蟾露冷梁塵暗，金鳳花開雲鬢秋。", "十畝稻香新綠野，一聲歌斷舊青樓。", "芭蕉半卷西池雨，日暮門前雙白鷗。"]'),
('5b54b1f8-7f9d-4efa-8a5e-38e7666cae6e','寄舊同年','何扶','唐','唐诗','tang','','[]','金榜題名墨尚新，今年依舊去年春。',32,'全唐诗/poet.tang.28000.json','["金榜題名墨尚新，今年依舊去年春。", "花間每被紅妝問，何事重來只一人。"]'),
('3a4e6505-1883-421a-81d4-791f2fe109f4','望九華山','柴夔','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','九華如劍插雲霓，青靄連空望欲迷。',64,'全唐诗/poet.tang.28000.json','["九華如劍插雲霓，青靄連空望欲迷。", "北截吳門疑地盡，南連楚界覺天低。", "龍池水蘸中秋月，石路人攀上漢梯。", "惆悵舊游無復到，會須登此出塵泥。"]'),
('80bc7242-0faf-4e71-bd08-87dc7797434f','寄妾趙氏','房千里','唐','唐诗','tang','','[]','鸞鳳分飛海樹秋，忍聽鐘鼓越王樓。',64,'全唐诗/poet.tang.28000.json','["鸞鳳分飛海樹秋，忍聽鐘鼓越王樓。", "只應霜月明君意，緩撫瑤琴送我愁。", "山遠莫教雙淚盡，雁來空寄八行幽。", "相如若返臨邛市，畫舸朱軒萬里游。"]'),
('ad146e03-747a-4a4b-865c-97a8aff9f099','早行','劉郇伯','唐','唐诗','tang','','[]','鐘靜人猶寢，天高月自涼。',48,'全唐诗/poet.tang.28000.json','["鐘靜人猶寢，天高月自涼。", "一星深戍火，殘月半橋霜。", "客老愁塵下，蟬寒怨路傍。", "青山依舊色，宛是馬卿鄉。"]'),
('3a6f6407-5231-4002-be02-0e6301f5c3b0','句','劉郇伯','唐','唐诗','tang','','[]','人生分外愁。',6,'全唐诗/poet.tang.28000.json','["人生分外愁。"]'),
('6b394904-befe-4dd5-81b2-2ded491c6ea5','贈成都僧','李章武','唐','唐诗','tang','','[]','南宗尚許通方便，何處心中更有經？好去苾蒭雲水畔，何山松栢不青青。',32,'全唐诗/poet.tang.28000.json','["南宗尚許通方便，何處心中更有經？好去苾蒭雲水畔，何山松栢不青青。"]'),
('1a388971-8cbd-4335-b787-db4dda3a604a','享太廟樂章','蕭倣','唐','唐诗','tang','','[]','聖祚無疆，慶傳樂章。',40,'全唐诗/poet.tang.28000.json','["聖祚無疆，慶傳樂章。", "金枝繁茂，玉葉延長。", "海瀆常晏，波濤不揚。", "汪汪美化，垂範今王。"]'),
('26d2ab27-e7d2-4c53-9fb1-202bbc0138e0','享太廟樂章','蕭倣','唐','唐诗','tang','','[]','於鑠丕嗣，惟帝之光。',40,'全唐诗/poet.tang.28000.json','["於鑠丕嗣，惟帝之光。", "羽籥象德，金石薦祥。", "聖系無極，景命永昌。", "神降上哲，維天配長。"]'),
('ed41bb29-5728-4baf-a842-a124083eb671','荅楊尚書','柳棠','唐','唐诗','tang','','[]','未向燕臺逢厚禮，幸因社會接餘歡。',32,'全唐诗/poet.tang.28000.json','["未向燕臺逢厚禮，幸因社會接餘歡。", "一魚喫了終無媿，鵾化爲鵬也不難。"]'),
('1a5db9d9-af47-4083-97d7-088dd9447897','席上戲東川楊尚書','柳棠','唐','唐诗','tang','','[]','莫言名位未相儔，風月何曾阻獻酬。',32,'全唐诗/poet.tang.28000.json','["莫言名位未相儔，風月何曾阻獻酬。", "前輩不須輕後輩，靖安今日在衡州。"]'),
('d7e9facb-cdfa-45db-ad83-38f2ba42c0ad','緱山月夜聞王子晉吹笙','鍾輅','唐','唐诗','tang','','[]','月滿緱山夜，風傳子晉笙。',72,'全唐诗/poet.tang.28000.json','["月滿緱山夜，風傳子晉笙。", "初聞盈谷遠，漸聽入雲清。", "杳異人間曲，遙分鶴上情。", "孤鸞驚欲舞，萬籟寂無聲。", "此夕留煙駕，何時返玉京？", "唯愁音響絕，曉色出都城。"]'),
('cb539b2b-56bb-41a5-8e69-7f43af8d2b19','南溪書院','楊發','唐','唐诗','tang','','[]','茅屋住來久，山深不置門。',48,'全唐诗/poet.tang.28000.json','["茅屋住來久，山深不置門。", "草生垂井口，花發接籬根。", "入院將雛鳥，攀蘿抱子猨。", "曾逢異人說，風景似桃源。"]'),
('b9d22e42-8b9b-4cdf-ad2e-94da89a8ccb3','春園醉醒閑臥小齋','楊發','唐','唐诗','tang','','[]','酣醉送餘春，醒來恨更頻。',48,'全唐诗/poet.tang.28000.json','["酣醉送餘春，醒來恨更頻。", "花殘蜂蠹物，葉暗鳥欺人。", "簾閉高眠貴，齋空浩氣新。", "從今北牕蝶，長是夢中身。"]'),
('7d3748cf-ba8b-4f09-8628-b7e08f270193','小園秋興','楊發','唐','唐诗','tang','','[]','誰言帝城裏，獨作野人居。',48,'全唐诗/poet.tang.28000.json','["誰言帝城裏，獨作野人居。", "石磴晴看疊，山苗晚自鋤。", "相慚五秉粟，尚癖一車書。", "昔日揚雄宅，還無鄉相輿。"]'),
('f527aa98-54ca-4175-a89d-e0e40db27c9f','與諸公池上待月','楊發','唐','唐诗','tang','','[]','樹密雲縈岸，池遙水際空。',48,'全唐诗/poet.tang.28000.json','["樹密雲縈岸，池遙水際空。", "芰開方吐鏡，蘋動欲含風。", "漸映沙汀白，微分渚葉紅。", "金波宜共賞，仙櫂一宵同。"]'),
('285f77cd-a017-4e27-ad44-acaeaac79b37','簷雀','楊發','唐','唐诗','tang','','[]','弱羽怯孤飛，投簷幸所依。',48,'全唐诗/poet.tang.28000.json','["弱羽怯孤飛，投簷幸所依。", "銜環唯報德，賀廈本知歸。", "紅觜休爭顧，丹心自識機。", "從來攀鳳足，生死戀光輝。"]'),
('f90f18d0-a857-4401-9b0c-88c70c642db5','殘花','楊發','唐','唐诗','tang','','[]','已笑良時晚，仍悲別酒催。',48,'全唐诗/poet.tang.28000.json','["已笑良時晚，仍悲別酒催。", "暖芳隨日薄，殘片逐風迴。", "黛歛愁歌扇，妝殘泣鏡臺。", "繁陰莫矜衒，終是共塵埃。"]'),
('e3eb03db-284c-4eef-bbed-223f82a01565','山泉','楊發','唐','唐诗','tang','','[]','半空飛下水，勢去響如雷。',72,'全唐诗/poet.tang.28000.json','["半空飛下水，勢去響如雷。", "靜徹啼猨寺，高陵坐客臺。", "耳同經劒閣，身若到天台。", "濺樹吹成凍，鄰祠觸作灰。", "深中試榔栗，淺處落莓苔。", "半夜重城閉，潺湲枕底來。"]'),
('377bfc60-652a-45e0-a006-2b3429f87910','秋晚日少陵原游山泉之什','楊發','唐','唐诗','tang','','[]','喧濁侵肌性未沈，每來雲外恣幽尋。',64,'全唐诗/poet.tang.28000.json','["喧濁侵肌性未沈，每來雲外恣幽尋。", "塵衣更喜秋泉潔，倦跡方依竹洞深。", "暫過偶然應繫分，有期終去但勞心。", "唯憐一夜空山月，似許他年伴獨吟。"]'),
('5a00bd0c-8efa-4506-96d8-9a7a6cd8d64e','秋晴獨立南亭','楊發','唐','唐诗','tang','','[]','晝對南風獨閉關，暗期幽鳥去仍還。',64,'全唐诗/poet.tang.28000.json','["晝對南風獨閉關，暗期幽鳥去仍還。", "如今有待終身貴，未若忘機盡日閑。", "心似蒙莊遊物外，官慚許掾在人間。", "開襟自向清風笑，無限秋光爲解顏。"]'),
('fdefa73b-111d-4b67-ae50-343eb1acce7a','宿黃花館','楊發','唐','唐诗','tang','','[]','孤館蕭條槐葉稀，暮蟬聲隔水聲微。',64,'全唐诗/poet.tang.28000.json','["孤館蕭條槐葉稀，暮蟬聲隔水聲微。", "年年爲客路無盡，日日送人身未歸。", "何處迷鴻離浦月，誰家愁婦擣霜衣。", "夜深不臥簾猶捲，數點殘螢入戶飛。"]'),
('3858aba8-a434-4161-b876-30932cdb1de5','南野逢田客','楊發','唐','唐诗','tang','','[]','桑柘悠悠水蘸堤，晚風晴景不妨犂。',64,'全唐诗/poet.tang.28000.json','["桑柘悠悠水蘸堤，晚風晴景不妨犂。", "高機猶織臥蠶子，下坂未饑逢飼妻。", "杏色滿林羊酪熟，麥涼浮壠雉媒低。", "生時自樂死由命，萬事在天管不迷。"]'),
('fd504db7-1451-43ed-8535-3d832aeeb913','東齋夜宴酬紹之起居見贈','楊發','唐','唐诗','tang','','[]','龍門八上不知津，唯有君心困益親。',64,'全唐诗/poet.tang.28000.json','["龍門八上不知津，唯有君心困益親。", "白社追遊名自遠，青袍相映道逾新。", "十年江海魚緘盡，一夜笙歌鳳吹頻。", "漸老舊交情更重，莫將美酒負良辰。"]'),
('a3b5ae5a-7283-4968-b235-37d4115c5d03','翫殘花','楊發','唐','唐诗','tang','','[]','十日濃芳一歲程，東風初急眼偏明。',32,'全唐诗/poet.tang.28000.json','["十日濃芳一歲程，東風初急眼偏明。", "低枝似泥幽人醉，莫道無情似有情。"]'),
('3338fae3-9357-4a05-9492-bc4c75aea40e','詠蛙','楊收','唐','唐诗','tang','','[]','兔邊分玉樹，龍底耀銅儀。',24,'全唐诗/poet.tang.28000.json','["兔邊分玉樹，龍底耀銅儀。", "會當同鼓吹，不復問官私。"]'),
('fbae43f0-12bb-40f6-853c-7d682bcf6c92','筆','楊收','唐','唐诗','tang','','[]','雖匪囊中物，何堅不可鑽。',24,'全唐诗/poet.tang.28000.json','["雖匪囊中物，何堅不可鑽。", "一朝操政柄，定使冠三端。"]'),
('b1b78a63-bf5c-4a86-8496-faab8b5f77a2','嘲吳人觀者','楊收','唐','唐诗','tang','','[]','爾幸無羸角，何用觸吾藩。',24,'全唐诗/poet.tang.28000.json','["爾幸無羸角，何用觸吾藩。", "若是升堂者，還應自得門。"]'),
('795a0d30-7e33-4cb0-9c71-00640cc2630f','甲子歲書事','楊乘','唐','唐诗','tang','','[]','豎子未鼎烹，大君尚旰食。',192,'全唐诗/poet.tang.28000.json','["豎子未鼎烹，大君尚旰食。", "風雷隨出師，雲霞有戰色。", "犒功椎萬牛，募勇懸千帛。", "武士日曳柴，飛將競執馘。", "喜氣迎捷書，懽聲送羽檄。", "天兵日雄強，桀犬稍離析。", "賊臂既已斷，賊喉既已搤。", "樂禍但鯨鯢，同惡爲肘腋。", "小大勢難侔，逆順初不敵。", "違命固天亡，恃險乖長策。", "蠆毒久萌牙，狼顧非日夕。", "禮貌忽驕狂，疏奏遂指斥。", "動衆豈佳兵，含忍恐無益。", "鴻恩既已孤，小效不足惜。", "腐儒一鉛刀，投筆時感激。", "帝閽不敢干，恓恓坐長畫。"]'),
('f197988c-128c-4c5b-ba4c-12edc25ca5fb','南徐春日懷古','楊乘','唐','唐诗','tang','','[]','六代驕奢地，三春物象繁。',168,'全唐诗/poet.tang.28000.json','["六代驕奢地，三春物象繁。", "靈湖通漲海，天塹隔中原。", "曉渡高帆駛，陰風巨艦翻。", "旌旗西日落，戈甲夏雲屯。", "豹變資陳武，龍飛擁晉元。", "風流前事盡，文物舊儀存。", "邪侮嘗移潤，忠貞幾度冤。", "興亡山兀兀，今古水渾渾。", "露滴蜂偷蘂，鶯啼日到軒。", "酒腸堆麴糵，詩思遶乾坤。", "愁夢全無蝶，離憂每愧萱。", "形骸勞大塊，玉石任炎崑。", "出處寧由己，升沈未足言。", "且應中聖樂，坐起任昏昏。"]'),
('4485534f-6f1d-42fc-9e4e-5e436390a2ea','吳中書事','楊乘','唐','唐诗','tang','','[]','十萬人家天塹東，管弦臺榭滿春風。',64,'全唐诗/poet.tang.28000.json','["十萬人家天塹東，管弦臺榭滿春風。", "名歸范蠡五湖上，國破西施一笑中。", "香逕自生蘭葉小，響廊深映月華空。", "尊前多暇但懷古，盡日愁吟誰與同。"]'),
('a611f612-6aac-4551-a73b-870f183cd0f3','建鄴懷古','楊乘','唐','唐诗','tang','','[]','故城故壘滿江濆，盡是干戈舊苦辛。',32,'全唐诗/poet.tang.28000.json','["故城故壘滿江濆，盡是干戈舊苦辛。", "見此即須知帝力，生來便作太平人。"]'),
('4e3b4647-f4fb-433d-b152-262e74599ea4','牓句','楊乘','唐','唐诗','tang','','[]','伶俜乖拙兩何如，晝泥琴聲夜泥書。',32,'全唐诗/poet.tang.28000.json','["伶俜乖拙兩何如，晝泥琴聲夜泥書。", "數拍胡笳彈未熟，故人新命畫胡車。"]'),
('595aa16c-a3e3-4d0b-bc7a-3eba6dbe736b','題楊收相公宅','尹璞','唐','唐诗','tang','','[]','禍福從來路不遙，偶然平地上煙霄。',32,'全唐诗/poet.tang.28000.json','["禍福從來路不遙，偶然平地上煙霄。", "煙霄未穩還平地，門對孤峯占寂寥。"]'),
('09a4efce-fd84-4660-9ab4-ae9c502887e8','明月照高樓','雍陶','唐','唐诗','tang','','[]','朗月何高高，樓中簾影寒。',96,'全唐诗/poet.tang.28000.json','["朗月何高高，樓中簾影寒。", "一婦獨含歎，四坐誰成歡。", "時節屢已移，遊旅杳不還。", "滄溟儻未涸，妾淚終不乾。", "君若無定雲，妾若不動山。", "雲行出山易，山逐雲去難。", "願爲邊塞塵，因風委君顏。", "君顏良洗多，盪妾濁水間。"]'),
('57436bfa-b684-4645-ab8c-5e40fd4c4320','酬秘書王丞見寄','雍陶','唐','唐诗','tang','','[]','朝下有閑思，南溝邊水行。',48,'全唐诗/poet.tang.28000.json','["朝下有閑思，南溝邊水行。", "因來見寥落，轉自嘆平生。", "白首丈夫氣，赤心知己情。", "留詩本相慰，却憶苦吟聲。"]'),
('9ae12a8a-8cea-4e3a-8e07-6de76cfbb9a0','贈金河戍客','雍陶','唐','唐诗','tang','','[]','慣獵金河路，曾逢雪不迷。',48,'全唐诗/poet.tang.28000.json','["慣獵金河路，曾逢雪不迷。", "射鵰青塚北，走馬黑山西。", "戍遠旌幡少，年深帳幕低。", "酬恩須盡敵，休說夢中閨。"]'),
('05bab583-1916-4f9d-aa6c-dac73dee60ca','孤桐','雍陶','唐','唐诗','tang','','[]','疎桐餘一幹，風雨日蕭條。',48,'全唐诗/poet.tang.28000.json','["疎桐餘一幹，風雨日蕭條。", "歲晚琴材老，天寒桂葉凋。", "已悲根半死，復恐尾全焦。", "幸在龍門下，知音肯寂寥。"]'),
('1b2afcfa-9338-4f4f-b953-2c7a775654f9','秋露','雍陶','唐','唐诗','tang','','[]','白露曖秋色，月明清漏中。',48,'全唐诗/poet.tang.28000.json','["白露曖秋色，月明清漏中。", "痕沾珠箔重，點落玉盤空。", "竹動時驚鳥，莎寒暗滴蟲。", "滿園生永夜，漸欲與霜同。"]'),
('e9c4d4bc-c37f-43ac-8d77-3bd2b6ecb9cc','送徐使君赴岳州','雍陶','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','渺渺楚江上，風旗搖去舟。',48,'全唐诗/poet.tang.28000.json','["渺渺楚江上，風旗搖去舟。", "馬歸雲夢晚，猨叫洞庭秋。", "別思滿南渡，鄉心生北樓。", "巴陵山水郡，應稱謝公遊。"]'),
('d4553423-a81d-42e4-815c-3b5a43cc02b4','送裴璋還蜀因亦懷歸','雍陶','唐','唐诗','tang','','[]','客在劒門外，新年音信稀。',48,'全唐诗/poet.tang.28000.json','["客在劒門外，新年音信稀。", "自爲千里別，已送幾人歸。", "陌上月初落，馬前花正飛。", "離言殊未盡，春雨滿行衣。"]'),
('7e089b32-773a-45a3-ab40-662a8693087b','送前鄠縣李少府','雍陶','唐','唐诗','tang','','[]','近出圭峯下，還期又不賒。',48,'全唐诗/poet.tang.28000.json','["近出圭峯下，還期又不賒。", "身閑多宿寺，官滿未移家。", "罷釣臨秋水，開尊對月華。", "自當蓬閣選，豈得臥煙霞。"]'),
('f8573c60-f0b3-42b8-ab1d-f360c6b5f005','送宜春裴明府之任','雍陶','唐','唐诗','tang','','[]','南行春已滿，路半水茫然。',48,'全唐诗/poet.tang.28000.json','["南行春已滿，路半水茫然。", "楚望花當渡，湘陰橘滿川。", "山橫湖色上，帆出鳥行前。", "此任無辭遠，親人貴用還。"]'),
('e2112e9f-7bdd-463b-9509-10deee22b235','贈宗靜上人','雍陶','唐','唐诗','tang','','[]','世上方傳教，山中未得歸。',48,'全唐诗/poet.tang.28000.json','["世上方傳教，山中未得歸。", "閑花飄講席，馴鴿汙禪衣。", "積雨誰過寺，殘鐘自掩扉。", "寒來垂頂帽，白髮剃應稀。"]'),
('4dea4bdd-ba6f-4636-bfd7-08b28aee5412','同賈島宿無可上人院','雍陶','唐','唐诗','tang','','[]','何處銷愁宿，攜囊就遠僧。',48,'全唐诗/poet.tang.28000.json','["何處銷愁宿，攜囊就遠僧。", "中宵吟有雪，空屋語無燈。", "靜境唯聞鐸，寒牀但枕肱。", "還因愛閑客，始得見南能。"]'),
('5d1de8d4-9452-4b6a-a1df-0e0012a2297a','和劉補闕秋園寓興六首 一','雍陶','唐','唐诗','tang','','[]','水木夕陰冷，池塘秋意多。',48,'全唐诗/poet.tang.28000.json','["水木夕陰冷，池塘秋意多。", "庭風吹故葉，階露淨寒莎。", "愁燕窺燈語，情人見月過。", "砧聲聽已別，蟲響復相和。"]'),
('87dc5771-82a5-4eb8-b1c0-6852e81c74e5','和劉補闕秋園寓興六首 二','雍陶','唐','唐诗','tang','','[]','閉門無事後，此地即山中。',48,'全唐诗/poet.tang.28000.json','["閉門無事後，此地即山中。", "但覺鳥聲異，不知人境同。", "晚花開爲雨，殘果落因風。", "獨坐還吟酌，詩成酒已空。"]'),
('5afec976-2eda-4c13-aaf8-9fed63e551be','和劉補闕秋園寓興六首 三','雍陶','唐','唐诗','tang','','[]','自得家林趣，常時在外稀。',48,'全唐诗/poet.tang.28000.json','["自得家林趣，常時在外稀。", "對僧餐野食，迎客著山衣。", "雀鬬翻簷散，蟬驚出樹飛。", "功成他日後，何必五湖歸。"]'),
('d55ea231-d593-469f-a326-ca790f1e2385','和劉補闕秋園寓興六首 四','雍陶','唐','唐诗','tang','','[]','秋色庭蕪上，清朝見露華。',48,'全唐诗/poet.tang.28000.json','["秋色庭蕪上，清朝見露華。", "疎篁抽晚筍，幽藥吐寒芽。", "引水新渠淨，登臺小徑斜。", "人來多愛此，蕭爽似仙家。"]'),
('1bba2324-7492-4b19-b2ee-23b39efba0d7','和劉補闕秋園寓興六首 五','雍陶','唐','唐诗','tang','','[]','禁掖朝回後，林園勝賞時。',48,'全唐诗/poet.tang.28000.json','["禁掖朝回後，林園勝賞時。", "野人來辨藥，庭鶴往看棊。", "晚日明丹棗，朝霜潤紫棃。", "還因重風景，猶自有秋詩。"]'),
('64c5aa73-dfc1-4fa1-af9a-e6b0f2fefb1d','和劉補闕秋園寓興六首 六','雍陶','唐','唐诗','tang','','[]','聖代少封事，閑居方屏喧。',48,'全唐诗/poet.tang.28000.json','["聖代少封事，閑居方屏喧。", "漏寒雲外闕，木落月中園。", "山鳥宿簷樹，水螢流洞門。", "無人見清景，林下自開尊。"]'),
('4b11a699-03ff-45a1-99ed-a316198e32bb','岳陽晚景','雍陶','唐','唐诗','tang','','[]','漢陽無遠寺，見說過汾城。',48,'全唐诗/poet.tang.28000.json','["漢陽無遠寺，見說過汾城。", "雲雨經春客，江山幾日程。", "終隨鷗鳥去，祗在海潮生。", "前路逢漁父，多愁問姓名。"]'),
('06bef238-e5cb-4567-9189-181f7a5e69eb','塞上宿野寺','雍陶','唐','唐诗','tang','','[]','塞上蕃僧老，天寒疾上關。',48,'全唐诗/poet.tang.28000.json','["塞上蕃僧老，天寒疾上關。", "遠煙平似水，高樹暗如山。", "去馬朝常急，行人夜始閑。", "更深聽刁斗，時到磬聲間。"]'),
('5adaa05a-f57b-4138-b9bf-028e672bac51','寒食夜池上對月懷友','雍陶','唐','唐诗','tang','','[]','人間多別離，處處是相思。',48,'全唐诗/poet.tang.28000.json','["人間多別離，處處是相思。", "海內無煙夜，天涯有月時。", "跳魚翻荇葉，驚鵲出花枝。", "親友皆千里，三更獨遶池。"]'),
('a1539263-1eb6-45df-8982-60a437696a1f','自述','雍陶','唐','唐诗','tang','','[]','萬事誰能問，一名猶未知。',48,'全唐诗/poet.tang.28000.json','["萬事誰能問，一名猶未知。", "貧當多累日，閑過少年時。", "燈下和愁睡，花前帶酒悲。", "無謀常委命，轉覺命堪疑。"]'),
('8412179c-bd1d-48e3-aade-f826edcbffaa','送契玄上人南遊','雍陶','唐','唐诗','tang','','[]','紅葉落湘川，楓明映水天。',48,'全唐诗/poet.tang.28000.json','["紅葉落湘川，楓明映水天。", "尋鐘過楚寺，擁錫上瀧船。", "病客思留藥，迷人待說禪。", "南中多古跡，應訪虎溪泉。"]'),
('808146d5-a8f9-46d0-884d-cde93df5ae4f','少年行','雍陶','唐','唐诗','tang','','[]','不倚軍功有俠名，可憐毬獵少年情。',64,'全唐诗/poet.tang.28000.json','["不倚軍功有俠名，可憐毬獵少年情。", "戴鈴健鶻隨聲下，撼珮驕驄弄影行。", "覓匠重裝燕客劒，對人新按越姬箏。", "豈知儒者心偏苦，吟向秋風白髮生。"]'),
('93b34abe-9243-43b6-8505-2ad7af3ef323','詠雙白鷺','雍陶','唐','唐诗','tang','','[]','雙鷺應憐水滿池，風飄不動頂絲垂。',64,'全唐诗/poet.tang.28000.json','["雙鷺應憐水滿池，風飄不動頂絲垂。", "立當青草人先見，行傍白蓮魚未知。", "一足獨拳寒雨裏，數聲相叫早秋時。", "林塘得爾須增價，況與詩家物色宜。"]'),
('c6b73bba-eac6-46e0-a5f6-d0ea0fa5e936','晴詩','雍陶','唐','唐诗','tang','','[]','晚虹斜日塞天昏，一半山川帶雨痕。',64,'全唐诗/poet.tang.28000.json','["晚虹斜日塞天昏，一半山川帶雨痕。", "新水亂侵青草路，殘煙猶傍綠楊村。", "胡人羊馬休南牧，漢將旌旗在北門。", "行子喜聞無戰伐，閑看遊騎獵秋原。"]'),
('2f940e81-a45b-4f3d-8829-43c433da6ab5','送徐山人歸睦州舊隱','雍陶','唐','唐诗','tang','','[]','君在桐廬何處住，草堂應與戴家鄰。',64,'全唐诗/poet.tang.28000.json','["君在桐廬何處住，草堂應與戴家鄰。", "初歸山犬翻驚主，久別江鷗却避人。", "終日欲爲相逐計，臨岐空羨獨行身。", "秋風釣艇遙相憶，七里灘西片月新。"]'),
('b8fcdc71-3b18-424c-a250-ce19088b64ec','到蜀後記途中經歷','雍陶','唐','唐诗','tang','','[]','劒峯重疊雪雲漫，憶昨來時處處難。',64,'全唐诗/poet.tang.28000.json','["劒峯重疊雪雲漫，憶昨來時處處難。", "大散嶺頭春足雨，褒斜谷裏夏猶寒。", "蜀門去國三千里，巴路登山八十盤。", "自到成都燒酒熟，不思身更入長安。"]'),
('55543300-bb16-4e6e-b0ce-3422a17c1cea','憶山寄僧','雍陶','唐','唐诗','tang','','[]','塵路誰知蹋雪蹤，到來空認出雲峯。',64,'全唐诗/poet.tang.28000.json','["塵路誰知蹋雪蹤，到來空認出雲峯。", "天晴遠見月中樹，風便細聽煙際鐘。", "閱世數思僧並院，憶山長羨鶴歸松。", "新愁舊恨多難說，半在眉間半在胸。"]'),
('1a9ddafd-10aa-4315-83e8-d07579fe7e9f','贈玉芝觀王尊師','雍陶','唐','唐诗','tang','','[]','處處煙霞尋總遍，却來城市喜逢師。',64,'全唐诗/poet.tang.28000.json','["處處煙霞尋總遍，却來城市喜逢師。", "時流見說無人在，年紀唯應有鶴知。", "大藥已成寧畏晚，小松初種不嫌遲。", "長憂一日歸天去，未授靈方遣問誰。"]'),
('9e986045-2e4d-489b-8910-963b8c8d4c95','哭饒州吳諫議使君','雍陶','唐','唐诗','tang','','[]','忽聞身謝滿朝驚，俄感鄱陽罷市情。',64,'全唐诗/poet.tang.28000.json','["忽聞身謝滿朝驚，俄感鄱陽罷市情。", "遺愛永存今似古，高名不朽死如生。", "神仙難見青騾事，諫議空留白馬名。", "授館曾爲門下客，幾迴垂淚過宣平。"]'),
('46029df5-24e5-4990-b730-31d3940ee419','經杜甫舊宅','雍陶','唐','唐诗','tang','','[]','浣花溪裏花多處，爲憶先生在蜀時。',64,'全唐诗/poet.tang.28000.json','["浣花溪裏花多處，爲憶先生在蜀時。", "萬古只應留舊宅，千金無復換新詩。", "沙崩水檻鷗飛盡，樹壓村橋馬過遲。", "山月不知人事變，夜來江上與誰期。"]'),
('51fed55b-4e4a-4bcf-81d1-43fa4af68d20','河陰新城','雍陶','唐','唐诗','tang','','[]','高城新築壓長川，虎踞龍盤氣色全。',64,'全唐诗/poet.tang.28000.json','["高城新築壓長川，虎踞龍盤氣色全。", "五里似雲根不動，一重如月暈長圓。", "河流暗與溝池合，山色遙將睥睨連。", "自有此來當汴口，武牢何用鎖風煙。"]'),
('ce799406-a49b-4646-ae01-49120de3cc37','秋居病中','雍陶','唐','唐诗','tang','','[]','幽居悄悄何人到，落日清涼滿樹梢。',64,'全唐诗/poet.tang.28000.json','["幽居悄悄何人到，落日清涼滿樹梢。", "新句有時愁裏得，古方無效病來拋。", "荒簷數蝶懸蛛網，空屋孤螢入燕巢。", "獨臥南窗秋色晚，一庭紅葉掩衡茅。"]'),
('09da74fc-bb33-417e-b21d-54de471a641e','罷還邊將','雍陶','唐','唐诗','tang','','["\u9ec4\u6cb3"]','白鬚虜將話邊事，自失公權怨語多。',64,'全唐诗/poet.tang.28000.json','["白鬚虜將話邊事，自失公權怨語多。", "漢主豈勞思李牧，趙王猶是用廉頗。", "新鷹飽肉唯閑獵，舊劒生衣嬾更磨。", "百戰無功身老去，羨他年少渡黃河。"]'),
('997c7f3c-b416-442a-871d-1b2ed86d53c3','永樂殷堯藩明府縣池嘉蓮詠','雍陶','唐','唐诗','tang','','[]','青蘋白石匝蓮塘，水裏蓮開帶瑞光。',64,'全唐诗/poet.tang.28000.json','["青蘋白石匝蓮塘，水裏蓮開帶瑞光。", "露濕紅芳雙朵重，風飄綠蔕一枝長。", "同心梔子徒誇豔，合穗嘉禾豈解香。", "不獨豐祥先有應，更宜花縣對潘郎。"]'),
('b0a1eb79-2490-48d7-98de-1402ebc5cabd','詶李紺歲除送酒','雍陶','唐','唐诗','tang','','[]','歲盡貧生事事須，就中深恨酒錢無。',64,'全唐诗/poet.tang.28000.json','["歲盡貧生事事須，就中深恨酒錢無。", "故人充壽能分送，遠客消愁免自沽。", "一夜四乘傾鑿落，五更三點把屠蘇。", "已供時節深珍重，況許今朝更挈壺。"]'),
('3f1ebde3-7bbd-4265-802a-e31b2444e864','蜀路倦行因有所感','雍陶','唐','唐诗','tang','','[]','亂峯碎石金牛路，過客應騎鐵馬行。',64,'全唐诗/poet.tang.28000.json','["亂峯碎石金牛路，過客應騎鐵馬行。", "白日欲斜催後乘，青雲何處問前程？", "飛蠅一一皆先去，度鳥雙雙亦遠鳴。", "蹇步不唯傷旅思，此中兼見宦途情。"]'),
('9632ef0e-385e-4ec2-88ff-9f80fdd52463','寄永樂殷堯藩明府','雍陶','唐','唐诗','tang','','[]','古縣蕭條秋景晚，昔年陶令亦如君。',66,'全唐诗/poet.tang.28000.json','["古縣蕭條秋景晚，昔年陶令亦如君。", "頭巾漉酒臨黃菊，手[板]支頤向白雲。", "百里豈能容驥足，九霄終自別雞羣。", "相思不恨書來少，佳句多從闕下聞。"]'),
('06ec6a0b-4db5-4104-aa04-9fa73e229134','蜀中戰後感事','雍陶','唐','唐诗','tang','','[]','蜀道英靈地，山重水又回。',120,'全唐诗/poet.tang.28000.json','["蜀道英靈地，山重水又回。", "文章四子盛，道路五丁開。", "詞客題橋去，忠臣叱馭來。", "臥龍同駭浪，躍馬比浮埃。", "已謂無妖土，那知有禍胎。", "蕃兵依𣾴柳，蠻斾指江梅。", "戰後悲逢血，燒餘恨見灰。", "空留犀厭怪，無復酒除災。", "歲積萇弘怨，春深杜宇哀。", "家貧移未得，愁上望鄉臺。"]'),
('32e5bd2d-a284-40d9-8560-c7ea7235c0f5','荅蜀中經蠻後友人馬艾見寄','雍陶','唐','唐诗','tang','','[]','茜馬渡瀘水，北來如鳥輕。',72,'全唐诗/poet.tang.28000.json','["茜馬渡瀘水，北來如鳥輕。", "幾年朝鳳闕，一日破龜城。", "此地有征戰，誰家無死生。", "人悲還舊里，鳥喜下空營。", "弟姪意初定，交朋心尚驚。", "自從經難後，吟苦似猿聲。"]'),
('c6628482-6536-4067-90c5-d1b02cb347be','盧岳閑居十韻','雍陶','唐','唐诗','tang','','[]','擾擾走人寰，爭如占得閑。',120,'全唐诗/poet.tang.28000.json','["擾擾走人寰，爭如占得閑。", "防愁心付酒，求靜力登山。", "見藥芳時採，逢花好處攀。", "望雲開病眼，臨澗洗愁顏。", "春色流巖下，秋聲碎竹間。", "錦文苔點點，錢樣菊斑斑。", "路遠朝無客，門深夜不關。", "鶴飛高縹緲，鶯語巧綿蠻。", "養拙甘沈默，忘懷絕險艱。", "更憐雲外路，空去又空還。"]'),
('773f76c6-5be9-4050-9723-2b89bdae4e33','送于中丞使北蕃','雍陶','唐','唐诗','tang','','[]','朔將引雙旌，山遙磧雪平。',72,'全唐诗/poet.tang.28000.json','["朔將引雙旌，山遙磧雪平。", "經年通國信，計日得蕃情。", "野次依泉宿，沙中望火行。", "遠鵰秋有力，寒馬夜無聲。", "看獵臨胡帳，思鄉見漢城。", "來春擁邊騎，新草滿歸程。"]'),
('47bbf9de-0bca-45be-b958-fbddeeb7512a','和河南白尹西池北新葺水齋招賞十二韻','雍陶','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','二室峯前水，三川府右亭。',144,'全唐诗/poet.tang.28000.json','["二室峯前水，三川府右亭。", "亂流深竹逕，分遶小花汀。", "池角通泉脈，堂心豁地形。", "坐中寒瑟瑟，牀下細泠泠。", "雨夜思巫峽，秋朝想洞庭。", "千年孤鏡碧，一片遠天青。", "魚戲搖紅尾，鷗閑退白翎。", "荷傾瀉珠露，沙亂動金星。", "藤架如紗帳，苔牆似錦屏。", "龍門人少到，仙棹自多停。", "游憶高僧伴，吟招野客聽。", "餘波不能惜，便欲養浮萍。"]'),
('a66f7be8-b89b-472f-956c-31efd573429f','感興','雍陶','唐','唐诗','tang','','[]','貧女貌非醜，要須緣嫁遲。',24,'全唐诗/poet.tang.28000.json','["貧女貌非醜，要須緣嫁遲。", "還似求名客，無媒不及時。"]'),
('d1863ef7-4329-4565-90f8-ec88d7c7ec50','長安客感','雍陶','唐','唐诗','tang','','[]','日過千萬家，一家非所依。',24,'全唐诗/poet.tang.28000.json','["日過千萬家，一家非所依。", "不及行塵影，猶隨馬蹄歸。"]'),
('df3dcbc5-cbdc-4c41-863f-9854a0f1779f','春懷舊游','雍陶','唐','唐诗','tang','','[]','吟想舊經過，花時奈遠何。',24,'全唐诗/poet.tang.28000.json','["吟想舊經過，花時奈遠何。", "別來長似見，春夢入關多。"]'),
('8f4a339e-b4f4-472a-9355-28e1d409cb48','離京城宿商山作','雍陶','唐','唐诗','tang','','[]','山月吟聲苦，春風引思長。',24,'全唐诗/poet.tang.28000.json','["山月吟聲苦，春風引思長。", "無由及塵土，猶帶杏花香。"]'),
('82752dc9-5dc8-4e2f-8a47-871d1d9afca9','秋館雨夜','雍陶','唐','唐诗','tang','','[]','夜雨空館靜，幽人起裴回。',24,'全唐诗/poet.tang.28000.json','["夜雨空館靜，幽人起裴回。", "長安醉眠客，豈知新鴈來。"]'),
('9736cffd-e84d-432c-a95a-0fcd7aff143c','聞子規','雍陶','唐','唐诗','tang','','[]','百鳥有啼時，子規聲不歇。',24,'全唐诗/poet.tang.28000.json','["百鳥有啼時，子規聲不歇。", "春寒四鄰靜，獨叫三更月。"]'),
('d1a5b5ca-86c5-4188-b596-b8470e9a3588','懷無可上人','雍陶','唐','唐诗','tang','','[]','山寺秋時後，僧家夏滿時。',24,'全唐诗/poet.tang.28000.json','["山寺秋時後，僧家夏滿時。", "清涼多古跡，幾處有新詩。"]'),
('0275485d-b5e1-4e1d-9c89-4e0800d3b433','長安客感','雍陶','唐','唐诗','tang','','[]','客淚如危葉，長懸零落心。',24,'全唐诗/poet.tang.28000.json','["客淚如危葉，長懸零落心。", "況是悲秋日，臨風制不禁。"]'),
('ace8d2e7-ac57-4e08-b5ca-058ee2a393a8','送客遙望','雍陶','唐','唐诗','tang','','[]','別遠心更苦，遙將目送君。',24,'全唐诗/poet.tang.28000.json','["別遠心更苦，遙將目送君。", "光華不可見，孤鶴沒秋雲。"]'),
('7f6dab81-59e0-4f1a-96e9-6e7fbd0e8979','傷靡草','雍陶','唐','唐诗','tang','','[]','靡草似客心，年年亦先死。',24,'全唐诗/poet.tang.28000.json','["靡草似客心，年年亦先死。", "無由伴花落，暫得因風起。"]'),
('0f5853c3-c168-48aa-8761-33d1ecae62bc','放鶴','雍陶','唐','唐诗','tang','','[]','從今一去不須低，見說遼東好去棲。',32,'全唐诗/poet.tang.28000.json','["從今一去不須低，見說遼東好去棲。", "努力莫辭仙路遠，白雲飛處免羣雞。"]'),
('68c2d980-05a9-4967-865a-10b02cfe0966','早秋月夜','雍陶','唐','唐诗','tang','','[]','身閑伴月夜深行，風觸衣裳四體輕。',32,'全唐诗/poet.tang.28000.json','["身閑伴月夜深行，風觸衣裳四體輕。", "爲見近來天氣好，幾篇詩興入秋成。"]'),
('d5281616-fd34-4fff-b9a7-3ae56e73c5b8','蟬','雍陶','唐','唐诗','tang','','[]','高樹蟬聲入晚雲，不唯愁我亦愁君。',32,'全唐诗/poet.tang.28000.json','["高樹蟬聲入晚雲，不唯愁我亦愁君。", "何時各得身無事，每到聞時似不聞。"]'),
('6d199dc3-5e23-4ea2-8fd5-b941bbeaef41','公子行','雍陶','唐','唐诗','tang','','[]','公子風流嫌錦繡，新裁白紵作春衣。',32,'全唐诗/poet.tang.28000.json','["公子風流嫌錦繡，新裁白紵作春衣。", "金鞭留當誰家酒，拂柳穿花信馬歸。"]'),
('3b3ba1a2-fa7f-4867-995a-e716a4ec58b4','題情盡橋','雍陶','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b"]','從來只有情難盡，何事名爲情盡橋。',32,'全唐诗/poet.tang.28000.json','["從來只有情難盡，何事名爲情盡橋。", "自此改名爲折柳，任他離恨一條條。"]'),
('0b01efbd-02ec-4187-8db6-00011c47b9a6','峽中行','雍陶','唐','唐诗','tang','','[]','兩崖開盡水回環，一葉纔通石罅間。',32,'全唐诗/poet.tang.28000.json','["兩崖開盡水回環，一葉纔通石罅間。", "楚客莫言山勢險，世人心更險於山。"]'),
('a13ddfc2-a8d9-4b2f-b3c7-9f4522f69f6f','韋處士郊居','雍陶','唐','唐诗','tang','','["\u79cb\u5929", "\u5b64\u5bc2", "\u5199\u666f"]','滿庭詩境飄紅葉，繞砌琴聲滴暗泉。',32,'全唐诗/poet.tang.28000.json','["滿庭詩境飄紅葉，繞砌琴聲滴暗泉。", "門外晚晴秋色老，萬條寒玉一溪煙。"]'),
('c604c137-7a45-4a46-935a-de348a28cc1a','秋懷','雍陶','唐','唐诗','tang','','[]','古槐煙薄晚鴉愁，獨向黃昏立御溝。',32,'全唐诗/poet.tang.28000.json','["古槐煙薄晚鴉愁，獨向黃昏立御溝。", "南國望中生遠思，一行新鴈去汀洲。"]'),
('185b0401-991c-49e1-8230-c79729846aea','再下第將歸荆楚上白舍人','雍陶','唐','唐诗','tang','','[]','窮通應計一時間，今日甘從刖足還。',32,'全唐诗/poet.tang.28000.json','["窮通應計一時間，今日甘從刖足還。", "長倚玉人心自醉，不辭歸去哭荆山。"]'),
('454cc153-21c1-4f60-a4a0-20206159ed59','春行武關作','雍陶','唐','唐诗','tang','','[]','風香春暖展歸程，全勝遊仙入洞情。',32,'全唐诗/poet.tang.28000.json','["風香春暖展歸程，全勝遊仙入洞情。", "一路緣溪花覆水，不妨閑看不妨行。"]'),
('271a28b6-c938-4d63-820c-3cc9823b185d','恨別二首 一','雍陶','唐','唐诗','tang','','[]','知君餞酒深深意，圖使行人涕不流。',32,'全唐诗/poet.tang.28000.json','["知君餞酒深深意，圖使行人涕不流。", "如今卻恨酒中別，不得一言千里愁。"]'),
('5fef4bf7-fe52-4e72-a735-28f9450b009e','恨別二首 二','雍陶','唐','唐诗','tang','','[]','人言日遠還疎索，別後都非未別心。',32,'全唐诗/poet.tang.28000.json','["人言日遠還疎索，別後都非未別心。", "唯我憶君千里意，一年不見一重深。"]'),
('d0e6bb57-7c66-4b07-a870-b8480c5fc134','送人歸吳','雍陶','唐','唐诗','tang','','[]','遠愛春波正滿湖，羨君東去是歸途。',32,'全唐诗/poet.tang.28000.json','["遠愛春波正滿湖，羨君東去是歸途。", "吟詩好向月中宿，一叫水天沙鶴孤。"]'),
('23d71422-51f5-4102-aa3f-ac5f699a2ffb','喜夢歸','雍陶','唐','唐诗','tang','','[]','旅館歲闌頻有夢，分明最似此宵希。',32,'全唐诗/poet.tang.28000.json','["旅館歲闌頻有夢，分明最似此宵希。", "覺來莫道還無益，未得歸時且當歸。"]'),
('fda0464b-d28c-4b55-b83c-c8d385a2753e','路中問程知欲達青雲驛','雍陶','唐','唐诗','tang','','[]','行愁驛路問來人，西去經過願一聞。',32,'全唐诗/poet.tang.28000.json','["行愁驛路問來人，西去經過願一聞。", "落日回鞭相指點，前程從此是青雲。"]'),
('2f5e562a-ff78-42e3-8c1b-d9b3686907c5','題君山','雍陶','唐','唐诗','tang','','[]','風波不動影沈沈，翠色全微碧色深。',32,'全唐诗/poet.tang.28000.json','["風波不動影沈沈，翠色全微碧色深。", "應是水仙梳洗處，一螺青黛鏡中心。"]'),
('fcdb22e2-d567-4001-a280-e36d5af8b18f','離家後作','雍陶','唐','唐诗','tang','','[]','世上無媒似我希，一身惟有影相隨。',32,'全唐诗/poet.tang.28000.json','["世上無媒似我希，一身惟有影相隨。", "出門便作焚舟計，生不成名死不歸。"]'),
('9bc24bea-e491-4ef4-9037-ebfb1d5ae116','寄題峴亭','雍陶','唐','唐诗','tang','','[]','峴亭留恨爲傷杯，未得醒醒看便回。',32,'全唐诗/poet.tang.28000.json','["峴亭留恨爲傷杯，未得醒醒看便回。", "卻想醉游如夢見，直疑元本不曾來。"]'),
