('79d47a97-af2c-442d-89bc-8e7b1dff540a','渡桑乾河','雍陶','唐','唐诗','tang','','[]','南客豈曾諳塞北，年年唯見鴈飛回。',32,'全唐诗/poet.tang.28000.json','["南客豈曾諳塞北，年年唯見鴈飛回。", "今朝忽渡桑乾水，不似身來似夢來。"]'),
('9b304eac-7b7a-47c0-8d3c-b7cbfcf6df72','月下喜呂郎中除兵部','雍陶','唐','唐诗','tang','','[]','北闕雲間見碧天，南宮月似舊時圓。',32,'全唐诗/poet.tang.28000.json','["北闕雲間見碧天，南宮月似舊時圓。", "喜看列宿今朝正，休嘆參差十四年。"]'),
('bdf2ae96-0962-451e-a120-f3bbcd1fd167','天津橋望春','雍陶','唐','唐诗','tang','','["\u540a\u53e4\u4f24\u4eca", "\u6625\u5929"]','津橋春水浸紅霞，煙柳風絲拂岸斜。',32,'全唐诗/poet.tang.28000.json','["津橋春水浸紅霞，煙柳風絲拂岸斜。", "翠輦不來金殿閉，宮鶯銜出上陽花。"]'),
('de6c8f6f-65e7-47ee-a66c-3361196ad584','自蔚州南入真谷有似劒門因有歸思','雍陶','唐','唐诗','tang','','[]','我家蜀地身離久，忽見胡山似劒門。',32,'全唐诗/poet.tang.28000.json','["我家蜀地身離久，忽見胡山似劒門。", "馬上欲垂千里淚，耳邊唯欠一聲猨。"]'),
('40a9c093-74d2-48c0-b1e5-5f45cead2cd2','再經天涯地角山','雍陶','唐','唐诗','tang','','[]','每憶雲山養短才，悔緣名利入塵埃。',32,'全唐诗/poet.tang.28000.json','["每憶雲山養短才，悔緣名利入塵埃。", "十年馬足行多少，兩度天涯地角來。"]'),
('8a663f45-4944-41ee-bf77-19c6f27559b1','題等界寺二首 一','雍陶','唐','唐诗','tang','','[]','吳蜀千年等界村，英雄無主豈長存。',32,'全唐诗/poet.tang.28000.json','["吳蜀千年等界村，英雄無主豈長存。", "思量往事今何在，萬里山中一寺門。"]'),
('aec396fc-9374-40ef-9ffb-3ff7f69f385f','題等界寺二首 二','雍陶','唐','唐诗','tang','','[]','兩國道塗都萬里，來從此地等平分。',32,'全唐诗/poet.tang.28000.json','["兩國道塗都萬里，來從此地等平分。", "行人競說東西利，事不關心耳不聞。"]'),
('e34568b3-9eb2-4c23-ab6a-597e931868f3','洛源驛戲題','雍陶','唐','唐诗','tang','','[]','柳陰春嶺鳥新啼，暖色濃煙深處迷。',32,'全唐诗/poet.tang.28000.json','["柳陰春嶺鳥新啼，暖色濃煙深處迷。", "如恨往來人不見，水聲呦咽出花溪。"]'),
('11c120bd-370e-4fae-b220-783ca371bf66','遣愁','雍陶','唐','唐诗','tang','','[]','拋擲泥中一聽沈，不能三嘆引愁深。',32,'全唐诗/poet.tang.28000.json','["拋擲泥中一聽沈，不能三嘆引愁深。", "莫言客子無愁易，須識愁多暗損心。"]'),
('7c844c80-fb5d-4cfe-9615-d40e4f1c62cf','送友人棄官歸山居','雍陶','唐','唐诗','tang','','[]','不愛人間紫與緋，卻思松下著山衣。',32,'全唐诗/poet.tang.28000.json','["不愛人間紫與緋，卻思松下著山衣。", "春郊雨盡多新草，一路青青蹋雨歸。"]'),
('d2e9c93d-d2ba-4e1a-ae7f-1f845f6f9ded','山行','雍陶','唐','唐诗','tang','','[]','野花幽鳥幾千般，頭白山僧遍識難。',32,'全唐诗/poet.tang.28000.json','["野花幽鳥幾千般，頭白山僧遍識難。", "世上遊人無復見，一生唯向畫圖看。"]'),
('baac4c63-098b-4e93-aaa0-5e39282f60a2','送客二首 一','雍陶','唐','唐诗','tang','','[]','與君同在少年場，知己蕭條壯士傷。',32,'全唐诗/poet.tang.28000.json','["與君同在少年場，知己蕭條壯士傷。", "可惜報恩無處所，卻提孤劒過咸陽。"]'),
('888e10c7-e8e1-4e6c-bbc0-4831d58b2c16','送客二首 二','雍陶','唐','唐诗','tang','','[]','行人立馬強盤回，別字猶含未忍開。',32,'全唐诗/poet.tang.28000.json','["行人立馬強盤回，別字猶含未忍開。", "好去出門休落淚，不如前路早歸來。"]'),
('f9bff660-8bbe-4855-9cfe-31e1f46c7c2a','安國寺贈廣宣上人','雍陶','唐','唐诗','tang','','[]','馬急人忙塵路喧，幾從朝出到黃昏。',32,'全唐诗/poet.tang.28000.json','["馬急人忙塵路喧，幾從朝出到黃昏。", "今來合掌聽師語，一似敲冰清耳根。"]'),
('7aaa720b-10fe-446a-921c-781f96bacd36','初醒','雍陶','唐','唐诗','tang','','[]','心中得勝暫拋愁，醉臥涼風拂簟秋。',32,'全唐诗/poet.tang.28000.json','["心中得勝暫拋愁，醉臥涼風拂簟秋。", "半夜覺來新酒醒，一條斜月到牀頭。"]'),
('524d846c-9251-439c-931c-96a586db7016','送客歸襄陽舊居','雍陶','唐','唐诗','tang','','[]','襄陽耆舊別來稀，此去何人共掩扉。',32,'全唐诗/poet.tang.28000.json','["襄陽耆舊別來稀，此去何人共掩扉。", "唯有白銅鞮上月，水樓閑處待君歸。"]'),
('3de8ca41-7c50-42e9-a3cd-09d8a8e02dca','夜聞方響','雍陶','唐','唐诗','tang','','[]','方響聞時夜已深，聲聲敲著客愁心。',32,'全唐诗/poet.tang.28000.json','["方響聞時夜已深，聲聲敲著客愁心。", "不知正在誰家樂，月下猶疑是遠砧。"]'),
('a3e407cb-e48b-4bb0-9a05-8a7e25ff6382','路逢有似亡友者惻然賦此','雍陶','唐','唐诗','tang','','[]','吾友今生不可逢，風流空想舊儀容。',32,'全唐诗/poet.tang.28000.json','["吾友今生不可逢，風流空想舊儀容。", "朝來馬上頻回首，惆悵他人似蔡邕。"]'),
('faf0ba7b-e32d-4f9c-893a-e008d9e2c213','望月懷江上舊遊','雍陶','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','往歲曾隨江客船，秋風明月洞庭邊。',32,'全唐诗/poet.tang.28000.json','["往歲曾隨江客船，秋風明月洞庭邊。", "爲看今夜天如水，憶得當時水似天。"]'),
('268d8c2d-b2fc-4f84-9922-ca18d6e8248b','途中西望','雍陶','唐','唐诗','tang','','[]','行行何處散離愁，長路無因暫上樓。',32,'全唐诗/poet.tang.28000.json','["行行何處散離愁，長路無因暫上樓。", "唯到高原即西望，馬知人意亦回頭。"]'),
('4b5e1e84-ae60-48d2-a122-715654cee265','題友人所居','雍陶','唐','唐诗','tang','','[]','亞尹故居經幾主，只因君住有詩情。',32,'全唐诗/poet.tang.28000.json','["亞尹故居經幾主，只因君住有詩情。", "夜吟鄰叟聞惆悵，七八年來無此聲。"]'),
('66047bcf-84cd-431f-a29f-355e6a6e3d78','蔚州晏內遇新雪','雍陶','唐','唐诗','tang','','[]','胡盧河畔逢秋雪，疑是風飄白鶴毛。',32,'全唐诗/poet.tang.28000.json','["胡盧河畔逢秋雪，疑是風飄白鶴毛。", "坐客停杯看未定，將軍已濕褐花袍。"]'),
('b3551a13-c26e-4099-a455-70bb9c0cc0a3','蔚州晏內遇新雪 句','雍陶','唐','唐诗','tang','','[]','古木閩州道，驅羸落照間。',24,'全唐诗/poet.tang.28000.json','["古木閩州道，驅羸落照間。", "投村礙野水，問店隔荒山。"]'),
('e48200a3-357b-43fd-8dd0-a8432e7b647c','立春日','李遠','唐','唐诗','tang','','[]','暖日傍簾曉，濃春開篋紅。',48,'全唐诗/poet.tang.28000.json','["暖日傍簾曉，濃春開篋紅。", "釵斜穿綵燕，羅薄翦春蟲。", "巧著金刀力，寒侵玉指風。", "娉婷何處戴，山鬢綠成藂。"]'),
('4ed4857e-0b00-433c-aefd-24df862b57ae','翦綵','李遠','唐','唐诗','tang','','[]','翦綵贈相親，銀釵綴鳳真。',48,'全唐诗/poet.tang.28000.json','["翦綵贈相親，銀釵綴鳳真。", "雙雙銜綬鳥，兩兩度橋人。", "葉逐金刀出，花隨玉指新。", "願君千萬歲，無歲不逢春。"]'),
('f7133973-6d0b-4bee-b6de-9bcfd0f67969','題僧院','李遠','唐','唐诗','tang','','[]','不用問湯休，何人免白頭。',48,'全唐诗/poet.tang.28000.json','["不用問湯休，何人免白頭。", "百年如過鳥，萬事盡浮漚。", "別緒長牽夢，情由亂種愁。", "却嫌風景麗，窗外碧雲秋。"]'),
('55905a23-5d50-4ca0-932e-c990214f12df','觀廉女真葬','李遠','唐','唐诗','tang','','[]','玉窗拋翠管，輕袖掩銀鸞。',48,'全唐诗/poet.tang.28000.json','["玉窗拋翠管，輕袖掩銀鸞。", "錯落雲車斷，丁泠金磬寒。", "鶴尋深院宿，人借舊書看。", "寂寞焚香處，紅花滿石壇。"]'),
('870b4a7a-aec4-4c48-b1e6-715b7ca6a5e6','閑居','李遠','唐','唐诗','tang','','[]','塵事久相棄，沈浮皆不知。',48,'全唐诗/poet.tang.28000.json','["塵事久相棄，沈浮皆不知。", "牛羊歸古巷，燕雀遶疎籬。", "買藥經年曬，留僧盡日棊。", "唯憂釣魚伴，秋水隔波時。"]'),
('6c582b40-4bb7-4f52-892b-e76a872845c0','及第後送家兄遊蜀','李遠','唐','唐诗','tang','','[]','人誰無遠別，此別意多違。',48,'全唐诗/poet.tang.28000.json','["人誰無遠別，此別意多違。", "正鵠雖言中，冥鴻不共飛。", "玉京煙雨斷，巴國夢魂歸。", "若過嚴家瀨，慇懃看釣磯。"]'),
('57de2aec-4d31-4870-b93e-07531830ae29','送人入蜀','李遠','唐','唐诗','tang','','[]','蜀客本多愁，君今是勝遊。',36,'全唐诗/poet.tang.28000.json','["蜀客本多愁，君今是勝遊。", "碧藏雲外樹，紅露驛邊樓。", "杜魄呼名語，巴江作字流。"]'),
('dafb0652-6b76-4b05-be12-1c6f10d12ae8','遊故王駙馬池亭','李遠','唐','唐诗','tang','','[]','花樹杳玲瓏，漁舟處處通。',48,'全唐诗/poet.tang.28000.json','["花樹杳玲瓏，漁舟處處通。", "醉銷羅綺豔，香暖芰荷風。", "野鳥翻萍綠，斜橋印水紅。", "子猷簫管絕，誰愛碧鮮濃。"]'),
('165060cb-4603-4748-809d-aaa12fe3550e','悲銅雀臺','李遠','唐','唐诗','tang','','[]','西陵樹已盡，銅雀思偏多。',48,'全唐诗/poet.tang.28000.json','["西陵樹已盡，銅雀思偏多。", "雪密疑樓閣，花開想綺羅。", "影銷堂上舞，聲斷帳前歌。", "唯有漳河水，年年舊綠波。"]'),
('c0329a85-c983-495e-ab69-0ac4fb2f4fe7','陪新及第赴同年會','李遠','唐','唐诗','tang','','[]','曾攀芳桂英，處處共君行。',48,'全唐诗/poet.tang.28000.json','["曾攀芳桂英，處處共君行。", "今日杏園宴，當時天樂聲。", "柳濃堪繫馬，花上未藏鶯。", "滿座皆仙侶，同年別有情。"]'),
('85125048-bcdd-4cd7-ad88-ddde4a980bdd','詠鴈','李遠','唐','唐诗','tang','','["\u5199\u9e1f", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u9e1f"]','早晚辭沙漠，南來處處飛。',48,'全唐诗/poet.tang.28000.json','["早晚辭沙漠，南來處處飛。", "關山多雨雪，風水損毛衣。", "碧海魂應斷，紅樓信自稀。", "不知矰繳外，留得幾行歸。"]'),
('118acfbc-537b-43cc-bb31-9684c4168376','與碧溪上人別','李遠','唐','唐诗','tang','','[]','欲入鳳城遊，西溪別惠休。',48,'全唐诗/poet.tang.28000.json','["欲入鳳城遊，西溪別惠休。", "色隨花旋落，年共水爭流。", "客思偏來夜，蟬聲覺送秋。", "明朝逢舊侶，唯擬上歌樓。"]'),
('ab057de0-336c-480e-9e2d-6c46808b2755','贈殷山人','李遠','唐','唐诗','tang','','[]','有客抱琴宿，值予多怨懷。',48,'全唐诗/poet.tang.28000.json','["有客抱琴宿，值予多怨懷。", "啼烏弦易斷，嘯鶴調難諧。", "曲罷月移幌，韻清風滿齋。", "誰能將此妙，一爲奏金堦。"]'),
('1a215e20-5cce-4a5e-aa7a-634730d432bc','詠壁魚','李遠','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u5199\u9c7c", "\u548f\u7269"]','鱗細粉光鮮，開書亂眼前。',48,'全唐诗/poet.tang.28000.json','["鱗細粉光鮮，開書亂眼前。", "透窗疑漏網，落硯似流泉。", "潛穴河圖內，吞鉤乙字邊。", "莫言鬐鬣小，食盡白蘋篇。"]'),
('c9c5a2a2-6e6c-44fe-bb5c-32c616b21df1','聽話叢臺','李遠','唐','唐诗','tang','','[]','有客新從趙地回，自言曾上古叢臺。',64,'全唐诗/poet.tang.28000.json','["有客新從趙地回，自言曾上古叢臺。", "雲遮襄國天邊去，樹繞漳河地裏來。", "弦管變成山鳥哢，綺羅留作野花開。", "金輿玉輦無行跡，風雨惟知長綠苔。"]'),
('8de1ab43-e5cf-456f-852a-4f33e63c9a21','失鶴','李遠','唐','唐诗','tang','','[]','秋風吹却九臯禽，一片閑雲萬里心。',64,'全唐诗/poet.tang.28000.json','["秋風吹却九臯禽，一片閑雲萬里心。", "碧落有情應悵望，青天無路可追尋。", "來時白雪翎猶短，去日丹砂頂漸深。", "華表柱頭留語後，更無消息到如今。"]'),
('3e2cec01-d9df-4f66-a946-cdd1abb6607a','贈寫御容李長史','李遠','唐','唐诗','tang','','[]','玉座塵消硯水清，龍髯不動綵毫輕。',64,'全唐诗/poet.tang.28000.json','["玉座塵消硯水清，龍髯不動綵毫輕。", "初分隆準山河秀，乍點重瞳日月明。", "宮女捲簾皆暗認，侍臣開殿盡遙驚。", "三朝供奉無人敵，始覺僧繇浪得名。"]'),
('e3f436df-bca0-4f92-9c6a-ea5f8f158e3b','贈潼關不下山僧','李遠','唐','唐诗','tang','','[]','與君同在苦空間，君得空門我愛閑。',64,'全唐诗/poet.tang.28000.json','["與君同在苦空間，君得空門我愛閑。", "禁足已教修鴈塔，終身不擬下雞山。", "窗中遙指三千界，枕上斜看百二關。", "香茗一甌從此別，轉蓬流水幾時還。"]'),
('e956efde-6ec2-4761-aef6-fc04fcb1081d','過舊遊見雙鶴愴然有懷','李遠','唐','唐诗','tang','','[]','謝公何歲掩松楸，雙鶴依然傍玉樓。',64,'全唐诗/poet.tang.28000.json','["謝公何歲掩松楸，雙鶴依然傍玉樓。", "朱頂巑岏荒草上，雪毛零落小池頭。", "蓬瀛路斷君何在，雲水情深我尚留。", "他日若來華表上，更添多少令威愁。"]'),
('994dadf1-6e44-4c8c-be17-0842dece1c77','贈友人','李遠','唐','唐诗','tang','','[]','鳳城煙靄思偏多，曾向劉郎住處過。',64,'全唐诗/poet.tang.28000.json','["鳳城煙靄思偏多，曾向劉郎住處過。", "銀燭焰前貪勸酒，玉簫聲裏已聞歌。", "佳人惜別看嘶馬，公子含情向翠蛾。", "今日重來門巷改，出牆桐樹綠婆娑。"]'),
('fb853ae0-19b8-4653-94e9-a5a7f5d3777c','贈南嶽僧','李遠','唐','唐诗','tang','','["\u8861\u5c71"]','曾住衡陽嶽寺邊，門開江水與雲連。',64,'全唐诗/poet.tang.28000.json','["曾住衡陽嶽寺邊，門開江水與雲連。", "數州城郭藏寒樹，一片風帆著遠天。", "猨嘯不離行道處，客來皆到臥牀前。", "今朝惆悵紅塵裏，惟憶閑陪盡日眠。"]'),
('1ddbf022-4355-4f60-bade-2947377653f1','贈弘文杜校書','李遠','唐','唐诗','tang','','[]','高倚霞梯萬丈餘，共看移步入宸居。',64,'全唐诗/poet.tang.28000.json','["高倚霞梯萬丈餘，共看移步入宸居。", "曉隨鵷鷺排金鎖，靜對鉛黃校玉書。", "漠漠禁煙籠遠樹，泠泠宮漏響前除。", "還聞漢帝親詞賦，好爲從容奏子虛。"]'),
('4fd24ce0-d0b8-4214-bbf7-e9c5c0b24601','聽王氏話歸州昭君廟','李遠','唐','唐诗','tang','','[]','獻之閑坐說歸州，曾到昭君廟裏遊。',64,'全唐诗/poet.tang.28000.json','["獻之閑坐說歸州，曾到昭君廟裏遊。", "自古行人多怨恨，至今鄉土盡風流。", "泉如珠淚侵階滴，花似紅妝滿岸愁。", "河畔猶殘翠眉樣，有時新月傍簾鉤。"]'),
('250b668c-c0c3-4be6-be3b-bf94f7b20b7a','過馬嵬山','李遠','唐','唐诗','tang','','[]','金甲雲旗盡日迴，倉皇羅袖滿塵埃。',64,'全唐诗/poet.tang.28000.json','["金甲雲旗盡日迴，倉皇羅袖滿塵埃。", "濃香猶自飄鑾輅，恨魄無因離馬嵬。", "南內宮人悲帳殿，東溟方士問蓬萊。", "唯餘坡上彎環月，時送殘蛾入帝臺。"]'),
('b9f767bb-d3e5-4ab7-8080-680f2dcfcb64','吳越懷古','李遠','唐','唐诗','tang','','[]','吳越千年奈怨何，兩宮清吹作樵歌。',64,'全唐诗/poet.tang.28000.json','["吳越千年奈怨何，兩宮清吹作樵歌。", "姑蘇一敗雲無色，范蠡長遊水自波。", "霞拂故城疑轉斾，月依荒樹想嚬蛾。", "行人欲問西施館，江鳥寒飛碧草多。"]'),
('d56cec1d-da48-43e6-9442-6bdbdf696077','長安即事寄友人','李遠','唐','唐诗','tang','','[]','綺陌千年思斷蓬，今來還宿鳳城東。',64,'全唐诗/poet.tang.28000.json','["綺陌千年思斷蓬，今來還宿鳳城東。", "瑤臺鐘鼓長依舊，巫峽煙花自不同。", "千結故心爲怨網，萬條新景作愁籠。", "何時更伴劉郎去，却見夭桃滿樹紅。"]'),
('842e4ae4-920c-49a6-b89e-bc77b7d29c9b','聞明上人逝寄友人','李遠','唐','唐诗','tang','','[]','蕭寺曾過最上方，碧桐濃葉覆西廊。',64,'全唐诗/poet.tang.28000.json','["蕭寺曾過最上方，碧桐濃葉覆西廊。", "遊人縹緲紅衣亂，座客從容白日長。", "別後旋成莊叟夢，書來忽報惠休亡。", "他時若更相隨去，祗是含酸對影堂。"]'),
('d236a8fc-2a32-4025-bbd3-076adddd7754','贈咸陽李少府','李遠','唐','唐诗','tang','','[]','美貌雄才已少齊，寶書仙簡兩看題。',64,'全唐诗/poet.tang.28000.json','["美貌雄才已少齊，寶書仙簡兩看題。", "金刀片片裁新錦，玉步重重上舊梯。", "鵬到碧天排霧去，鳳遊瓊樹揀枝棲。", "蓬瀛宴罷試迴首，一望塵中路正迷。"]'),
('eb0d112a-4d21-451d-898c-5feecb52d6bf','隣人自金仙觀移竹','李遠','唐','唐诗','tang','','[]','移居新竹已堪看，斸破莓苔得幾竿。',64,'全唐诗/poet.tang.28000.json','["移居新竹已堪看，斸破莓苔得幾竿。", "圓節不教傷粉籜，低枝猶擬拂霜壇。", "牆頭枝動如煙綠，枕上風來送夜寒。", "第一莫教漁父見，且從蕭颯滿朱欄。"]'),
('4b6c88b1-eeb4-4913-a98d-d46985a99bc9','慈恩寺避暑','李遠','唐','唐诗','tang','','[]','香荷疑散麝，風鐸似調琴。',24,'全唐诗/poet.tang.28000.json','["香荷疑散麝，風鐸似調琴。", "不覺清涼晚，歸人滿柳陰。"]'),
('ea98ac3f-be2f-4b1c-8d3b-35a34c54dfdd','讀田光傳','李遠','唐','唐诗','tang','','[]','秦滅燕丹怨正深，古來豪客盡沾襟。',32,'全唐诗/poet.tang.28000.json','["秦滅燕丹怨正深，古來豪客盡沾襟。", "荆卿不了真閑事，辜負田光一片心。"]'),
('98e3bfe7-c57b-4fc8-a321-46a43e42a1c7','友人下第因以贈之','李遠','唐','唐诗','tang','','[]','劉毅雖然不擲盧，誰人不道解樗蒲。',32,'全唐诗/poet.tang.28000.json','["劉毅雖然不擲盧，誰人不道解樗蒲。", "黃金百萬終須得，只有挼莎更一呼。"]'),
('27c6b7fc-73cd-44f1-8cea-6c735af3d387','詠鴛鴦','李遠','唐','唐诗','tang','','["\u6292\u60c5", "\u548f\u7269", "\u548f\u7269\u8bd7"]','鴛鴦離別傷，人意似鴛鴦。',24,'全唐诗/poet.tang.28000.json','["鴛鴦離別傷，人意似鴛鴦。", "試取鴛鴦看，多應斷寸腸。"]'),
('9f643d4e-9431-46e7-b47e-b9514f28ebfd','贈箏妓伍卿','李遠','唐','唐诗','tang','','[]','輕輕沒後更無箏，玉腕紅紗到伍卿。',32,'全唐诗/poet.tang.28000.json','["輕輕沒後更無箏，玉腕紅紗到伍卿。", "座客滿筵都不語，一行哀鴈十三聲。"]'),
('96666100-2922-45d3-9c4a-3bcc1b0fff7f','黃陵廟詞','李遠','唐','唐诗','tang','','[]','黃陵廟前莎草春，黃陵女兒蒨裙新。',32,'全唐诗/poet.tang.28000.json','["黃陵廟前莎草春，黃陵女兒蒨裙新。", "輕舟小楫唱歌去，水遠山長愁殺人。"]'),
('b11a45bf-1185-4535-bf0c-74b87e6a532c','句','李遠','唐','唐诗','tang','','[]','人事三杯酒，流年一局棋。',28,'全唐诗/poet.tang.28000.json','["人事三杯酒，流年一局棋。", "青山不厭三杯酒，長日惟消一局棋。"]'),
('068a3721-4aa5-44d9-abfd-10e1d010ad6b','感懷詩一首','杜牧','唐','唐诗','tang','','[]','高文會隋季，提劒徇天意。',288,'全唐诗/poet.tang.28000.json','["高文會隋季，提劒徇天意。", "扶持萬代人，步驟三皇地。", "聖云繼之神，神仍用文治。", "德澤酌生靈，沈酣薰骨髓。", "旄頭騎箕尾，風塵薊門起。", "胡兵殺漢兵，屍滿咸陽市。", "宣皇走豪傑，談笑開中否。", "蟠聯兩河間，燼萌終不弭。", "號爲精兵處，齊蔡燕趙魏。", "合環千里疆，爭爲一家事。", "逆子嫁虜孫，西隣聘東里。", "急熱同手足，唱和如宮徵。", "法制自作爲，禮文爭僭擬。", "壓階螭鬬角，畫屋龍交尾。", "署紙日替名，分財賞稱賜。", "刳隍𣤮萬尋，繚垣疊千雉。", "誓將付孱孫，血絕然方已。", "九廟仗神靈，四海爲輸委。", "如何七十年，汗赩含羞恥。", "韓彭不再生，英衛皆爲鬼。", "凶門爪牙輩，穰穰如兒戲。", "累聖但日吁，閫外將誰寄。", "屯田數十萬，隄防常慴惴。", "急征赴軍須，厚賦資凶器。"]'),
('eba238d6-5856-4554-9945-fd22d9a421f8','杜秋娘詩','杜牧','唐','唐诗','tang','','[]','京江水清滑，生女白如脂。',288,'全唐诗/poet.tang.28000.json','["京江水清滑，生女白如脂。", "其間杜秋者，不勞朱粉施。", "老濞即山鑄，後庭千雙眉。", "秋持玉斝醉，與唱金縷衣。", "濞既白首叛，秋亦紅淚滋。", "吳江落日渡，灞岸綠楊垂。", "聯裾見天子，盼眄獨依依。", "椒壁懸錦幕，鏡奩蟠蛟螭。", "低鬟認新寵，窈裊復融怡。", "月上白璧門，桂影涼參差。", "金階露新重，閑捻紫簫吹。", "莓苔夾城路，南苑鴈初飛。", "紅粉羽林仗，獨賜辟邪旗。", "歸來煮豹胎，饜飫不能飴。", "咸池昇日慶，銅雀分香悲。", "雷音後車遠，事往落花時。", "燕禖得皇子，壯髪綠緌緌。", "畫堂授傅姆，天人親捧持。", "虎睛珠絡褓，金盤犀鎮帷。", "長楊射熊羆，武帳弄啞咿。", "漸拋竹馬劇，稍出舞雞奇。", "嶄嶄整冠珮，侍宴坐瑤池。", "眉宇儼圖畫，神秀射朝輝。", "一尺桐偶人，江充知自欺。"]'),
('3bf6ce08-f7a1-4c94-b690-0bf055d27c98','郡齋獨酌','杜牧','唐','唐诗','tang','','[]','前年鬢生雪，今年鬚帶霜。',300,'全唐诗/poet.tang.28000.json','["前年鬢生雪，今年鬚帶霜。", "時節序鱗次，古今同鴈行。", "甘英窮西海，四萬到洛陽。", "東南我所見，北可計幽荒。", "中畫一萬國，角角棊布方。", "地頑壓不穴，天逈老不僵。", "屈指百萬世，過如霹靂忙。", "人生落其內，何者爲彭殤。", "促束自繫縛，儒衣寬且長。", "旗亭雪中過，敢問當壚娘。", "我愛李侍中，標標七尺強。", "白羽八扎弓，䏶壓綠檀槍。", "風前略橫陣，紫髯分兩傍。", "淮西萬虎士，怒目不敢當。", "功成賜宴麟德殿，猨超鶻掠廣毬場。", "三千宮女側頭看，相排踏碎雙明璫。", "旌竿幖幖旗㸌㸌，意氣橫鞭歸故鄉。", "我愛朱處士，三吳當中央。", "罷亞百頃稻，西風吹半黃。", "尚可活鄉里，豈唯滿囷倉。", "後嶺翠撲撲，前溪碧泱泱。", "霧曉起鳧鴈，日晚下牛羊。", "叔舅欲飲我，社甕爾來嘗。", "伯姊子欲歸，彼亦有壺漿。"]'),
('19b95441-a769-42ee-89b6-dc618f37b993','張好好詩','杜牧','唐','唐诗','tang','','[]','君爲豫章姝，十三纔有餘。',288,'全唐诗/poet.tang.28000.json','["君爲豫章姝，十三纔有餘。", "翠茁鳳生尾，丹葉蓮含跗。", "高閣倚天半，章江聯碧虛。", "此地試君唱，特使華筵鋪。", "主人顧四座，始訝來踟蹰。", "吳娃起引贊，低徊映長裾。", "雙鬟可高下，纔過青羅襦。", "盼盼乍垂袖，一聲雛鳳呼。", "繁弦迸關紐，塞管裂圓蘆。", "衆音不能逐，褭褭穿雲衢。", "主人再三歎，謂言天下殊。", "贈之天馬錦，副以水犀梳。", "龍沙看秋浪，明月遊朱湖。", "自此每相見，三日已爲疎。", "玉質隨月滿，豔態逐春舒。", "絳脣漸輕巧，雲步轉虛徐。", "旌斾忽東下，笙歌隨舳艫。", "霜凋謝樓樹，沙暖句溪蒲。", "身外任塵土，罇前極歡娛。", "飄然集仙客，諷賦欺相如。", "聘之碧瑤珮，載以紫雲車。", "洞閉水聲遠，月高蟾影孤。", "爾來未幾歲，散盡高陽徒。", "洛城重相見，婥婥爲當壚。"]'),
('d151956a-dfeb-4637-a84c-740f8650dddc','冬至日寄小姪阿宜詩','杜牧','唐','唐诗','tang','','[]','小姪名阿宜，未得三尺長。',288,'全唐诗/poet.tang.28000.json','["小姪名阿宜，未得三尺長。", "頭圓筋骨緊，兩眼明且光。", "去年學官人，竹馬遶四廊。", "指揮羣兒輩，意氣何堅剛。", "今年始讀書，下口三五行。", "隨兄旦夕去，歛手整衣裳。", "去歲冬至日，拜我立我旁。", "祝爾願爾貴，仍且壽命長。", "今年我江外，今日生一陽。", "憶爾不可見，祝爾傾一觴。", "陽德比君子，初生甚微茫。", "排陰出九地，萬物隨開張。", "一似小兒學，日就復月將。", "勤勤不自已，二十能文章。", "仕宦至公相，致君作堯湯。", "我家公相家，劒佩嘗丁當。", "舊第開朱門，長安城中央。", "第中無一物，萬卷書滿堂。", "家集二百編，上下馳皇王。", "多是撫州寫，今來五紀強。", "尚可與爾讀，助爾爲賢良。", "經書括根本，史書閱興亡。", "高摘屈宋豔，濃薰班馬香。", "李杜泛浩浩，韓柳摩蒼蒼。"]'),
('d75971af-9e4f-4a60-b7ca-f66222d9e407','李甘詩','杜牧','唐','唐诗','tang','','[]','太和八九年，訓注極虓虎。',288,'全唐诗/poet.tang.28000.json','["太和八九年，訓注極虓虎。", "潛身九地底，轉上青天去。", "四海鏡清澄，千官雲片縷。", "公私各閑暇，追遊日相伍。", "豈知禍亂根，枝葉潛滋莽。", "九年夏四月，天誡若言語。", "烈風駕地震，獰雷驅猛雨。", "夜於正殿階，拔去千年樹。", "吾君不省覺，二凶日威武。", "操持北斗柄，開閉天門路。", "森森明庭士，縮縮循牆鼠。", "平生負奇節，一旦如奴虜。", "指名爲錮黨，狀跡誰告訴。", "喜無李杜誅，敢憚髡鉗苦。", "時當秋夜月，日值曰庚午。", "喧喧皆傳言，明晨相登注。", "予時與和鼎，官班各持斧。", "和鼎顧予言，我死知處所。", "當庭裂詔書，退立須鼎俎。", "君門曉日開，赭案橫霞布。", "儼雅千官容，勃鬱吾累怒。", "適屬命鄜將，昨之傳者誤。", "明日詔書下，謫斥南荒去。", "夜登青泥坂，墜車傷左股。"]'),
('e1552a0b-36d0-43ca-bc22-9e8653ec7eb8','洛中送冀處士東遊','杜牧','唐','唐诗','tang','','[]','處士有儒術，走可挾車輈。',288,'全唐诗/poet.tang.28000.json','["處士有儒術，走可挾車輈。", "壇宇寬帖帖，符彩高酋酋。", "不愛事耕稼，不樂干王侯。", "四十餘年中，超超爲浪遊。", "元和五六歲，客於幽魏州。", "幽魏多壯士，意氣相淹留。", "劉濟願跪履，田興請建籌。", "處士拱兩手，笑之但掉頭。", "自此南走越，尋山入羅浮。", "願學不死藥，粗知其來由。", "却於童頂上，蕭蕭玄髪抽。", "我作八品吏，洛中如繫囚。", "忽遭冀處士，豁若登高樓。", "拂榻與之坐，十日語不休。", "論今星璨璨，考古寒颼颼。", "治亂掘根本，蔓延相牽鉤。", "武事何駿壯，文理何優柔。", "顏回捧俎豆，項羽橫戈矛。", "祥雲遶毛髪，高浪開咽喉。", "但可感神鬼，安能爲獻酬。", "好入天子夢，刻像來爾求。", "胡爲去吳會，欲浮滄海舟。", "贈以蜀馬箠，副之胡罽裘。", "餞酒載三斗，東郊黃葉稠。"]'),
('2187e5ea-af1d-4503-a3b5-29432a5c2316','送沈處士赴蘇州李中丞招以詩贈行','杜牧','唐','唐诗','tang','','[]','山城樹葉紅，下有碧溪水。',288,'全唐诗/poet.tang.28000.json','["山城樹葉紅，下有碧溪水。", "溪橋向吳路，酒旗誇酒美。", "下馬此送君，高歌爲君醉。", "念君苞材能，百工在城壘。", "空山三十年，鹿裘挂窓睡。", "自言隴西公，飄然我知己。", "舉酒屬吳門，今朝爲君起。", "懸弓三百斤，囊書數萬紙。", "戰賊即戰賊，爲吏即爲吏。", "盡我所有無，惟公之指使。", "予曰隴西公，滔滔大君子。", "常思掄羣材，一爲國家治。", "譬如匠見木，礙眼皆不棄。", "大者麤十圍，小者細一指。", "㨝橛與棟梁，施之皆有位。", "忽然豎明堂，一揮立能致。", "予亦何爲者，亦受公恩紀。", "處士有常言，殘虜爲犬豕。", "常恨兩手空，不得一馬箠。", "今依隴西公，如虎傅兩翅。", "公非刺史材，當坐巖廊地。", "處士魁奇姿，必展平生志。", "東吳饒風光，翠巘多名寺。", "疎煙亹亹秋，獨酌平生思。"]'),
('d312c06e-0822-4f79-976e-a17d24284aec','長安送友人遊湖南','杜牧','唐','唐诗','tang','','[]','子性劇弘和，愚衷深褊狷。',72,'全唐诗/poet.tang.28000.json','["子性劇弘和，愚衷深褊狷。", "相舍囂譊中，吾過何由鮮。", "楚南饒風烟，湘岸苦縈宛。", "山密夕陽多，人稀芳草遠。", "青梅繁枝低，斑笋新梢短。", "莫哭葬魚人，酒醒且眠飯。"]'),
('3f98de59-a2b3-494f-a29f-d54bf52b2f19','皇風','杜牧','唐','唐诗','tang','','[]','仁聖天子神且武，內興文教外披攘。',64,'全唐诗/poet.tang.28000.json','["仁聖天子神且武，內興文教外披攘。", "以德化人漢文帝，側身修道周宣王。", "迒蹊巢穴盡窒塞，禮樂刑政皆弛張。", "何當提筆侍巡狩，前驅白斾弔河湟。"]'),
('8c6e2c3e-933f-4b97-b448-e2b87508bca4','雪中書懷','杜牧','唐','唐诗','tang','','[]','臘雪一尺厚，雲凍寒頑癡。',192,'全唐诗/poet.tang.28000.json','["臘雪一尺厚，雲凍寒頑癡。", "孤城大澤畔，人疎煙火微。", "憤悱欲誰語，憂慍不能持。", "天子號仁聖，任賢如事師。", "凡稱曰治具，小大無不施。", "明庭開廣敞，才雋受羈維。", "如日月縆昇，若鸞鳳葳蕤。", "人才自朽下，棄去亦其宜。", "北虜壞亭障，聞屯千里師。", "牽連久不解，他盜恐旁窺。", "臣實有長策，彼可徐鞭笞。", "如蒙一召議，食肉寢其皮。", "斯乃廟堂事，爾微非爾知。", "向來躐等語，長作陷身機。", "行當臘欲破，酒齊不可遲。", "且想春候暖，甕間傾一巵。"]'),
('1ea22471-a39a-45de-a8f2-91b4f18058a0','雨中作','杜牧','唐','唐诗','tang','','[]','賤子本幽慵，多爲雋賢侮。',84,'全唐诗/poet.tang.28000.json','["賤子本幽慵，多爲雋賢侮。", "得州荒僻中，更值連江雨。", "一褐擁秋寒，小窗侵竹塢。", "濁醪氣色嚴，皤腹瓶甖古。", "酣酣天地寬，怳怳嵇劉伍。", "但爲適性情，豈是藏鱗羽。", "一世一萬朝，朝朝醉中去。"]'),
('06c0883b-c3f2-4ad5-bb48-b95e9565ecf1','偶遊石盎僧舍','杜牧','唐','唐诗','tang','','[]','敬岑草浮光，句沚水解脉。',132,'全唐诗/poet.tang.28000.json','["敬岑草浮光，句沚水解脉。", "益鬱乍怡融，凝嚴忽頹坼。", "梅纇暖眠酣，風緒和無力。", "鳧浴漲汪汪，雛嬌村冪冪。", "落日美樓臺，輕烟飾阡陌。", "瀲綠古津遠，積潤苔基釋。", "孰謂漢陵人，來作江汀客。", "載筆念無能，捧籌慙所畫。", "任轡偶追閑，逢幽果遭適。", "僧語淡如雲，塵事繁堪織。", "今古幾輩人，而我何能息。"]'),
('3ac6f62b-3cf7-4c7d-8e00-28964220dcce','赴京初入汴口曉景即事先寄兵部李郎中','杜牧','唐','唐诗','tang','','[]','清淮控隋漕，北走長安道。',132,'全唐诗/poet.tang.28000.json','["清淮控隋漕，北走長安道。", "檣形櫛櫛斜，浪態迤迤好。", "初旭紅可染，明河澹如掃。", "澤闊鳥來遲，村飢人語早。", "露蔓蟲絲多，風蒲燕雛老。", "秋思高蕭蕭，客態長褭褭。", "因懷京洛間，宦遊何戚草。", "什伍持津梁，澒湧爭追討。", "翾便詎可尋，幾秘安能考。", "小人乏馨香，上下將何禱。", "唯有君子心，顯豁知幽抱。"]'),
('4e167af1-7d67-4417-aa13-bff4bbe8f9f1','獨酌','杜牧','唐','唐诗','tang','','["\u6cf0\u5c71"]','長空碧杳杳，萬古一飛鳥。',48,'全唐诗/poet.tang.28000.json','["長空碧杳杳，萬古一飛鳥。", "生前酒伴閑，愁醉閑多少。", "烟深隋家寺，殷葉暗相照。", "獨佩一壺遊，秋毫泰山小。"]'),
('e4621776-8acc-4c77-9d0e-26c2a8689b43','惜春','杜牧','唐','唐诗','tang','','[]','春半年已除，其餘強爲有。',48,'全唐诗/poet.tang.28000.json','["春半年已除，其餘強爲有。", "即此醉殘花，便同嘗臘酒。", "悵望送春杯，殷勤掃花箒。", "誰爲駐東流，年年長在手。"]'),
('ae9b1b8f-777e-482a-9cf7-92ce97b1b2f0','題安州浮雲寺樓寄湖州張郎中','杜牧','唐','唐诗','tang','','[]','去夏疎雨餘，同倚朱闌語。',48,'全唐诗/poet.tang.28000.json','["去夏疎雨餘，同倚朱闌語。", "當時樓下水，今日到何處？", "恨如春草多，事與孤鴻去。", "楚岸柳何窮，別愁紛若絮。"]'),
('5d156a2c-d295-4474-8422-786d994266a2','過驪山作','杜牧','唐','唐诗','tang','','[]','始皇東遊出周鼎，劉項縱觀皆引頸。',64,'全唐诗/poet.tang.28000.json','["始皇東遊出周鼎，劉項縱觀皆引頸。", "削平天下實辛勤，却爲道傍窮百姓。", "黔首不愚爾益愚，千里函關囚獨夫。", "牧童火入九泉底，燒作灰時猶未枯。"]'),
('86292a61-8f33-4b35-bbcb-498430f26245','池州送孟遲先輩','杜牧','唐','唐诗','tang','','[]','昔子來陵陽，時當苦炎熱。',288,'全唐诗/poet.tang.28000.json','["昔子來陵陽，時當苦炎熱。", "我雖在金臺，頭角長垂折。", "奉披塵意驚，立語平生豁。", "寺樓最鶱軒，坐送飛鳥沒。", "一罇中夜酒，半破前峰月。", "烟院松飄蕭，風廊竹交戛。", "時步郭西南，繚徑苔圓折。", "好鳥響丁丁，小溪光汃汃。", "籬落見娉婷，機絲弄啞軋。", "烟濕樹姿嬌，雨餘山態活。", "仲秋往歷陽，同上牛磯歇。", "大江吞天去，一練橫坤抹。", "千帆美滿風，曉日殷鮮血。", "歷陽裴太守，襟韻苦超越。", "鞔鼓畫麒麟，看君擊狂節。", "離袖颭應勞，恨粉啼還咽。", "明年忝諫官，綠樹秦川闊。", "子提健筆來，勢若夸父渴。", "九衢林馬撾，千門織車轍。", "秦臺破心膽，黥陣驚毛髪。", "子既屈一鳴，余固宜三刖。", "慵憂長者來，病怯長街喝。", "僧爐風雪夜，相對眠一褐。", "暖灰重擁瓶，曉粥還分鉢。"]'),
('a337ea22-8120-47eb-a23b-f8e3af843077','重送','杜牧','唐','唐诗','tang','','[]','手撚金僕姑，腰懸玉轆轤。',44,'全唐诗/poet.tang.28000.json','["手撚金僕姑，腰懸玉轆轤。", "爬頭峰北正好去，係取可汗鉗作奴。", "六宮雖念相如賦，其那防邊重武夫。"]'),
('dbfba3c0-60a7-4b6a-95f0-1cf8ab994ff8','題池州弄水亭','杜牧','唐','唐诗','tang','','[]','弄水亭前溪，颭灩翠綃舞。',288,'全唐诗/poet.tang.28000.json','["弄水亭前溪，颭灩翠綃舞。", "綺席草芊芊，紫嵐峯伍伍。", "螭蟠得形勢，翬飛如軒戶。", "一鏡匳曲堤，萬丸跳猛雨。", "檻前燕鴈棲，枕上巴帆去。", "叢筠侍修廊，密蕙媚幽圃。", "杉樹碧爲幢，花駢紅作堵。", "停樽遲晚月，咽咽上幽渚。", "客舟耿孤燈，萬里人夜語。", "漫流罥苔槎，飢鳧曬雪羽。", "玄絲落鉤餌，冰鱗看吞吐。", "斷霓天帔垂，狂燒漢旗怒。", "曠朗半秋曉，蕭瑟好風露。", "光潔疑可攬，欲以襟懷貯。", "幽抱吟九歌，羈情思湘浦。", "四時皆異狀，終日爲良遇。", "小山浸石稜，撑舟入幽處。", "孤歌倚桂巖，晚酒眠松塢。", "紆餘帶竹村，蠶鄉足砧杵。", "塍泉落環珮，畦苗差纂組。", "風俗知所尚，豪強耻孤侮。", "隣喪不相舂，公租無詬負。", "農時貴伏臘，簪瑱事禮賂。", "鄉校富華禮，征行產強弩。"]'),
('03c19b2c-c28a-4b55-a963-bf71b354f7a2','題宣州開元寺','杜牧','唐','唐诗','tang','','[]','南朝謝眺城，東吳最深處。',96,'全唐诗/poet.tang.28000.json','["南朝謝眺城，東吳最深處。", "亡國去如鴻，遺寺藏烟塢。", "樓飛九十尺，廊環四百柱。", "高高下下中，風繞松桂樹。", "青苔照朱閣，白鳥兩相語。", "溪聲入僧夢，月色暉粉堵。", "閱景無旦夕，憑闌有今古。", "留我酒一罇，前山看春雨。"]'),
('4c4f47e6-7e0d-4787-ac88-7e6921b33667','大雨行','杜牧','唐','唐诗','tang','','[]','東垠黑風駕海水，海底卷上天中央。',208,'全唐诗/poet.tang.28000.json','["東垠黑風駕海水，海底卷上天中央。", "三吳六月忽悽慘，晚後點滴來蒼茫。", "錚棧雷車軸轍壯，矯躩蛟龍爪尾長。", "神鞭鬼馭載陰帝，來往噴灑何顚狂。", "四面崩騰玉京仗，萬里橫互羽林槍。", "雲纏風束亂敲磕，黃帝未勝蚩尤強。", "百川氣勢苦豪俊，坤關密鏁愁開張。", "太和六年亦如此，我時壯氣神洋洋。", "東樓聳首看不足，恨無羽翼高飛翔。", "盡召邑中豪健者，闊展朱盤開酒場。", "奔觥槌鼓助聲勢，眼底不顧纖腰娘。", "今年闒茸鬢已白，奇遊壯觀唯深藏。", "景物不盡人自老，誰知前事堪悲傷。"]'),
('80501b83-39ec-4237-b760-69cc32067ba0','自宣州赴官入京路逢裴坦判官歸宣州因題贈','杜牧','唐','唐诗','tang','','[]','敬亭山下百頃竹，中有詩人小謝城。',208,'全唐诗/poet.tang.28000.json','["敬亭山下百頃竹，中有詩人小謝城。", "城高跨樓滿金碧，下聽一溪寒水聲。", "梅花落徑香繚繞，雪白玉璫花下行。", "縈風酒斾挂朱閣，半醉遊人聞弄笙。", "我初到此未三十，頭腦釤利筋骨輕。", "畫堂檀板秋拍碎，一引有時聯十觥。", "老閑腰下丈二組，塵土高懸千載名。", "重遊鬢白事皆改，唯見東流春水平。", "對酒不敢起，逢君還眼明。", "雲罍看人捧，波臉任他橫。", "一醉六十日，古來聞阮生。", "是非離別際，始見醉中情。", "今日送君話前事，高歌引劒還一傾。", "江湖酒伴如相問，終老烟波不計程。"]'),
('87007df8-aaeb-4050-aa30-c3ca59e9433c','贈宣州元處士','杜牧','唐','唐诗','tang','','[]','陵陽北郭隱，身世兩忘者。',48,'全唐诗/poet.tang.28000.json','["陵陽北郭隱，身世兩忘者。", "蓬蒿三畝居，寬於一天下。", "罇酒對不酌，默與玄相話。", "人生自不足，愛歎遭逢寡。"]'),
('cd34c792-ce55-4e8c-9625-88802d985c38','村行','杜牧','唐','唐诗','tang','','[]','春半南陽西，柔桑過村塢。',48,'全唐诗/poet.tang.28000.json','["春半南陽西，柔桑過村塢。", "褭褭垂柳風，點點迴塘雨。", "蓑唱牧牛兒，籬窺蒨裙女。", "半濕解征衫，主人饋雞黍。"]'),
('62c91e86-2423-4741-84ab-d392d7df173d','史將軍二首 一','杜牧','唐','唐诗','tang','','[]','長鉟周都尉，閑如秋嶺雲。',48,'全唐诗/poet.tang.28000.json','["長鉟周都尉，閑如秋嶺雲。", "取蝥弧登壘，以駢隣翼軍。", "百戰百勝價，河南河北聞。", "今遇太平日，老去誰憐君。"]'),
('f1a5a818-4f0b-4a55-a237-cc85e3767b7b','史將軍二首 二','杜牧','唐','唐诗','tang','','[]','壯氣蓋燕趙，耽耽魁傑人。',48,'全唐诗/poet.tang.28000.json','["壯氣蓋燕趙，耽耽魁傑人。", "彎弧五百步，長戟八十斤。", "河湟非內地，安史有遺塵。", "何日武臺坐，兵符授虎臣。"]'),
('0532d507-dd36-4bb4-868a-fe771d68c11e','華清宮三十韻','杜牧','唐','唐诗','tang','','[]','繡嶺明珠殿，層巒下繚牆。',288,'全唐诗/poet.tang.28000.json','["繡嶺明珠殿，層巒下繚牆。", "仰窺丹檻影，猶想赭袍光。", "昔帝登封後，中原自古強。", "一千年際會，三萬里農桑。", "几席延堯舜，軒墀接禹湯。", "雷霆馳號令，星斗煥文章。", "釣築乘時用，芝蘭在處芳。", "北扉閑木索，南面富循良。", "至道思玄圃，平居厭未央。", "鉤陳裹巖谷，文陛壓青蒼。", "歌吹千秋節，樓臺八月涼。", "神仙高縹緲，環珮碎丁當。", "泉暖涵窓鏡，雲嬌惹粉囊。", "嫩嵐滋翠葆，清渭照紅粧。", "帖泰生靈壽，懽娛歲序長。", "月聞仙曲調，霓作舞衣裳。", "雨露偏金穴，乾坤入醉鄉。", "玩兵師漢武，迴手倒干將。", "黥鬣掀東海，胡牙揭上陽。", "喧呼馬嵬血，零落羽林槍。", "傾國留無路，還魂怨有香。", "蜀峰橫慘澹，秦樹遠微茫。", "鼎重山難轉，天扶業更昌。", "望賢餘故老，花萼舊池塘。"]'),
('7d9eee90-19c6-46c5-95bc-3e34c86359aa','長安雜題長句六首 一','杜牧','唐','唐诗','tang','','[]','觚稜金碧照山高，萬國珪璋捧赭袍。',64,'全唐诗/poet.tang.28000.json','["觚稜金碧照山高，萬國珪璋捧赭袍。", "舐筆和鉛欺賈馬，讚功論道鄙蕭曹。", "東南樓日珠簾卷，西北天宛玉厄豪。", "四海一家無一事，將軍攜鏡泣霜毛。"]'),
('a62027b9-ac14-4a96-a5b6-1471d107f42d','長安雜題長句六首 二','杜牧','唐','唐诗','tang','','[]','晴雲似絮惹低空，紫陌微微弄袖風。',64,'全唐诗/poet.tang.28000.json','["晴雲似絮惹低空，紫陌微微弄袖風。", "韓嫣金丸莎覆綠，許公韉汗杏粘紅。", "煙生窈窕深東第，輪撼流蘇下北宮。", "自笑苦無樓護智，可憐鉛槧竟何功。"]'),
('435da91f-fece-442b-8567-107ba31ebaa0','長安雜題長句六首 三','杜牧','唐','唐诗','tang','','[]','雨晴九陌鋪江練，嵐嫩千峰疊海濤。',64,'全唐诗/poet.tang.28000.json','["雨晴九陌鋪江練，嵐嫩千峰疊海濤。", "南苑草芳眠錦雉，夾城雲暖下霓旄。", "少年羈絡青紋玉，遊女花簪紫蒂桃。", "江碧柳深人盡醉，一瓢顏巷日空高。"]'),
('afc6681b-6e31-4b0f-988e-f2566d2808a5','長安雜題長句六首 四','杜牧','唐','唐诗','tang','','[]','束帶謬趨文石陛，有章曾拜皁囊封。',64,'全唐诗/poet.tang.28000.json','["束帶謬趨文石陛，有章曾拜皁囊封。", "期嚴無奈睡留癖，勢窘猶爲酒泥慵。", "偷釣侯家池上雨，醉吟隋寺日沈鐘。", "九原可作吾誰與，師友瑯琊邴曼容。"]'),
('48b8d48b-5e63-4cf2-be67-9f110823d690','長安雜題長句六首 五','杜牧','唐','唐诗','tang','','[]','洪河清渭天池濬，太白終南地軸橫。',64,'全唐诗/poet.tang.28000.json','["洪河清渭天池濬，太白終南地軸橫。", "祥雲輝映漢宮紫，春光繡畫秦川明。", "草妬佳人鈿朵色，風回公子玉銜聲。", "六飛南幸芙蓉苑，十里飄香入夾城。"]'),
('26ad42b7-b471-43d8-a403-61c70d011cf2','長安雜題長句六首 六','杜牧','唐','唐诗','tang','','[]','豐貂長組金張輩，駟馬文衣許史家。',64,'全唐诗/poet.tang.28000.json','["豐貂長組金張輩，駟馬文衣許史家。", "白鹿原頭回獵騎，紫雲樓下醉江花。", "九重樹影連清漢，萬壽山光學翠華。", "誰識大君謙讓德，一毫名利鬬鼃蟇。"]'),
('22e1a6e4-3934-4d1d-a3ad-ce4606e423e4','河湟','杜牧','唐','唐诗','tang','','["\u7231\u56fd", "\u5fe7\u56fd\u5fe7\u6c11"]','元載相公曾借箸，憲宗皇帝亦留神。',64,'全唐诗/poet.tang.28000.json','["元載相公曾借箸，憲宗皇帝亦留神。", "旋見衣冠就東市，忽遺弓劒不西巡。", "牧羊驅馬雖戎服，白髮丹心盡漢臣。", "唯有涼州歌舞曲，流傳天下樂閑人。"]'),
('b1836f0d-c025-4227-994c-81fcc32abab4','許七侍御棄官東歸瀟灑江南頗聞自適高秋企望題詩寄贈十韻','杜牧','唐','唐诗','tang','','[]','天子繡衣吏，東吳美退居。',120,'全唐诗/poet.tang.28000.json','["天子繡衣吏，東吳美退居。", "有園同庾信，避事學相如。", "蘭畹晴香嫩，筠溪翠影疎。", "江山九秋後，風月六朝餘。", "錦帙開詩軸，青囊結道書。", "霜巖紅薜荔，露沼白芙蕖。", "睡雨高梧密，棊燈小閣虛。", "凍醪元亮秫，寒鱠季鷹魚。", "塵意迷今古，雲情識卷舒。", "他年雪中櫂，陽羨訪吾廬。"]'),
('21a25ad0-efcd-4736-bb8a-7bdd1718f45a','李給事中敏二首 一','杜牧','唐','唐诗','tang','','[]','一章緘拜皁囊中，懍懍朝廷有古風。',63,'全唐诗/poet.tang.28000.json','["一章緘拜皁囊中，懍懍朝廷有古風。", "元禮去歸緱氏學江充來見犬臺宮。", "紛紜白晝驚千古，鈇鑕朱殷幾一空。", "曲突徙薪人不會，海邊今作釣魚翁。"]'),
('bbea466c-3c71-4c61-a50b-8528c8a23328','李給事中敏二首 二','杜牧','唐','唐诗','tang','','[]','晚髪悶還梳，憶君秋醉餘。',36,'全唐诗/poet.tang.28000.json','["晚髪悶還梳，憶君秋醉餘。", "可憐劉校尉，曾訟石中書。", "消長雖殊事，仁賢每自如。"]'),
('2656c476-8e06-4d52-bed8-5102a10e0130','題永崇西平王宅太尉愬院六韻','杜牧','唐','唐诗','tang','','[]','天下無雙將，關西第一雄。',72,'全唐诗/poet.tang.28000.json','["天下無雙將，關西第一雄。", "授符黃石老，學劒白猿翁。", "矯矯雲長勇，恂恂郄縠風。", "家呼小太尉，國號大梁公。", "半夜龍驤去，中原虎穴空。", "隴山兵十萬，嗣子握琱弓。"]'),
('16aeb267-54a8-4c49-9d94-3306022db14d','東兵長句十韻','杜牧','唐','唐诗','tang','','[]','上黨爭爲天下脊，邯鄲四十萬秦坑。',160,'全唐诗/poet.tang.28000.json','["上黨爭爲天下脊，邯鄲四十萬秦坑。", "狂童何者欲專地，聖主無私豈翫兵。", "玄象森羅搖北落，詩人章句詠東征。", "雄如馬武皆彈劒，少似終軍亦請纓。", "屈指廟堂無失策，垂衣堯舜待昇平。", "羽林東下雷霆怒，楚甲南來組練明。", "即墨龍文光照曜，常山蛇陣勢縱橫。", "落鵰都尉萬人敵，黑矟將軍一鳥輕。", "漸見長圍雲欲合，可憐窮壘帶猶縈。", "凱歌應是新年唱，便逐春風浩浩聲。"]'),
('9e0663db-9490-4fb0-9078-2893d7bea293','過勤政樓','杜牧','唐','唐诗','tang','','[]','千秋令節名空在，承露絲囊世已無。',32,'全唐诗/poet.tang.28000.json','["千秋令節名空在，承露絲囊世已無。", "唯有紫苔偏得意，年年因雨上金鋪。"]'),
('e6530863-e268-46d9-8987-932b95880479','過魏文貞公宅','杜牧','唐','唐诗','tang','','[]','蟪蛄寧與雪霜期，賢哲難教俗士知。',32,'全唐诗/poet.tang.28000.json','["蟪蛄寧與雪霜期，賢哲難教俗士知。", "可憐貞觀太平後，天且不留封德彝。"]'),
('690d298b-3851-4c06-9a4c-6fb0d2edf3b9','早春閣下寓直蕭九舍人亦直內署因寄書懷四韻','杜牧','唐','唐诗','tang','','[]','御水初銷凍，宮花尚怯寒。',48,'全唐诗/poet.tang.28000.json','["御水初銷凍，宮花尚怯寒。", "千峰橫紫翠，雙闕凭闌干。", "玉漏輕風順，金莖淡日殘。", "王喬在何處，清漢正驂鸞。"]'),
('594fbb93-3c35-4cb6-a972-cbdfa2af3c48','秋晚與沈十七舍人期遊樊川不至','杜牧','唐','唐诗','tang','','[]','邀侶以官解，泛然成獨遊。',48,'全唐诗/poet.tang.28000.json','["邀侶以官解，泛然成獨遊。", "川光初媚日，山色正矜秋。", "野竹疎還密，巖泉咽復流。", "杜村連潏水，晚步見垂鉤。"]'),
('9dd71670-cca1-4053-8717-7eae8e581eb0','念昔遊三首 一','杜牧','唐','唐诗','tang','','[]','十載飄然繩檢外，罇前自獻自爲酬。',32,'全唐诗/poet.tang.28000.json','["十載飄然繩檢外，罇前自獻自爲酬。", "秋山春雨閑吟處，倚徧江南寺寺樓。"]'),
('a4f7b1c2-21e2-469a-ab95-72927d5958d8','念昔遊三首 二','杜牧','唐','唐诗','tang','','[]','雲門寺外逢猛雨，林黑山高雨脚長。',32,'全唐诗/poet.tang.28000.json','["雲門寺外逢猛雨，林黑山高雨脚長。", "曾奉郊宮爲近侍，分明羽林槍。"]'),
('ab3d61d5-ed3d-4573-b61d-7e3b9af7715f','念昔遊三首 三','杜牧','唐','唐诗','tang','','[]','李白題詩水西寺，古木回巖樓閣風。',32,'全唐诗/poet.tang.28000.json','["李白題詩水西寺，古木回巖樓閣風。", "半醒半醉遊三日，紅白花開山雨中。"]'),
('a8302824-60db-4898-b5f7-de39d4666f6b','今皇帝陛下一詔徵兵不日功集河湟諸郡次第歸降臣獲覩聖功輒獻歌詠','杜牧','唐','唐诗','tang','','[]','捷書皆應睿謀期，十萬曾無一鏃遺。',64,'全唐诗/poet.tang.28000.json','["捷書皆應睿謀期，十萬曾無一鏃遺。", "漢武慙誇朔方地，周宣休道太原師。", "威加塞外寒來早，恩入河源凍合遲。", "聽取滿城歌舞曲，涼州聲韻喜參差。"]'),
('e9c2e42e-a6c1-4203-9970-e23b77e06a78','奉和白相公聖德和平致茲休運歲終功就合詠盛明呈上三相公長句四韻','杜牧','唐','唐诗','tang','','[]','行看臘破好年光，萬壽南山對未央。',64,'全唐诗/poet.tang.28000.json','["行看臘破好年光，萬壽南山對未央。", "黠戛可汗修職貢，文思天子復河湟。", "應須日馭西巡狩，不假星弧北射狼。", "吉甫裁詩歌盛業，一篇江漢美宣王。"]'),
('14316b5b-cba2-41e0-84bd-3c3ed0c02407','過華清宮絕句三首 一','杜牧','唐','唐诗','tang','','["\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u9ad8\u4e2d\u53e4\u8bd7", "\u5e26\u6709\u5730\u540d", "\u548f\u53f2", "\u5730\u540d"]','長安回望繡成堆，山頂千門次第開。',32,'全唐诗/poet.tang.28000.json','["長安回望繡成堆，山頂千門次第開。", "一騎紅塵妃子笑，無人知是荔枝來。"]'),
('cb86c6a7-f428-4126-8e80-262b9e3d7a52','過華清宮絕句三首 二','杜牧','唐','唐诗','tang','','[]','新豐綠樹起黃埃，數騎漁陽探使回。',32,'全唐诗/poet.tang.28000.json','["新豐綠樹起黃埃，數騎漁陽探使回。", "霓裳一曲千峰上，舞破中原始下來。"]'),
('337d1cf5-29eb-44e3-a32e-30f97274ba7f','過華清宮絕句三首 三','杜牧','唐','唐诗','tang','','[]','萬國笙歌醉太平，倚天樓殿月分明。',32,'全唐诗/poet.tang.28000.json','["萬國笙歌醉太平，倚天樓殿月分明。", "雲中亂拍祿山舞，風過重巒下笑聲。"]'),
('6a2432a7-d169-4216-8aaa-212a2ef3b690','登樂遊原','杜牧','唐','唐诗','tang','','["\u7231\u56fd", "\u79cb\u5929", "\u601d\u4e61", "\u6292\u6000", "\u611f\u6168", "\u4e94\u8a00\u7edd\u53e5"]','長空澹澹孤鳥沒，萬古銷沈向此中。',32,'全唐诗/poet.tang.28000.json','["長空澹澹孤鳥沒，萬古銷沈向此中。", "看取漢家何事業，五陵無樹起秋風。"]'),
('5a429d13-1d1b-4a15-9823-4abea75b9fa4','聞慶州趙縱使君與党項戰中箭身死輒書長句','杜牧','唐','唐诗','tang','','[]','將軍獨乘鐵驄馬，榆溪戰中金僕姑。',64,'全唐诗/poet.tang.28000.json','["將軍獨乘鐵驄馬，榆溪戰中金僕姑。", "死綏却是古來有，驍將自驚今日無。", "青史文章爭點筆，朱門歌舞笑捐軀。", "誰知我亦輕生者，不得君王丈二殳。"]'),
('17172d81-1211-4265-8908-4a3ec146106c','送容州唐中丞赴鎮','杜牧','唐','唐诗','tang','','[]','交阯同星座，龍泉佩斗文。',48,'全唐诗/poet.tang.28000.json','["交阯同星座，龍泉佩斗文。", "燒香翠羽帳，看舞鬱金裙。", "鷁首衝瀧浪，犀渠拂嶺雲。", "莫教銅柱北，空說馬將軍。"]'),
('e5cbf443-9e01-45ed-a539-112611295082','夏州崔常侍自少常亞列出領麾幢十韻','杜牧','唐','唐诗','tang','','[]','帝命詩書將，登壇禮樂卿。',120,'全唐诗/poet.tang.28000.json','["帝命詩書將，登壇禮樂卿。", "三邊要高枕，萬里得長城。", "對客猶褒博，填門已斾旌。", "腰間五綬貴，天下一家榮。", "野水差新燕，芳郊哢夏鶯。", "別風嘶玉勒，殘日望金莖。", "榆塞孤煙媚，銀川綠草明。", "戈矛虓虎士，弓箭落鵰兵。", "魏絳言堪採，陳湯事偶成。", "若須垂竹帛，靜勝是功名。"]'),
('747fdddf-b43d-426c-bcbd-2f3b9eccb08e','街西長句','杜牧','唐','唐诗','tang','','[]','碧池新漲浴嬌鴉，分鏁長安富貴家。',64,'全唐诗/poet.tang.28000.json','["碧池新漲浴嬌鴉，分鏁長安富貴家。", "遊騎偶同人鬬酒，名園相倚杏交花。", "銀鞦騕褭嘶宛馬，繡鞅璁瓏走鈿車。", "一曲將軍何處笛，連雲芳草日初斜。"]'),
('f06ddbb3-1a93-425c-9cc3-83d40f526348','春申君','杜牧','唐','唐诗','tang','','[]','烈士思酬國士恩，春申誰與快冤魂。',32,'全唐诗/poet.tang.28000.json','["烈士思酬國士恩，春申誰與快冤魂。", "三千賓客總珠履，欲使何人殺李園。"]'),
('a7ed23a0-683c-4d52-8e5e-abfed4b24bb5','奉陵宮人','杜牧','唐','唐诗','tang','','[]','相如死後無詞客，延壽亡來絕畫工。',32,'全唐诗/poet.tang.28000.json','["相如死後無詞客，延壽亡來絕畫工。", "玉顏不是黃金少，淚滴秋山入壽宮。"]'),
('30c9065b-873e-4240-a0ba-e4a4c7ec3cc6','讀韓杜集','杜牧','唐','唐诗','tang','','["\u8bfb\u4e66", "\u8d5e\u7f8e"]','杜詩韓集愁來讀，似倩麻姑癢處抓。',32,'全唐诗/poet.tang.28000.json','["杜詩韓集愁來讀，似倩麻姑癢處抓。", "天外鳳凰誰得髓，無人解合續弦膠。"]'),
('6688d66f-0e76-4669-a277-4a76316beacf','春日言懷寄虢州李常侍十韻','杜牧','唐','唐诗','tang','','[]','岸蘚生紅藥，巖泉漲碧塘。',120,'全唐诗/poet.tang.28000.json','["岸蘚生紅藥，巖泉漲碧塘。", "地分蓮嶽秀，草接鼎原芳。", "雨派潀漴急，風畦芷若香。", "織蓬眠舴艋，驚夢起鴛鴦。", "論吐開冰室，詩陳曝錦張。", "貂簪荆玉潤，丹穴鳳毛光。", "今日還珠守，何年執戟郎。", "且嫌遊晝短，莫問積薪長。", "無計披清裁，唯持祝壽觴。", "願公如衛武，百歲尚康強。"]'),
('fc087994-5a91-4153-89fe-92c6c51d2201','李侍郎於陽羨里富有泉石牧亦於陽羨粗有薄產敘舊述懷因獻長句四韻','杜牧','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','冥鴻不下非無意，塞馬歸來是偶然。',64,'全唐诗/poet.tang.28000.json','["冥鴻不下非無意，塞馬歸來是偶然。", "紫綬公卿今放曠，白頭郎吏尚留連。", "終南山下拋泉洞，陽羨溪中買釣船。", "欲與明公操履杖，願聞休去是何年。"]'),
('6f65a961-7967-4595-bce3-b7b094dfadfb','贈李處士長句四韻','杜牧','唐','唐诗','tang','','[]','玉函怪牒鎖靈篆，紫洞香風吹碧桃。',64,'全唐诗/poet.tang.28000.json','["玉函怪牒鎖靈篆，紫洞香風吹碧桃。", "老翁四目牙爪利，擲火萬里精神高。", "靄靄祥雲隨步武，纍纍秋冢歎蓬蒿。", "三山朝去應非久，姹女當窗繡羽袍。"]'),
('f97759c8-a206-4452-a695-8b0f40d7f720','送國棊王逢','杜牧','唐','唐诗','tang','','[]','玉子紋楸一路饒，最宜簷雨竹蕭蕭。',64,'全唐诗/poet.tang.28000.json','["玉子紋楸一路饒，最宜簷雨竹蕭蕭。", "羸形暗去春泉長，拔勢橫來野火燒。", "守道還如周柱史，鏖兵不羨霍嫖姚。", "浮生七十更萬日，與子期于局上銷。"]'),
('1d6d532d-4fe2-4883-b9c2-1a2af4f8ebb8','重送絕句','杜牧','唐','唐诗','tang','','[]','絕藝如君天下少，閑人似我世間無。',32,'全唐诗/poet.tang.28000.json','["絕藝如君天下少，閑人似我世間無。", "別後竹窓風雪夜，一燈明暗覆吳圖。"]'),
('51445201-8364-4479-8e38-44561562e28b','少年行','杜牧','唐','唐诗','tang','','[]','連環羈玉聲光碎，綠錦蔽泥虬卷高。',32,'全唐诗/poet.tang.28000.json','["連環羈玉聲光碎，綠錦蔽泥虬卷高。", "春風細雨走馬去，珠落璀璀白罽袍。"]'),
('a886252d-a06c-49f3-bc18-26a96a128dcd','奉和門下相公送西川相公兼領相印出鎮全蜀詩十八韻','杜牧','唐','唐诗','tang','','[]','盛業冠伊唐，台階翊戴光。',216,'全唐诗/poet.tang.28000.json','["盛業冠伊唐，台階翊戴光。", "無私天雨露，有截舜衣裳。", "蜀輟新衡鏡，池留舊鳳凰。", "同心真石友，寫恨蔑河梁。", "虎騎搖風斾，貂冠韻水蒼。", "彤弓隨武庫，金印逐文房。", "棧壓嘉陵咽，峰橫劒閣長。", "前驅二星去，開險五丁忙。", "回首崢嶸盡，連天草樹芳。", "丹心懸魏闕，往事愴甘棠。", "治化輕諸葛，威聲懾夜郎。", "君平教說卦，夫子召升堂。", "塞接西山雪，橋維萬里檣。", "奪霞紅錦爛，撲地酒壚香。", "忝逐三千客，曾依數仞牆。", "滯頑堪白屋，攀附亦同行。", "肉管伶倫曲，簫韶清廟章。", "唱高知和寡，小子斐然狂。"]'),
('6b1d8442-4872-433e-9e0a-37be8fc98de8','朱坡','杜牧','唐','唐诗','tang','','[]','下杜鄉園古，泉聲繞舍啼。',240,'全唐诗/poet.tang.28000.json','["下杜鄉園古，泉聲繞舍啼。", "靜思長慘切，薄宦與乖暌。", "北闕千門外，南山午谷西。", "倚川紅葉嶺，連寺綠楊堤。", "迥野翹霜鶴，澄潭舞錦雞。", "濤驚堆萬岫，舸急轉千溪。", "眉點萱牙嫩，風條柳幄迷。", "岸藤梢虺尾，沙渚印麑蹄。", "火燎湘桃塢，波光碧繡畦。", "日痕絙翠巘，陂影墮晴霓。", "蝸壁斕斑蘚，銀筵豆蔻泥。", "洞雲生片段，苔徑繚高低。", "偃蹇松公老，森嚴竹陣齊。", "小蓮娃欲語，幽笋稚相攜。", "漢館留餘趾，周臺接故蹊。", "蟠蛟岡隱隱，班雉草萋萋。", "樹老蘿紆組，巖深石啓閨。", "侵窓紫桂茂，拂面翠禽棲。", "有計冠終挂，無才筆謾提。", "自塵何太甚，休笑觸藩羝。"]'),
('7a9d092c-3ee9-4ca9-83f1-11bc59fb3986','早春寄岳州李使君李善棊愛酒情地閑雅','杜牧','唐','唐诗','tang','','[]','城高倚峭巘，地勝足樓臺。',108,'全唐诗/poet.tang.28000.json','["城高倚峭巘，地勝足樓臺。", "朔漠暖鴻去，瀟湘春水來。", "縈盈幾多思，掩抑若爲裁。", "返照三聲角，寒香一樹梅。", "烏林芳草遠，赤壁健帆開。", "往事空遺恨，東流豈不回。", "分符潁川政，弔屈洛陽才。", "拂匣調珠柱，磨鉛勘玉杯。", "棊翻小窟勢，壚撥凍醪醅。"]'),
('909490a2-5083-4b45-b44c-0df6f7cd7eb3','送王侍御赴夏口座主幕','杜牧','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','君爲珠履三千客，我是青衿七十徒。',48,'全唐诗/poet.tang.28000.json','["君爲珠履三千客，我是青衿七十徒。", "禮數全優知隗始，討論常見念回愚。", "黃鶴樓前春水闊，一杯還憶故人無。"]'),
('2c972bc6-cc65-4ead-a899-29a68298bb0f','自貽','杜牧','唐','唐诗','tang','','[]','杜陵蕭次君，遷少去官頻。',48,'全唐诗/poet.tang.28000.json','["杜陵蕭次君，遷少去官頻。", "寂寞憐吾道，依稀似古人。", "餙心無彩繢，到骨是風塵。", "自嫌如匹素，刀尺不由身。"]'),
('d1c9fb4d-2e0c-4fe4-851e-31be5ce89454','自遣','杜牧','唐','唐诗','tang','','[]','四十已云老，況逢憂窘餘。',72,'全唐诗/poet.tang.28000.json','["四十已云老，況逢憂窘餘。", "且抽持板手，却展小年書。", "嗜酒狂嫌阮，知非晚笑蘧。", "聞流寧歎吒，待俗不親疎。", "遇事知裁剪，操心識卷舒。", "還稱二千石，於我意何如。"]'),
('e1f2edef-a6a6-40bd-97e1-c5dedb7976b2','題桐葉','杜牧','唐','唐诗','tang','','[]','去年桐落故溪上，把筆偶題歸燕詩。',192,'全唐诗/poet.tang.28000.json','["去年桐落故溪上，把筆偶題歸燕詩。", "江樓今日送歸燕，正是去年題葉時。", "葉落燕歸真可惜，東流玄髪且無期。", "笑筵歌席反惆悵，明月清風愴別離。", "莊叟彭殤同在夢，陶潛身世兩相遺。", "一丸五色成虛語，石爛松薪更莫疑。", "哆侈不勞文似錦，進趨何必利如錐。", "錢神任爾知無敵，酒聖於吾亦庶幾。", "江畔秋光蟾閣鏡，檻前山翠茂陵眉。", "樽香輕泛數枝菊，簷影斜侵半局棊。", "休指宦遊論巧拙，秪將愚直禱神祇。", "三吳煙水平生念，寧向閑人道所之。"]'),
('0e8ea9f7-c97d-40a9-ab5e-8317678d6377','沈下賢','杜牧','唐','唐诗','tang','','[]','斯人清唱何人和，草徑苔蕪不可尋。',32,'全唐诗/poet.tang.28000.json','["斯人清唱何人和，草徑苔蕪不可尋。", "一夕小敷山下夢，水如環珮月如襟。"]'),
('f7f84fa9-a466-46f4-9934-ec9faff3ce19','李和鼎','杜牧','唐','唐诗','tang','','[]','鵩鳥飛來庚子直，謫去日蝕辛卯年。',32,'全唐诗/poet.tang.28000.json','["鵩鳥飛來庚子直，謫去日蝕辛卯年。", "由來枉死賢才事，消長相持勢自然。"]'),
('78e09255-add5-4659-9448-f085f3e72e22','贈沈學士張歌人','杜牧','唐','唐诗','tang','','[]','拖袖事當年，郎教唱客前。',72,'全唐诗/poet.tang.28000.json','["拖袖事當年，郎教唱客前。", "斷時輕裂玉，收處遠繰煙。", "孤直縆雲定，光明滴水圓。", "泥情遲急管，流恨咽長弦。", "吳苑春風起，河橋酒斾懸。", "憑君更一醉，家在杜陵邊。"]'),
('0eb9c7e7-b800-4ec0-88a6-ed07d05ac67f','憶遊朱坡四韻','杜牧','唐','唐诗','tang','','[]','秋草樊川路，斜陽覆盎門。',48,'全唐诗/poet.tang.28000.json','["秋草樊川路，斜陽覆盎門。", "獵逢韓嫣騎，樹識館陶園。", "帶雨經荷沼，盤烟下竹村。", "如今歸不得，自戴望天盆。"]'),
('d83a9e7c-3c75-4cf0-9eab-0ca0085405f7','朱坡絕句三首 一','杜牧','唐','唐诗','tang','','[]','故國池塘倚御渠，江城三詔換魚書。',32,'全唐诗/poet.tang.28000.json','["故國池塘倚御渠，江城三詔換魚書。", "賈生辭賦恨流落，秪向長沙住歲餘。"]'),
('8b35b626-7398-4f93-9dea-6497b9557bbe','朱坡絕句三首 二','杜牧','唐','唐诗','tang','','[]','煙深苔巷唱樵兒，花落寒輕倦客歸。',32,'全唐诗/poet.tang.28000.json','["煙深苔巷唱樵兒，花落寒輕倦客歸。", "藤岸竹洲相掩映，滿池春雨鸊鵜飛。"]'),
('cbb59b8b-ba8d-446e-a32a-3a5aba73215e','朱坡絕句三首 三','杜牧','唐','唐诗','tang','','[]','乳肥春洞生鵝管，沼避回巖勢犬牙。',32,'全唐诗/poet.tang.28000.json','["乳肥春洞生鵝管，沼避回巖勢犬牙。", "自笑卷懷頭角縮，歸盤煙磴恰如蝸。"]'),
('0dcd49c4-9c54-4213-a053-0735ff32a300','出宮人二首 一','杜牧','唐','唐诗','tang','','[]','閑吹玉殿昭華管，醉折梨園縹蔕花。',32,'全唐诗/poet.tang.28000.json','["閑吹玉殿昭華管，醉折梨園縹蔕花。", "十年一夢歸人世，絳縷猶封繫臂紗。"]'),
('fe0bd7d8-e052-444f-bc78-e450c1218ea5','出宮人二首 二','杜牧','唐','唐诗','tang','','[]','平陽拊背穿馳道，銅雀分香下璧門。',32,'全唐诗/poet.tang.28000.json','["平陽拊背穿馳道，銅雀分香下璧門。", "幾向綴珠深殿裏，妬拋羞態臥黃昏。"]'),
('95c94d96-7449-4eca-a38d-fcd0a435b729','長安秋望','杜牧','唐','唐诗','tang','','["\u79cb\u5929", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','樓倚霜樹外，鏡天無一毫。',24,'全唐诗/poet.tang.28000.json','["樓倚霜樹外，鏡天無一毫。", "南山與秋色，氣勢兩相高。"]'),
('a8b2207b-ed83-4c74-adca-856c4eda51b5','獨酌','杜牧','唐','唐诗','tang','','[]','窓外正風雪，擁爐開酒缸。',24,'全唐诗/poet.tang.28000.json','["窓外正風雪，擁爐開酒缸。", "何如釣船雨，蓬底睡秋江。"]'),
('c98648f2-4460-4e42-8e3f-8330d837fa2a','醉眠','杜牧','唐','唐诗','tang','','[]','秋醪雨中熟，寒齋落葉中。',24,'全唐诗/poet.tang.28000.json','["秋醪雨中熟，寒齋落葉中。", "幽人本多睡，更酌一樽空。"]'),
('0c417148-927c-4333-bddd-0c72c081f126','不飲贈酒','杜牧','唐','唐诗','tang','','[]','細算人生事，彭殤共一籌。',24,'全唐诗/poet.tang.28000.json','["細算人生事，彭殤共一籌。", "與愁爭底事，要爾作戈矛。"]'),
('c8222908-3d20-44a3-bf34-decc9d982042','昔事文皇帝三十二韻','杜牧','唐','唐诗','tang','','[]','昔事文皇帝，叨官在諫垣。',288,'全唐诗/poet.tang.28000.json','["昔事文皇帝，叨官在諫垣。", "奏章爲得地，齚齒負明恩。", "金虎知難動，毛釐亦恥言。", "掩頭雖欲吐，到口却成吞。", "照膽常懸鏡，窺天自戴盆。", "周鐘既窕槬，黥陣亦瘢痕。", "鳳闕觚稜影，仙盤曉日暾。", "雨晴文石滑，風暖戟衣翻。", "每慮號無告，長憂駭不存。", "隨行唯跼蹐，出語但寒暄。", "宮省咽喉任，戈矛羽衛屯。", "光塵皆影附，車馬定西奔。", "億萬持衡價，錙銖挾契論。", "堆時過北斗，積處滿西園。", "接櫂隋河溢，連蹄蜀棧刓。", "漉空滄海水，搜盡卓王孫。", "鬬巧猴雕刺，誇趫索挂跟。", "狐威假白額，梟嘯得黃昏。", "馥馥芝蘭圃，森森枳棘藩。", "吠聲嗾國猘，公議怯膺門。", "竄逐諸丞相，蒼茫遠帝閽。", "一名爲吉士，誰免弔湘魂。", "間世英明主，中興道德尊。", "崑岡憐積火，河漢注清源。"]'),
('ad4f5881-dee8-459e-a238-1a6d71bb578d','道一大尹存之庭美二學士簡于聖明自致霄漢皆與舍弟昔年還往牧支離窮悴竊於一麾書美歌詩兼自言志因成長句四韻呈上三君子','杜牧','唐','唐诗','tang','','[]','九金神鼎重丘山，五玉諸侯雜珮環。',64,'全唐诗/poet.tang.28000.json','["九金神鼎重丘山，五玉諸侯雜珮環。", "星座通霄狼鬣暗，戍樓吹笛虎牙閑。", "斗間紫氣龍埋獄，天上洪爐帝鑄顏。", "若念西河舊交友，魚符應許出函關。"]'),
('81a76fa8-deac-4ef4-8142-04c9872b2f8a','杏園','杜牧','唐','唐诗','tang','','[]','夜來微雨洗芳塵，公子驊騮步貼勻。',32,'全唐诗/poet.tang.28000.json','["夜來微雨洗芳塵，公子驊騮步貼勻。", "莫怪杏園顦顇去，滿城多少插花人。"]'),
('88aa49da-9872-465a-a795-e3120ec633b4','春晚題韋家亭子','杜牧','唐','唐诗','tang','','[]','擁鼻侵襟花草香，高臺春去恨茫茫。',32,'全唐诗/poet.tang.28000.json','["擁鼻侵襟花草香，高臺春去恨茫茫。", "蔫紅半落平池晚，曲渚飄成錦一張。"]'),
('cd78c143-aeb7-4443-8aeb-69e788d66c2e','過田家宅','杜牧','唐','唐诗','tang','','[]','安邑南門外，誰家板築高。',24,'全唐诗/poet.tang.28000.json','["安邑南門外，誰家板築高。", "奉誠園裏地，牆缺見蓬蒿。"]'),
('1aba19d5-e5cf-45cf-82ee-58648d419b25','見宋拾遺題名處感而成詩','杜牧','唐','唐诗','tang','','[]','竄逐窮荒與死期，餓唯蒿藿病無醫。',32,'全唐诗/poet.tang.28000.json','["竄逐窮荒與死期，餓唯蒿藿病無醫。", "憐君更抱重泉恨，不見崇山謫去時。"]'),
('d7421f3a-5cea-4476-aca5-6ab120303f16','雪晴訪趙嘏街西所居三韻','杜牧','唐','唐诗','tang','','[]','命代風騷將，誰登李杜壇。',40,'全唐诗/poet.tang.28000.json','["命代風騷將，誰登李杜壇。", "少陵鯨海動，翰苑鶴天寒。", "今日訪君還有意，三條冰雪獨來看。"]'),
('24ca9268-9cbd-423b-b423-12e1a9aa9041','將赴吳興登樂遊原一絕','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u7231\u56fd"]','清時有味是無能，閑愛孤雲靜愛僧。',32,'全唐诗/poet.tang.28000.json','["清時有味是無能，閑愛孤雲靜愛僧。", "欲把一麾江海去，樂遊原上望昭陵。"]'),
('e5fc20d0-10f7-4b8c-954c-7198fcf2cd98','洛陽長句二首 一','杜牧','唐','唐诗','tang','','[]','草色人心相與閑，是非名利有無間。',64,'全唐诗/poet.tang.28000.json','["草色人心相與閑，是非名利有無間。", "橋橫落照虹堪畫，樹鎖千門鳥自還。", "芝蓋不來雲杳杳，仙舟何處水潺潺？", "君王謙讓泥金事，蒼翠空高萬歲山。"]'),
('8a16c3ba-6095-4c22-92ad-6e3adb53bee1','洛陽長句二首 二','杜牧','唐','唐诗','tang','','[]','天漢東穿白玉京，日華浮動翠光生。',48,'全唐诗/poet.tang.28000.json','["天漢東穿白玉京，日華浮動翠光生。", "橋邊遊女珮環委，波底上陽金碧明。", "月鎖名園孤鶴唳，川酣秋夢鑿龍聲。"]'),
('ac86417f-9ce1-4b16-90c9-8bf7a14ee47c','洛中監察病假滿送韋楚老拾遺歸朝','杜牧','唐','唐诗','tang','','[]','洛橋風暖細翻衣，春引仙官去玉墀。',64,'全唐诗/poet.tang.28000.json','["洛橋風暖細翻衣，春引仙官去玉墀。", "獨鶴初沖太虛日，九牛新落一毛時。", "行開教化期君是，臥病神祇禱我知。", "十載丈夫堪恥處，朱雲猶掉直言旗。"]'),
('763a05fa-d6c1-41a7-b11f-2e3bb9540ef5','東都送鄭處誨校書歸上都','杜牧','唐','唐诗','tang','','[]','悠悠渠水清，雨霽洛陽城。',48,'全唐诗/poet.tang.28000.json','["悠悠渠水清，雨霽洛陽城。", "槿墮初開豔，蟬聞第一聲。", "故人容易去，白髮等閑生。", "此別無多語，期君晦盛名。"]'),
('643c46d6-1e3f-41f0-b78c-60df0400e496','故洛陽城有感','杜牧','唐','唐诗','tang','','[]','一片宮牆當道危，行人爲爾去遲遲。',64,'全唐诗/poet.tang.28000.json','["一片宮牆當道危，行人爲爾去遲遲。", "篳圭苑裏秋風後，平樂館前斜日時。", "錮黨豈能留漢鼎，清談空解識胡兒。", "千燒萬戰坤靈死，慘慘終年鳥雀悲。"]'),
('554f48ec-69db-4890-96b5-7eaca5e6596e','揚州三首 一','杜牧','唐','唐诗','tang','','[]','煬帝雷塘土，迷藏有舊樓。',48,'全唐诗/poet.tang.28000.json','["煬帝雷塘土，迷藏有舊樓。", "誰家唱水調，明月滿揚州。", "駿馬宜閑出，千金好舊游。", "喧闐醉年少，半脫紫茸裘。"]'),
('a75989ce-f97f-4abc-bc28-4463c888ccc7','揚州三首 二','杜牧','唐','唐诗','tang','','[]','秋風放螢苑，春草鬬雞臺。',48,'全唐诗/poet.tang.28000.json','["秋風放螢苑，春草鬬雞臺。", "金絡擎鵰去，鸞環拾翠來。", "蜀船紅錦重，越橐水沈堆。", "處處皆華表，淮王奈却回。"]'),
('c761c2ee-9b29-45a2-bdea-af11fa94f7c3','揚州三首 三','杜牧','唐','唐诗','tang','','[]','街垂千步柳，霞映兩重城。',59,'全唐诗/poet.tang.28000.json','["街垂千步柳，霞映兩重城。", "天碧臺閣麗，風涼歌管清。", "纖腰間長袖，玉珮雜繁纓。", "拖軸誠爲壯，豪華不可名。", "自是荒淫罪何妨作帝京。"]'),
('6e659f21-993b-44be-9ceb-66d0a9d9206a','潤州二首 一','杜牧','唐','唐诗','tang','','[]','句吳亭東千里秋，放歌曾作昔年遊。',64,'全唐诗/poet.tang.28000.json','["句吳亭東千里秋，放歌曾作昔年遊。", "青苔寺裏無馬跡，綠水橋邊多酒樓。", "大抵南朝皆曠達，可憐東晉最風流。", "月明更想桓伊在，一笛聞吹出塞愁。"]'),
('34230058-6ff4-4ec3-b248-67e005ed9403','潤州二首 二','杜牧','唐','唐诗','tang','','[]','謝眺詩中佳麗地，夫差傳裏水犀軍。',64,'全唐诗/poet.tang.28000.json','["謝眺詩中佳麗地，夫差傳裏水犀軍。", "城高鐵甕橫強弩，柳暗朱樓多夢雲。", "畫角愛飄江北去，釣歌長向月中聞。", "揚州塵土試回首，不惜千金借與君。"]'),
('48c6fee4-fc95-4b0e-8107-6ec225e1b79d','題揚州禪智寺','杜牧','唐','唐诗','tang','','[]','雨過一蟬噪，飄蕭松桂秋。',48,'全唐诗/poet.tang.28000.json','["雨過一蟬噪，飄蕭松桂秋。", "青苔滿階砌，白鳥故遲留。", "暮靄生深樹，斜陽下小樓。", "誰知竹西路，歌吹是揚州。"]'),
('32dad2e8-0db2-4828-8d23-9dbb828bab62','西江懷古','杜牧','唐','唐诗','tang','','[]','上吞巴漢控瀟湘，怒似連山淨鏡光。',64,'全唐诗/poet.tang.28000.json','["上吞巴漢控瀟湘，怒似連山淨鏡光。", "魏帝縫囊真戲劇，苻堅投箠更荒唐。", "千秋釣艇歌明月，萬里沙鷗弄夕陽。", "範蠡清塵何寂寞，好風唯屬往來商。"]'),
('40382e0d-b922-4c98-8ece-aa19d5185786','江南懷古','杜牧','唐','唐诗','tang','','[]','車書混一業無窮，井邑山川今古同。',32,'全唐诗/poet.tang.28000.json','["車書混一業無窮，井邑山川今古同。", "戊辰年向金陵過，惆悵閑吟憶庾公。"]'),
('b1a23dad-694c-41a0-82b7-6a0ddde6d246','江南春絕句','杜牧','唐','唐诗','tang','','["\u6625", "\u5c71\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u5bfa\u5e99", "\u6625\u5929"]','千里鶯啼綠映江，水村山郭酒旗風。',32,'全唐诗/poet.tang.28000.json','["千里鶯啼綠映江，水村山郭酒旗風。", "南朝四百八十寺，多少樓臺煙雨中。"]'),
('0b701d26-ca76-4bef-baa6-0498963a716c','將赴宣州留題揚州禪智寺','杜牧','唐','唐诗','tang','','[]','故里溪頭松柏雙，來時盡日倚松窓。',32,'全唐诗/poet.tang.28000.json','["故里溪頭松柏雙，來時盡日倚松窓。", "杜陵隋苑已絕國，秋晚南遊更渡江。"]'),
('fd8f10d0-5751-4610-a901-550e74fb161b','題宣州開元寺水閣閣下宛溪夾溪居人','杜牧','唐','唐诗','tang','','[]','六朝文物草連空，天淡雲閑今古同。',64,'全唐诗/poet.tang.28000.json','["六朝文物草連空，天淡雲閑今古同。", "鳥去鳥來山色裏，人歌人哭水聲中。", "深秋簾幕千家雨，落日樓臺一笛風。", "惆悵無因見范蠡，參差煙樹五湖東。"]'),
('a3e5a592-dc26-4cc9-a310-525f32b195f6','宣州送裴坦判官往舒州時牧欲赴官歸京','杜牧','唐','唐诗','tang','','["\u4e5d\u534e\u5c71", "\u6292\u60c5", "\u9001\u522b", "\u5199\u666f"]','日暖泥融雪半銷，行人芳草馬聲驕。',64,'全唐诗/poet.tang.28000.json','["日暖泥融雪半銷，行人芳草馬聲驕。", "九華山路雲遮寺，清弋江村柳拂橋。", "君意如鴻高的的，我心懸斾正搖搖。", "同來不得同歸去，故國逢春一寂寥。"]'),
('12781143-afe6-4a27-83bb-20307ff23ef7','句溪夏日送盧霈秀才歸王屋山將欲赴舉','杜牧','唐','唐诗','tang','','[]','野店正紛泊，繭蠶初引絲。',48,'全唐诗/poet.tang.28000.json','["野店正紛泊，繭蠶初引絲。", "行人碧溪渡，繫馬綠楊枝。", "苒苒跡始去，悠悠心所期。", "秋山念君別，惆悵桂花時。"]'),
('90d5325d-54e6-4dd0-a0e0-94a6fbb5eb57','自宣城赴官上京','杜牧','唐','唐诗','tang','','[]','瀟灑江湖十過秋，酒杯無日不淹留。',64,'全唐诗/poet.tang.28000.json','["瀟灑江湖十過秋，酒杯無日不淹留。", "謝公城畔溪驚夢，蘇小門前柳拂頭。", "千里雲山何處好，幾人襟韻一生休。", "塵冠挂却知閑事，終擬蹉跎訪舊遊。"]'),
('e85a9e02-bf6d-45e8-b409-34d494901c16','春末題池州弄水亭','杜牧','唐','唐诗','tang','','[]','使君四十四，兩佩左銅魚。',96,'全唐诗/poet.tang.28000.json','["使君四十四，兩佩左銅魚。", "爲吏非循吏，論書讀底書。", "晚花紅豔靜，高樹綠陰初。", "亭宇清無比，溪山畫不如。", "嘉賓能嘯詠，宮妓巧粧梳。", "逐日愁皆碎，隨時醉有餘。", "偃須求五鼎，陶秪愛吾廬。", "趣向人皆異，賢豪莫笑渠。"]'),
('3aa3cf45-b634-4721-8c60-74b843904b43','登池州九峰樓寄張祜','杜牧','唐','唐诗','tang','','[]','百感中來不自由，角聲孤起夕陽樓。',64,'全唐诗/poet.tang.28000.json','["百感中來不自由，角聲孤起夕陽樓。", "碧山終日思無盡，芳草何年恨即休。", "睫在眼前長不見，道非身外更何求。", "誰人得似張公子，千首詩輕萬戶侯。"]'),
('6d24827d-f7c1-4b16-ba8b-1f3a84cbd455','齊安郡晚秋','杜牧','唐','唐诗','tang','','["\u79cb\u5929", "\u5b64\u72ec", "\u6000\u53e4"]','柳岸風來影漸疎，使君家似野人居。',64,'全唐诗/poet.tang.28000.json','["柳岸風來影漸疎，使君家似野人居。", "雲容水態還堪賞，嘯志歌懷亦自如。", "雨暗殘燈碁散後，酒醒孤枕鴈來初。", "可憐赤壁爭雄渡，唯有蓑翁坐釣魚。"]'),
('ea5ac55c-1d02-43f9-a411-da4255d3c30f','九日齊安登高','杜牧','唐','唐诗','tang','','["\u8282\u65e5", "\u91cd\u9633\u8282", "\u91cd\u9633"]','江涵秋影鴈初飛，與客攜壺上翠微。',64,'全唐诗/poet.tang.28000.json','["江涵秋影鴈初飛，與客攜壺上翠微。", "塵世難逢開口笑，菊花須插滿頭歸。", "但將酩酊酬佳節，不用登臨歎落暉。", "古往今來只如此，牛山何必淚霑衣。"]'),
('ecd7e71b-cfeb-401a-9834-e971a6afc54e','池州春送前進士蒯希逸','杜牧','唐','唐诗','tang','','[]','芳草復芳草，斷腸還斷腸。',48,'全唐诗/poet.tang.28000.json','["芳草復芳草，斷腸還斷腸。", "自然堪下淚，何必更殘陽。", "楚岸千萬里，燕鴻三兩行。", "有家歸不得，況舉別君觴。"]'),
('0ba5ff8d-f653-4c16-ba3c-476a101f7d30','齊安郡中偶題二首 一','杜牧','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','兩竿落日溪橋上，半縷輕煙柳影中。',32,'全唐诗/poet.tang.28000.json','["兩竿落日溪橋上，半縷輕煙柳影中。", "多少綠荷相倚恨，一時回首背西風。"]'),
('a979e4fd-0abe-4078-9f0c-a5a58b63fd80','齊安郡中偶題二首 二','杜牧','唐','唐诗','tang','','[]','秋聲無不攪離心，夢澤蒹葭楚雨深。',32,'全唐诗/poet.tang.28000.json','["秋聲無不攪離心，夢澤蒹葭楚雨深。", "自滴階前大梧葉，干君何事動哀吟。"]'),
('c7025f2b-f037-447d-9cbf-444588fd4934','齊安郡後池絕句','杜牧','唐','唐诗','tang','','["\u5199\u666f", "\u590f\u5929", "\u6292\u60c5"]','菱透浮萍綠錦池，夏鶯千囀弄薔薇。',32,'全唐诗/poet.tang.28000.json','["菱透浮萍綠錦池，夏鶯千囀弄薔薇。", "盡日無人看微雨，鴛鴦相對浴紅衣。"]'),
('51793720-6e73-4dc2-b4ad-e20b4439b612','題齊安城樓','杜牧','唐','唐诗','tang','','["\u601d\u4e61"]','嗚咽江樓角一聲，微陽瀲瀲落寒汀。',32,'全唐诗/poet.tang.28000.json','["嗚咽江樓角一聲，微陽瀲瀲落寒汀。", "不用憑闌苦回首，故鄉七十五長亭。"]'),
('be60d3de-6077-4525-aafc-bcaaee8e7a79','池州李使君沒後十一日處州新命始到後見歸妓感而成詩','杜牧','唐','唐诗','tang','','[]','縉雲新命詔初行，纔是孤魂壽器成。',64,'全唐诗/poet.tang.28000.json','["縉雲新命詔初行，纔是孤魂壽器成。", "黃壤不知新雨露，粉書空換舊銘旌。", "巨卿哭處雲空斷，阿騖歸來月正明。", "多少四年遺愛事，鄉閭生子李爲名。"]'),
('2ba882ca-87ba-4f85-840f-999b3ae3563b','見劉秀才與池州妓別','杜牧','唐','唐诗','tang','','[]','遠風南浦萬重波，未似生離別恨多。',64,'全唐诗/poet.tang.28000.json','["遠風南浦萬重波，未似生離別恨多。", "楚管能吹柳花怨，吳姬爭唱竹枝歌。", "金釵橫處綠雲墮，玉筯凝時紅粉和。", "待得枚臯相見日，自應粧鏡笑蹉跎。"]'),
('9dc42ceb-2ad5-4fd4-a3ec-fb7066096802','池州廢林泉寺','杜牧','唐','唐诗','tang','','[]','廢寺林溪上，頹垣倚亂峰。',36,'全唐诗/poet.tang.28000.json','["廢寺林溪上，頹垣倚亂峰。", "看棲歸樹鳥，猶想過山鐘。", "石路尋僧去，此生應不逢。"]'),
('2a9d70a4-570b-4972-b7c1-e4bd395ae81b','憶齊安郡','杜牧','唐','唐诗','tang','','[]','平生睡足處，雲夢澤南州。',48,'全唐诗/poet.tang.28000.json','["平生睡足處，雲夢澤南州。", "一夜風欺竹，連江雨送秋。", "格卑常汩汩，力學強悠悠。", "終掉塵中手，瀟湘釣漫流。"]'),
('022a3d00-b611-43eb-a8de-0708716ce025','池州清溪','杜牧','唐','唐诗','tang','','[]','弄溪終日到黃昏，照數秋來白髮根。',32,'全唐诗/poet.tang.28000.json','["弄溪終日到黃昏，照數秋來白髮根。", "何物賴君千遍洗，筆頭塵土漸無痕。"]'),
('b86db95b-15ac-4d37-a2ec-682f9ea6fd06','遊池州林泉寺金碧洞','杜牧','唐','唐诗','tang','','[]','袖拂霜林下石稜，潺湲聲斷滿溪冰。',32,'全唐诗/poet.tang.28000.json','["袖拂霜林下石稜，潺湲聲斷滿溪冰。", "攜茶臘月遊金碧，合有文章病茂陵。"]'),
('57fcc29a-3136-4a89-b306-54bf8e30438c','即事','杜牧','唐','唐诗','tang','','[]','因思上黨三年戰，閑詠周公七月詩。',64,'全唐诗/poet.tang.28000.json','["因思上黨三年戰，閑詠周公七月詩。", "竹帛未聞書死節，丹青空見畫靈旗。", "蕭條井邑如魚尾，早晚干戈識虎皮。", "莫笑一麾東下計，滿江秋浪碧參差。"]'),
('6b237f5d-d5e7-4298-8ba1-56a2df082f8d','贈李秀才','杜牧','唐','唐诗','tang','','[]','骨清年少眼如冰，鳳羽參差五色層。',32,'全唐诗/poet.tang.28000.json','["骨清年少眼如冰，鳳羽參差五色層。", "天上麒麟時一下，人間不獨有徐陵。"]'),
('3afc8229-82f7-4ff9-a0de-5ddeb0f88631','寄李起居四韻','杜牧','唐','唐诗','tang','','[]','楚女梅簪白雪姿，前溪碧水凍醪時。',64,'全唐诗/poet.tang.28000.json','["楚女梅簪白雪姿，前溪碧水凍醪時。", "雲罍心凸知難捧，鳳管簧寒不受吹。", "南國劒眸能盼眄，侍臣香袖愛僛垂。", "自憐窮律窮途客，正怯孤燈一局碁。"]'),
('0a9216fd-4030-4bef-8072-e593ff72a1b5','題池州貴池亭','杜牧','唐','唐诗','tang','','[]','勢比凌歊宋武臺，分明百里遠帆開。',32,'全唐诗/poet.tang.28000.json','["勢比凌歊宋武臺，分明百里遠帆開。", "蜀江雪浪西江滿，強半春寒去却來。"]'),
('4cf8ea1f-34fd-4ef0-abf2-00d8bf91091c','蘭溪','杜牧','唐','唐诗','tang','','[]','蘭溪春盡碧泱泱，映水蘭花雨發香。',32,'全唐诗/poet.tang.28000.json','["蘭溪春盡碧泱泱，映水蘭花雨發香。", "楚國大夫憔悴日，應尋此路去瀟湘。"]'),
('e005cd58-79a0-440d-8626-727ce5328c29','睦州四韻','杜牧','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u5199\u666f", "\u611f\u6168", "\u4ed5\u9014"]','州在釣臺邊，溪山實可憐。',48,'全唐诗/poet.tang.28000.json','["州在釣臺邊，溪山實可憐。", "有家皆掩映，無處不潺湲。", "好樹鳴幽鳥，晴樓入野煙。", "殘春杜陵客，中酒落花前。"]'),
('2703ed11-ada5-4fa4-9904-22dd1b1821a2','秋晚早發新定','杜牧','唐','唐诗','tang','','[]','解印書千軸，重陽酒百缸。',48,'全唐诗/poet.tang.28000.json','["解印書千軸，重陽酒百缸。", "涼風滿紅樹，曉月下秋江。", "巖壑會歸去，塵埃終不降。", "懸纓未敢濯，嚴瀨碧淙淙。"]'),
('6e3688e7-0bc4-4297-9b41-98b3f014a88c','除官歸京睦州雨霽','杜牧','唐','唐诗','tang','','[]','秋半吳天霽，清凝萬里光。',120,'全唐诗/poet.tang.28000.json','["秋半吳天霽，清凝萬里光。", "水聲侵笑語，嵐翠撲衣裳。", "遠樹疑羅帳，孤雲認粉囊。", "溪山侵兩越，時節到重陽。", "顧我能甘賤，無由得自強。", "悮曾公觸尾，不敢夜循墻。", "豈意籠飛鳥，還爲錦帳郎。", "網今開傅燮，書舊識黃香。", "姹女真虛語，飢兒欲一行。", "淺深須揭厲，休更學張綱。"]'),
('9a7216cc-6181-4bd8-a2e7-5d68d6edc287','夜泊桐廬先寄蘇臺盧郎中','杜牧','唐','唐诗','tang','','[]','水檻桐廬館，歸舟繫石根。',36,'全唐诗/poet.tang.28000.json','["水檻桐廬館，歸舟繫石根。", "笛吹孤戌月，犬吠隔溪村。", "十載違清裁，幽懷未一論。"]'),
('906890ad-278f-4252-be3f-405b809a4178','新轉南曹未敘朝散初秋暑退出守吳興書此篇以自見志','杜牧','唐','唐诗','tang','','[]','捧詔汀洲去，全家羽翼飛。',96,'全唐诗/poet.tang.28000.json','["捧詔汀洲去，全家羽翼飛。", "喜拋新錦帳，榮借舊朱衣。", "且免材爲累，何妨拙有機。", "宋株聊自守，魯酒怕旁圍。", "清尚寧無素，光陰亦未晞。", "一盃寬幕席，五字弄珠璣。", "越浦黃柑嫩，吳溪紫蟹肥。", "平生江海志，佩得左魚歸。"]'),
('c1bd16df-e065-48cd-855a-25d67663cdfb','題白蘋洲','杜牧','唐','唐诗','tang','','[]','山鳥飛紅帶，亭薇拆紫花。',48,'全唐诗/poet.tang.28000.json','["山鳥飛紅帶，亭薇拆紫花。", "溪光初透徹，秋色正清華。", "靜處知生樂，喧中見死誇。", "無多珪組累，終不負煙霞。"]'),
('5e19012a-a57f-4e53-ae4f-40a3b4303db2','題茶山','杜牧','唐','唐诗','tang','','[]','山實東吳秀，茶稱瑞草魁。',168,'全唐诗/poet.tang.28000.json','["山實東吳秀，茶稱瑞草魁。", "剖符雖俗吏，修貢亦仙才。", "溪盡停蠻櫂，旗張卓翠苔。", "柳村穿窈窕，松澗渡喧豗。", "等級雲峰峻，寬平洞府開。", "拂天聞笑語，特地見樓臺。", "泉嫩黃金湧，牙香紫璧裁。", "拜章期沃日，輕騎疾奔雷。", "舞袖嵐侵澗，歌聲谷答回。", "磬音藏葉鳥，雪豔照潭梅。", "好是全家到，兼爲奉詔來。", "樹陰香作帳，花徑落成堆。", "景物殘三月，登臨愴一盃。", "重遊難自尅，俛首入塵埃。"]'),
('da21588d-5e04-4707-a084-696ba5120669','茶山下作','杜牧','唐','唐诗','tang','','[]','春風最窈窕，日曉柳村西。',48,'全唐诗/poet.tang.28000.json','["春風最窈窕，日曉柳村西。", "嬌雲光占岫，健水鳴分溪。", "燎巖野花遠，戛瑟幽鳥啼。", "把酒坐芳草，亦有佳人攜。"]'),
('f540523d-6bde-433c-87d5-e1929f04bcbd','入茶山下題水口草市絕句','杜牧','唐','唐诗','tang','','[]','倚溪侵嶺多高樹，誇酒書旗有小樓。',32,'全唐诗/poet.tang.28000.json','["倚溪侵嶺多高樹，誇酒書旗有小樓。", "驚起鴛鴦豈無恨，一雙飛去却回頭。"]'),
('7c5abe03-8a94-43d1-b340-e25aa1f83fc6','春日茶山病不飲酒因呈賓客','杜牧','唐','唐诗','tang','','[]','笙歌登畫船，十日清明前。',48,'全唐诗/poet.tang.28000.json','["笙歌登畫船，十日清明前。", "山秀白雲膩，溪光紅粉鮮。", "欲開未開花，半陰半晴天。", "誰知病太守，猶得作茶仙。"]'),
('01746278-f392-4ef2-b743-f04920747aec','不飲贈官妓','杜牧','唐','唐诗','tang','','[]','芳草正得意，汀洲日欲西。',48,'全唐诗/poet.tang.28000.json','["芳草正得意，汀洲日欲西。", "無端千樹柳，更拂一條溪。", "幾朵梅堪折，何人手好攜。", "誰憐佳麗地，春恨却悽悽。"]'),
('d3adfc13-1050-4049-8cb4-4355e2b0256f','早春贈軍事薛判官','杜牧','唐','唐诗','tang','','[]','雪後新正半，春來四刻長。',48,'全唐诗/poet.tang.28000.json','["雪後新正半，春來四刻長。", "晴梅朱粉豔，嫩水碧羅光。", "弦管開雙調，花鈿坐兩行。", "唯君莫惜醉，認取少年場。"]'),
('44f95de1-e861-45ce-af4e-cc4443bb5d7c','代吳興妓春初寄薛軍事','杜牧','唐','唐诗','tang','','[]','霧冷侵紅粉，春陰撲翠鈿。',48,'全唐诗/poet.tang.28000.json','["霧冷侵紅粉，春陰撲翠鈿。", "自悲臨曉鏡，誰與惜流年。", "柳暗霏微雨，花愁黯淡天。", "金釵有幾隻，抽當酒家錢。"]'),
('b3407eba-d066-4e2e-903f-1af94e886ab7','八月十二日得替後移居霅溪館因題長句四韻','杜牧','唐','唐诗','tang','','[]','萬家相慶喜秋成，處處樓臺歌板聲。',64,'全唐诗/poet.tang.28000.json','["萬家相慶喜秋成，處處樓臺歌板聲。", "千歲鶴歸猶有恨，一年人住豈無情。", "夜涼溪館留僧話，風定蘇潭看月生。", "景物登臨閑始見，願爲閑客此閑行。"]'),
('dadb8a20-904f-451c-a2ff-90add19d8976','初冬夜飲','杜牧','唐','唐诗','tang','','[]','淮陽多病偶求歡，客袖侵霜與燭盤。',32,'全唐诗/poet.tang.28000.json','["淮陽多病偶求歡，客袖侵霜與燭盤。", "砌下梨花一堆雪，明年誰此凭闌干。"]'),
('767881fd-3732-4255-a091-2408754395d1','栽竹','杜牧','唐','唐诗','tang','','[]','本因遮日種，却似爲溪移。',48,'全唐诗/poet.tang.28000.json','["本因遮日種，却似爲溪移。", "歷歷羽林影，疎疎煙露姿。", "蕭騷寒雨夜，敲劼晚風時。", "故國何年到，塵冠挂一枝。"]'),
('273c54cd-db27-4ede-9b96-4412483aab04','梅','杜牧','唐','唐诗','tang','','["\u6885\u82b1"]','輕盈照溪水，掩斂下瑤臺。',48,'全唐诗/poet.tang.28000.json','["輕盈照溪水，掩斂下瑤臺。", "妬雪聊相比，欺春不逐來。", "偶同佳客見，似爲凍醪開。", "若在秦樓畔，堪爲弄玉媒。"]'),
('1cbf46c5-1136-49a5-954d-22408a0d96df','山石榴','杜牧','唐','唐诗','tang','','[]','似火山榴映小山，繁中能薄豔中閑。',32,'全唐诗/poet.tang.28000.json','["似火山榴映小山，繁中能薄豔中閑。", "一朵佳人玉釵上，秪疑燒却翠雲鬟。"]'),
('cc24cf38-f6e8-456b-9ca0-5deaf9ca640e','柳長句','杜牧','唐','唐诗','tang','','[]','日落水流西復東，春光不盡柳何窮。',64,'全唐诗/poet.tang.28000.json','["日落水流西復東，春光不盡柳何窮。", "巫娥廟裏低含雨，宋玉宅前斜帶風。", "不嫌榆莢共爭翠，深與桃花相映紅。", "灞上漢南千萬樹，幾人遊宦別離中。"]'),
('f3e578a1-2ab6-4397-b2ff-a9d27f8568a3','隋堤柳','杜牧','唐','唐诗','tang','','[]','夾岸垂楊三百里，秪應圖畫最相宜。',32,'全唐诗/poet.tang.28000.json','["夾岸垂楊三百里，秪應圖畫最相宜。", "自嫌流落西歸疾，不見東風二月時。"]'),
('00430c53-2891-4917-ba7c-5cccc0dcf9b0','柳絕句','杜牧','唐','唐诗','tang','','[]','數樹新開翠影齊，倚風情態被春迷。',32,'全唐诗/poet.tang.28000.json','["數樹新開翠影齊，倚風情態被春迷。", "依依故國樊川恨，半掩村橋半掩溪。"]'),
('ab6eb2e3-96e6-49bc-ad2c-c70fe0fe889d','獨柳','杜牧','唐','唐诗','tang','','[]','含煙一株柳，拂地搖風久。',24,'全唐诗/poet.tang.28000.json','["含煙一株柳，拂地搖風久。", "佳人不忍折，悵望回纖手。"]'),
('9ee69d68-c50d-4a8e-9125-9ce8b90e38de','早鴈','杜牧','唐','唐诗','tang','','["\u6028\u523a", "\u548f\u7269", "\u6292\u6000", "\u5199\u9e1f", "\u548f\u7269\u8bd7", "\u9e1f"]','金河秋半虜弦開，雲外驚飛四散哀。',64,'全唐诗/poet.tang.28000.json','["金河秋半虜弦開，雲外驚飛四散哀。", "仙掌月明孤影過，長門燈暗數聲來。", "須知胡騎紛紛在，豈逐春風一一回。", "莫厭瀟湘少人處，水多菰米岸莓苔。"]'),
('b755806f-5908-4013-9635-f35b5e4d7514','鵁鶄','杜牧','唐','唐诗','tang','','[]','芝莖抽紺趾，清唳擲金梭。',48,'全唐诗/poet.tang.28000.json','["芝莖抽紺趾，清唳擲金梭。", "日翅閑張錦，風池去罥羅。", "靜眠依翠荇，暖戲折高荷。", "山陰豈無爾，繭字換羣鵝。"]'),
('a9bff166-bad3-4e2f-8e9a-3b3dab4c99cd','鸚鵡','杜牧','唐','唐诗','tang','','[]','華堂日漸高，雕檻繫紅縚。',48,'全唐诗/poet.tang.28000.json','["華堂日漸高，雕檻繫紅縚。", "故國隴山樹，美人金剪刀。", "避籠交翠尾，罅嘴靜新毛。", "不念三緘事，世途皆爾曹。"]'),
('d77c98b5-c087-448d-aa25-0abf916df46b','鶴','杜牧','唐','唐诗','tang','','[]','清音迎曉月，愁思立寒蒲。',48,'全唐诗/poet.tang.28000.json','["清音迎曉月，愁思立寒蒲。", "丹頂西施頰，霜毛四皓鬚。", "碧雲行止躁，白鷺性靈麤。", "終日無群伴，溪邊弔影孤。"]'),
('79dfd992-325b-4f0d-88fb-41af329b14c9','鴉','杜牧','唐','唐诗','tang','','[]','擾擾復翻翻，黃昏颺冷煙。',48,'全唐诗/poet.tang.28000.json','["擾擾復翻翻，黃昏颺冷煙。", "毛欺皇后髪，聲感楚姬弦。", "蔓壘盤風下，霜林接翅眠。", "秪如西旅樣，頭白豈無緣。"]'),
('db60ce28-affd-4810-90aa-0937eba12898','鷺鷥','杜牧','唐','唐诗','tang','','[]','雪衣雪髪青玉觜，羣捕魚兒溪影中。',32,'全唐诗/poet.tang.28000.json','["雪衣雪髪青玉觜，羣捕魚兒溪影中。", "驚飛遠映碧山去，一樹梨花落晚風。"]'),
('7ae31638-4d94-433c-94f4-dbe0a936dd67','村舍燕','杜牧','唐','唐诗','tang','','[]','漢宮一百四十五，多下珠簾閉瑣窓。',32,'全唐诗/poet.tang.28000.json','["漢宮一百四十五，多下珠簾閉瑣窓。", "何處營巢夏將半，茅簷煙裏語雙雙。"]'),
('3350ad48-ab27-410c-a204-4e223a6a457a','歸燕','杜牧','唐','唐诗','tang','','[]','畫堂歌舞喧喧地，社去社來人不看。',32,'全唐诗/poet.tang.28000.json','["畫堂歌舞喧喧地，社去社來人不看。", "長是江樓使君伴，黃昏猶待倚闌干。"]'),
('511e17d0-14fe-4303-8bca-c2544eb84a25','傷猨','杜牧','唐','唐诗','tang','','[]','獨折南園一朵梅，重尋幽坎已生苔。',32,'全唐诗/poet.tang.28000.json','["獨折南園一朵梅，重尋幽坎已生苔。", "無端晚吹驚高樹，似裊長枝欲下來。"]'),
('fc695811-2ff0-4ea9-a0ed-c593fc3a218f','還俗老僧','杜牧','唐','唐诗','tang','','[]','雪髪不長寸，秋寒力更微。',36,'全唐诗/poet.tang.28000.json','["雪髪不長寸，秋寒力更微。", "獨尋一徑葉，猶挈衲殘衣。", "日暮千峰裏，不知何處歸。"]'),
('9b8eb5bd-f6d7-4629-92c7-12d73573c0d1','斫竹','杜牧','唐','唐诗','tang','','[]','寺廢竹色死，宦家寧爾留。',24,'全唐诗/poet.tang.28000.json','["寺廢竹色死，宦家寧爾留。", "霜根漸隨斧，風玉尚敲秋。"]'),
('95bf4642-3062-48e0-a1fd-cc8505d63998','將赴湖州留題亭菊','杜牧','唐','唐诗','tang','','[]','陶菊手自種，楚蘭心有期。',24,'全唐诗/poet.tang.28000.json','["陶菊手自種，楚蘭心有期。", "遙知渡江日，正是擷芳時。"]'),
('aeb383ee-1d05-4d4c-a662-dcb83fb07284','折菊','杜牧','唐','唐诗','tang','','[]','籬東菊徑深，折得自孤吟。',24,'全唐诗/poet.tang.28000.json','["籬東菊徑深，折得自孤吟。", "雨中衣半濕，擁鼻自知心。"]'),
('efa43677-f926-4a14-a837-0a330c0a9fdd','雲','杜牧','唐','唐诗','tang','','[]','盡日看雲首不回，無心都大似無才。',32,'全唐诗/poet.tang.28000.json','["盡日看雲首不回，無心都大似無才。", "可憐光彩一片玉，萬里晴天何處來。"]'),
('519c3422-7504-4293-9a27-73c83c1ac1ec','醉後題僧院','杜牧','唐','唐诗','tang','','[]','離心忽忽復悽悽，雨晦傾瓶取醉泥。',32,'全唐诗/poet.tang.28000.json','["離心忽忽復悽悽，雨晦傾瓶取醉泥。", "可羨高僧共心語，一如攜穉往東西。"]'),
('e4a297e3-7f61-4691-9435-589af58c5b75','題禪院','杜牧','唐','唐诗','tang','','[]','觥船一櫂百分空，十歲青春不負公。',32,'全唐诗/poet.tang.28000.json','["觥船一櫂百分空，十歲青春不負公。", "今日鬢絲禪榻畔，茶煙輕颺落花風。"]'),
('a18f0079-46d6-4a55-ac4c-420df4b9fc92','哭李給事中敏','杜牧','唐','唐诗','tang','','[]','陽陵郭門外，陂陁丈五墳。',24,'全唐诗/poet.tang.28000.json','["陽陵郭門外，陂陁丈五墳。", "九泉如結友，茲地好埋君。"]'),
('33d6f968-bc8f-4eae-9ea8-09a8b7e0d665','黃州竹徑鬬','杜牧','唐','唐诗','tang','','[]','竹濁蟠小徑，屈折鬬蛇來。',24,'全唐诗/poet.tang.28000.json','["竹濁蟠小徑，屈折鬬蛇來。", "三年得歸去，知遶幾千回。"]'),
('f4f3ad55-7782-4654-91dd-5246a4a0eed8','題敬愛寺樓','杜牧','唐','唐诗','tang','','[]','暮景千山雪，春寒百尺樓。',24,'全唐诗/poet.tang.28000.json','["暮景千山雪，春寒百尺樓。", "獨登還獨下，誰會我悠悠。"]'),
('ad0752ec-4d39-4e7a-b4a0-5316996c1c81','送劉秀才歸江陵','杜牧','唐','唐诗','tang','','[]','綵服鮮華覲渚宮，鱸魚新熟別江東。',64,'全唐诗/poet.tang.28000.json','["綵服鮮華覲渚宮，鱸魚新熟別江東。", "劉郎浦夜侵船月，宋玉亭春弄袖風。", "落落精神終有立，飄飄才思杳無窮。", "誰人世上爲金口，借取明時一薦雄。"]'),
('b31e0478-a723-4a99-aaa9-4e645bd2604a','見吳秀才與池妓別因成絕句','杜牧','唐','唐诗','tang','','[]','紅燭短時羌笛怨，清歌咽處蜀弦高。',32,'全唐诗/poet.tang.28000.json','["紅燭短時羌笛怨，清歌咽處蜀弦高。", "萬里分飛兩行淚，滿江寒雨正蕭騷。"]'),
('2090e1eb-ae03-4fc6-a227-2d96318191d5','湖南正初招李郢秀才','杜牧','唐','唐诗','tang','','[]','行樂及時時已晚，對酒當歌歌不成。',64,'全唐诗/poet.tang.28000.json','["行樂及時時已晚，對酒當歌歌不成。", "千里暮山重疊翠，一溪寒水淺深情。", "高人以飲爲忙事，浮世除詩盡強名。", "看著白蘋芽欲吐，雪舟相訪勝閑行。"]'),
('23a44d51-2452-4472-924f-20bd7f7b910e','贈朱道靈','杜牧','唐','唐诗','tang','','[]','劉根丹篆三千字，郭璞青囊兩卷書。',32,'全唐诗/poet.tang.28000.json','["劉根丹篆三千字，郭璞青囊兩卷書。", "牛渚磯南謝山北，白雲深處有巖居。"]'),
('8092ed18-a644-4244-b6c0-7fe47070d8eb','屏風絕句','杜牧','唐','唐诗','tang','','[]','屏風周昉畫纖腰，歲久丹青色半銷。',32,'全唐诗/poet.tang.28000.json','["屏風周昉畫纖腰，歲久丹青色半銷。", "斜倚玉窓鸞髪女，拂塵猶自妬嬌嬈。"]'),
('d759ee6d-b24e-4fc3-8675-7c33e25f5ced','哭韓綽','杜牧','唐','唐诗','tang','','[]','平明送葬上都門，紼翣交橫逐去魂。',32,'全唐诗/poet.tang.28000.json','["平明送葬上都門，紼翣交橫逐去魂。", "歸來冷笑悲身事，喚婦呼兒索酒盆。"]'),
('4e6221b3-e5bf-40ac-855b-d9625beb5364','新定途中','杜牧','唐','唐诗','tang','','[]','無端偶效張文紀，下杜鄉園別五秋。',32,'全唐诗/poet.tang.28000.json','["無端偶效張文紀，下杜鄉園別五秋。", "重過江南更千里，萬山深處一孤舟。"]'),
('6c40fa2c-8faf-421d-be74-8b9da907fc55','題新定八松院小石','杜牧','唐','唐诗','tang','','[]','雨滴珠璣碎，苔生紫翠重。',24,'全唐诗/poet.tang.28000.json','["雨滴珠璣碎，苔生紫翠重。", "故關何日到，且看小三峰。"]'),
('bfbe8c22-538d-45df-8fc6-07d527e6bc8b','往年隨故府吳興公夜泊蕪湖口今赴官西去再宿蕪湖感舊傷懷因成十六韻','杜牧','唐','唐诗','tang','','[]','南指陵陽路，東流似昔年。',192,'全唐诗/poet.tang.28000.json','["南指陵陽路，東流似昔年。", "重恩山未答，雙鬢雪飄然。", "數仞慙投跡，群公愧拍肩。", "駑駘蒙錦繡，塵土浴潺湲。", "郭隗黃金峻，虞卿白璧鮮。", "貔貅環玉帳，鸚鵡破蠻牋。", "極浦沈碑會，秋花落帽筵。", "旌旗明迥野，冠珮照神仙。", "籌畫言何補，優容道實全。", "謳謠人撲地，雞犬樹連天。", "紫鳳超如電，青襟散似煙。", "蒼生未經濟，墳草已芊綿。", "往事惟沙月，孤燈但客船。", "峴山雲影畔，棠葉水聲前。", "故國還歸去，浮生亦可憐。", "高歌一曲淚，明日夕陽邊。"]'),
('1bd8c40c-eac0-46ac-969e-a9dcd3382323','懷鍾陵舊遊四首 一','杜牧','唐','唐诗','tang','','[]','一謁征南最少年，虞卿雙璧截肪鮮。',64,'全唐诗/poet.tang.28000.json','["一謁征南最少年，虞卿雙璧截肪鮮。", "歌謠千里春長暖，絲管高臺月正圓。", "玉帳軍籌羅俊彥，絳帷環珮立神仙。", "陸公餘德機雲在，如我酬恩合執鞭。"]'),
('86500cf0-f0a0-4a79-893e-6bedd71460ee','懷鍾陵舊遊四首 二','杜牧','唐','唐诗','tang','','[]','滕閣中春綺席開，柘枝蠻鼓殷晴雷。',64,'全唐诗/poet.tang.28000.json','["滕閣中春綺席開，柘枝蠻鼓殷晴雷。", "垂樓萬幕青雲合，破浪千帆陣馬來。", "未掘雙龍牛斗氣，高懸一榻棟梁材。", "連巴控越知何事，珠翠沈檀處處堆。"]'),
('a36dd569-3de9-454d-8ea2-40cda1c009d4','懷鍾陵舊遊四首 三','杜牧','唐','唐诗','tang','','[]','十頃平湖堤柳合，岸秋蘭芷綠纖纖。',72,'全唐诗/poet.tang.28000.json','["十頃平湖堤柳合，岸秋蘭芷綠纖纖。", "一聲明月採蓮女，四面朱樓卷畫簾。", "白鷺煙紛光的的，微漣風定翠{氵忄占}{氵忄占}。", "斜輝更落西山影，千步虹橋氣象兼。"]'),
('f57d3221-b9aa-49e5-9c50-21cc46215c8c','懷鍾陵舊遊四首 四','杜牧','唐','唐诗','tang','','[]','控壓平江十萬家，秋來江靜鏡新磨。',64,'全唐诗/poet.tang.28000.json','["控壓平江十萬家，秋來江靜鏡新磨。", "城頭晚鼓雷霆後，橋上遊人笑語多。", "日落汀痕千里色，月當樓午一聲歌。", "昔年行樂穠桃畔，醉與龍沙揀蜀羅。"]'),
('63a80b35-d8ea-48ef-af36-7810c2d82fe0','臺城曲二首 一','杜牧','唐','唐诗','tang','','[]','整整復斜斜，隨旗簇晚沙。',36,'全唐诗/poet.tang.28000.json','["整整復斜斜，隨旗簇晚沙。", "門外韓擒虎，樓頭張麗華。", "誰憐容足地，却羨井中鼃。"]'),
('2059adb6-6df8-4339-aaa6-19918cc6f9aa','臺城曲二首 二','杜牧','唐','唐诗','tang','','[]','王頒兵勢急，鼓下坐蠻奴。',36,'全唐诗/poet.tang.28000.json','["王頒兵勢急，鼓下坐蠻奴。", "瀲灩倪塘水，叉牙出骨鬚。", "乾蘆一炬火，回首是平蕪。"]'),
('9f2c9620-79c0-4929-adc4-8d22a8f400fc','江上雨寄崔碣','杜牧','唐','唐诗','tang','','[]','春半平江雨，圓文破蜀羅。',48,'全唐诗/poet.tang.28000.json','["春半平江雨，圓文破蜀羅。", "聲眠篷底客，寒濕釣來蓑。", "暗澹遮山遠，空濛著柳多。", "此時懷舊恨，相望意如何。"]'),
('6161b416-2cc1-482e-87bf-824be6bc84a0','罷鍾陵幕吏十三年來泊湓浦感舊爲詩','杜牧','唐','唐诗','tang','','[]','青梅雨中熟，檣倚酒旗邊。',48,'全唐诗/poet.tang.28000.json','["青梅雨中熟，檣倚酒旗邊。", "故國殘春夢，孤舟一褐眠。", "搖搖遠堤柳，暗暗十程煙。", "南奏鐘陵道，無因似昔年。"]'),
('afc80a09-19c1-466c-aeda-9a90b0b0ff3f','商山麻澗','杜牧','唐','唐诗','tang','','["\u751f\u6d3b", "\u5199\u666f", "\u7530\u56ed"]','雲光嵐彩四面合，柔柔垂柳十餘家。',64,'全唐诗/poet.tang.28000.json','["雲光嵐彩四面合，柔柔垂柳十餘家。", "雉飛鹿過芳草遠，牛巷雞塒春日斜。", "秀眉老父對罇酒，蒨袖女兒簪野花。", "征車自念塵土計，惆悵溪邊書細沙。"]'),
('78fb5437-65d1-4935-9c9f-c39965efad1d','商山富水驛','杜牧','唐','唐诗','tang','','[]','益戇由來未覺賢，終須南去弔湘川。',64,'全唐诗/poet.tang.28000.json','["益戇由來未覺賢，終須南去弔湘川。", "當時物議朱雲小，後代聲華白日懸。", "邪佞每思當面唾，清貧長欠一杯錢。", "驛名不合輕移改，留警朝天者惕然。"]'),
('aabd4bc3-4975-4d76-a91a-88b324791261','丹水','杜牧','唐','唐诗','tang','','[]','何事苦縈迴，離腸不自裁。',48,'全唐诗/poet.tang.28000.json','["何事苦縈迴，離腸不自裁。", "恨身隨夢去，春態逐雲來。", "沈定藍光徹，喧盤粉浪開。", "翠巖三百尺，誰作子陵臺。"]'),
('71613d6e-3c46-4916-91b1-2f2bdb65cc30','題武關','杜牧','唐','唐诗','tang','','["\u540a\u53e4\u4f24\u4eca", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','碧溪留我武關東，一笑懷王跡自窮。',64,'全唐诗/poet.tang.28000.json','["碧溪留我武關東，一笑懷王跡自窮。", "鄭袖嬌嬈酣似醉，屈原憔悴去如蓬。", "山墻谷塹依然在，弱吐強吞盡已空。", "今日聖神家四海，戌旗長卷夕陽中。"]'),
('8e030eda-3a52-46ea-ad33-40137058f623','除官赴闕商山道中絕句','杜牧','唐','唐诗','tang','','[]','水疊鳴珂樹如帳，長楊春殿九門珂。',32,'全唐诗/poet.tang.28000.json','["水疊鳴珂樹如帳，長楊春殿九門珂。", "我來惆悵不自決，欲去欲住終如何。"]'),
('0bae49af-8404-43ad-9365-8fba6e888bed','漢江','杜牧','唐','唐诗','tang','','[]','溶溶漾漾白鷗飛，綠淨春深好染衣。',32,'全唐诗/poet.tang.28000.json','["溶溶漾漾白鷗飛，綠淨春深好染衣。", "南去北來人自老，夕陽長送釣船歸。"]'),
('723e51b8-cea0-4ce3-adac-f20fda3b54d5','襄陽雪夜感懷','杜牧','唐','唐诗','tang','','[]','往事起獨念，飄然自不勝。',48,'全唐诗/poet.tang.28000.json','["往事起獨念，飄然自不勝。", "前灘急夜響，密雪映寒燈。", "的的三年夢，迢迢一綫緪。", "明朝楚山上，莫上最高層。"]'),
('f18d8018-cb67-494d-9b0e-831b3558756a','詠歌聖德遠懷天寶因題關亭長句四韻','杜牧','唐','唐诗','tang','','[]','聖敬文思業太平，海寰天下唱歌行。',64,'全唐诗/poet.tang.28000.json','["聖敬文思業太平，海寰天下唱歌行。", "秋來氣勢洪河壯，霜後精神泰華獰。", "廣德者強朝萬國，用賢無敵是長城。", "君王若悟治安論，安史何人敢弄兵。"]'),
('efab3f0d-4e53-4277-b4cd-9fd3b89019a4','途中作','杜牧','唐','唐诗','tang','','[]','綠樹南陽道，千峰勢遠隨。',36,'全唐诗/poet.tang.28000.json','["綠樹南陽道，千峰勢遠隨。", "碧溪風澹態，芳樹雨餘姿。", "野渡雲初暖，征人袖半垂。"]'),
('b809e73b-f524-4922-8e14-9fe0c0348268','重到襄陽哭亡友韋壽朋','杜牧','唐','唐诗','tang','','[]','故人墳樹立秋風，伯道無兒跡更空。',32,'全唐诗/poet.tang.28000.json','["故人墳樹立秋風，伯道無兒跡更空。", "重到笙歌分散地，隔江吹笛月明中。"]'),
('7c93c162-d424-4d91-b71b-7c9b81713b8c','赤壁','杜牧','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6218\u4e89", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u5510\u8bd7\u4e09\u767e\u9996", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u8a00\u7edd\u53e5"]','折戟沈沙鐵未銷，自將磨洗認前朝。',32,'全唐诗/poet.tang.28000.json','["折戟沈沙鐵未銷，自將磨洗認前朝。", "東風不與周郎便，銅雀春深鏁二喬。"]'),
('bc64fa88-7231-45a4-acfb-20601e9d8440','雲夢澤','杜牧','唐','唐诗','tang','','[]','日旗龍斾想飄揚，一索功高縛楚王。',32,'全唐诗/poet.tang.28000.json','["日旗龍斾想飄揚，一索功高縛楚王。", "直是超然五湖客，未如終始郭汾陽。"]'),
('8ff7d3b9-9b28-4293-8fde-aae03e263d65','除官行至昭應聞友人出官因寄','杜牧','唐','唐诗','tang','','[]','賤子來千里，明公去一麾。',48,'全唐诗/poet.tang.28000.json','["賤子來千里，明公去一麾。", "可能休涕淚，豈獨感恩知。", "草木窮秋後，山川落照時。", "如何望故國，驅馬却遲遲。"]'),
('7879bd00-f62e-4030-9c0e-776e629fefdf','寄浙東韓八評事','杜牧','唐','唐诗','tang','','[]','一笑五雲溪上舟，跳丸日月十經秋。',64,'全唐诗/poet.tang.28000.json','["一笑五雲溪上舟，跳丸日月十經秋。", "鬢衰酒減欲誰泥，跡辱魂慙好自尤。", "夢寐幾回迷蛺蝶，文章應解伴牢愁。", "無窮塵土無聊事，不得清言解不休。"]'),
('8de30193-fba7-4aef-9ff9-c3726a22104d','泊秦淮','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u7231\u56fd", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u8a00\u7edd\u53e5"]','煙籠寒水月籠沙，夜泊秦淮近酒家。',32,'全唐诗/poet.tang.28000.json','["煙籠寒水月籠沙，夜泊秦淮近酒家。", "商女不知亡國恨，隔江猶唱後庭花。"]'),
('12f3e91e-1c38-487b-a645-bbf19ac943ae','秋浦途中','杜牧','唐','唐诗','tang','','["\u601d\u4e61"]','蕭蕭山路窮秋雨，淅淅溪風一岸蒲。',32,'全唐诗/poet.tang.28000.json','["蕭蕭山路窮秋雨，淅淅溪風一岸蒲。", "爲問寒沙新到雁，來時還下杜陵無。"]'),
('5029a80b-731c-43a4-a302-23920b4c64dd','題桃花夫人廟','杜牧','唐','唐诗','tang','','[]','細腰宮裏露桃新，脉脉無言度幾春。',32,'全唐诗/poet.tang.28000.json','["細腰宮裏露桃新，脉脉無言度幾春。", "至竟息亡緣底事，可憐金谷墜樓人。"]'),
('0fb652c9-c48c-4a0b-bf5a-250c2ecd52a5','初春有感寄歙州邢員外','杜牧','唐','唐诗','tang','','[]','雪漲前溪水，啼聲已繞灘。',36,'全唐诗/poet.tang.28000.json','["雪漲前溪水，啼聲已繞灘。", "梅衰未減態，春嫩不禁寒。", "跡去夢一覺，年來事百般。"]'),
('30d52eda-5bb3-4e60-847d-9cef36f891cb','書懷寄中朝往還','杜牧','唐','唐诗','tang','','[]','平生自許少塵埃，爲吏塵中勢自迴。',64,'全唐诗/poet.tang.28000.json','["平生自許少塵埃，爲吏塵中勢自迴。", "朱紱久慙官借與，白題還嘆老將來。", "須知世路難輕進，豈是君門不大開。", "霄漢幾多同學伴，可憐頭角盡卿材。"]'),
('948e4f5f-bab8-40fe-9bd6-5d0147208933','寄崔鈞','杜牧','唐','唐诗','tang','','[]','緘書報子玉，爲我謝平津。',48,'全唐诗/poet.tang.28000.json','["緘書報子玉，爲我謝平津。", "自愧掃門士，誰爲乞火人。", "詞臣陪羽獵，戰將騁騏驎。", "兩地差池恨，江汀醉送君。"]'),
('9cda8e61-fac0-4c14-ad84-72d7318dd31d','初春雨中舟次和州橫江裴使君見迎李趙二秀才同來因書四韻兼寄江南許渾先輩','杜牧','唐','唐诗','tang','','[]','芳草渡頭微雨時，萬株楊柳拂波垂。',64,'全唐诗/poet.tang.28000.json','["芳草渡頭微雨時，萬株楊柳拂波垂。", "蒲根水暖雁初浴，梅徑香寒蜂未知。", "辭客倚風吟暗淡，使君迴馬濕旌旗。", "江南仲蔚多情調，悵望春陰幾首詩。"]'),
('a9150feb-1af5-47f2-a858-4a84afec8569','和州絕句','杜牧','唐','唐诗','tang','','[]','江湖醉渡十年春，牛渚山邊六問津。',32,'全唐诗/poet.tang.28000.json','["江湖醉渡十年春，牛渚山邊六問津。", "歷陽前事知何實，高位紛紛見陷人。"]'),
('ce45b6ae-176c-44be-834e-95f1f4cc2f92','題烏江亭','杜牧','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u52b1\u5fd7", "\u548f\u53f2\u6000\u53e4"]','勝敗兵家事不期，包羞忍恥是男兒。',32,'全唐诗/poet.tang.28000.json','["勝敗兵家事不期，包羞忍恥是男兒。", "江東子弟多才俊，卷土重來未可知。"]'),
('73a0e38b-f3c6-456c-9120-79a385acbde6','題橫江館','杜牧','唐','唐诗','tang','','[]','孫家兄弟晉龍驤，馳騁功名業帝王。',32,'全唐诗/poet.tang.28000.json','["孫家兄弟晉龍驤，馳騁功名業帝王。", "至竟江山誰是主，苔磯空屬釣魚郎。"]'),
('10a4bf8c-caed-42a0-8ae2-9be9ac847b94','寄澧州張舍人笛','杜牧','唐','唐诗','tang','','[]','髪勻肉好生春嶺，截玉鑽星寄使君。',64,'全唐诗/poet.tang.28000.json','["髪勻肉好生春嶺，截玉鑽星寄使君。", "檀的染時痕半月，落梅飄處響穿雲。", "樓中威鳳傾冠聽，沙上驚鴻掠水分。", "遙想紫泥封詔罷，夜深應隔禁墻聞。"]'),
('146f2975-7439-4e91-b13f-d9f1128ecd4b','寄揚州韓綽判官','杜牧','唐','唐诗','tang','','[]','青山隱隱水迢迢，秋盡江南草木凋。',32,'全唐诗/poet.tang.28000.json','["青山隱隱水迢迢，秋盡江南草木凋。", "二十四橋明月夜，玉人何處教吹簫。"]'),
('d1675d33-d1f9-45de-b62d-248b68ebd95a','送李羣玉赴舉','杜牧','唐','唐诗','tang','','[]','故人別來面如雪，一榻拂雲秋影中。',32,'全唐诗/poet.tang.28000.json','["故人別來面如雪，一榻拂雲秋影中。", "玉白花紅三百首，五陵誰唱與春風。"]'),
('daea041a-e25e-4e84-8259-6ea57f41d7bd','送薛種遊湖南','杜牧','唐','唐诗','tang','','["\u9001\u522b", "\u540c\u60c5"]','賈傅松醪酒，秋來美更香。',24,'全唐诗/poet.tang.28000.json','["賈傅松醪酒，秋來美更香。", "憐君片雲思，一去遶瀟湘。"]'),
('d7845e2e-507e-447c-88dc-81fa48ebe533','題壽安縣甘棠館御溝','杜牧','唐','唐诗','tang','','[]','一渠東注芳華苑，苑鏁池塘百歲空。',32,'全唐诗/poet.tang.28000.json','["一渠東注芳華苑，苑鏁池塘百歲空。", "水殿半傾蟾口澀，爲誰流下蓼花中。"]'),
('a9d1f98c-aa7c-47ab-8c78-22435044a3ac','汴河懷古','杜牧','唐','唐诗','tang','','[]','錦纜龍舟隋煬帝，平臺複道漢梁王。',32,'全唐诗/poet.tang.28000.json','["錦纜龍舟隋煬帝，平臺複道漢梁王。", "遊人閑起前朝念，折柳孤吟斷殺腸。"]'),
('c7c1509b-e03c-4a52-a794-15fd89bb2e01','汴河阻凍','杜牧','唐','唐诗','tang','','[]','千里長河初凍時，玉珂瑤珮響參差。',32,'全唐诗/poet.tang.28000.json','["千里長河初凍時，玉珂瑤珮響參差。", "浮生却似冰底水，日夜東流人不知。"]'),
('bf9aae5e-6233-4d81-a97a-b8d807856646','酬張祜處士見寄長句四韻','杜牧','唐','唐诗','tang','','[]','七子論詩誰似公，曹劉須在指揮中。',64,'全唐诗/poet.tang.28000.json','["七子論詩誰似公，曹劉須在指揮中。", "薦衡昔日知文舉，乞火無人作蒯通。", "北極樓臺長挂夢，西江波浪遠吞空。", "可憐故國三千里，虛唱歌詞滿六宮。"]'),
('63c2eec6-c998-4c11-8a77-858c8dd62cee','寄宣州鄭諫議','杜牧','唐','唐诗','tang','','[]','大夫官重醉江東，瀟灑名儒振古風。',64,'全唐诗/poet.tang.28000.json','["大夫官重醉江東，瀟灑名儒振古風。", "文石陛前辭聖主，碧雲天外作冥鴻。", "五言寧謝顏光祿，百歲須齊衛武公。", "再拜宜同丈人行，過庭交分有無同。"]'),
('cd95b67d-b48a-48b5-86d7-9013581bb1f8','題元處士高亭','杜牧','唐','唐诗','tang','','[]','水接西江天外聲，小齋松影拂雲平。',32,'全唐诗/poet.tang.28000.json','["水接西江天外聲，小齋松影拂雲平。", "何人教我吹長笛，與倚春風弄月明。"]'),
('537a4e19-aa23-4606-8bd1-f1a3a383582e','鄭瓘協律','杜牧','唐','唐诗','tang','','[]','廣文遺韻留樗散，雞犬圖書共一船。',32,'全唐诗/poet.tang.28000.json','["廣文遺韻留樗散，雞犬圖書共一船。", "自說江湖不歸事，阻風中酒過年年。"]'),
('c91696b5-4487-4bb7-9a31-2c08bbf65b31','和野人殷潛之題籌筆驛十四韻','杜牧','唐','唐诗','tang','','[]','三吳裂婺女，九錫獄孤兒。',168,'全唐诗/poet.tang.28000.json','["三吳裂婺女，九錫獄孤兒。", "霸主業未半，本朝心是誰。", "永安宮受詔，籌筆驛沈思。", "畫地乾坤在，濡毫勝負知。", "艱難同草創，得失計毫釐。", "寂默經千慮，分明渾一期。", "川流縈智思，山聳助扶持。", "慷慨匡時畧，從容問罪師。", "褒中秋鼓角，渭曲晚旌旗。", "仗義懸無敵，鳴攻故有辭。", "若非天奪去，豈復慮能支。", "子夜星纔落，鴻毛鼎便移。", "郵亭世自換，白日事長垂。", "何處躬耕者，猶題殄瘁詩。"]'),
('d2870b27-aad2-4db9-8dcf-c0cf664032ea','重題絕句一首','杜牧','唐','唐诗','tang','','[]','郵亭寄人世，人世寄郵亭。',24,'全唐诗/poet.tang.28000.json','["郵亭寄人世，人世寄郵亭。", "何如自籌度，鴻路有冥冥。"]'),
('34bb4ecb-16aa-46dd-b6f0-bf461ee71b86','送陸洿郎中棄官東歸','杜牧','唐','唐诗','tang','','[]','少微星動照春雲，魏闕衡門路自分。',32,'全唐诗/poet.tang.28000.json','["少微星動照春雲，魏闕衡門路自分。", "倏去忽來應有意，世間塵土謾疑君。"]'),
('c6015cfb-c874-426d-831f-2b43f4c355b5','寄珉笛與宇文舍人','杜牧','唐','唐诗','tang','','[]','調高銀字聲還側，物比柯亭韻校奇。',32,'全唐诗/poet.tang.28000.json','["調高銀字聲還側，物比柯亭韻校奇。", "寄與玉人天上去，桓將軍見不教吹。"]'),
('1a8ecdaf-bc64-4834-b6bd-12e6ac2e0454','寄內兄和州崔員外十二韻','杜牧','唐','唐诗','tang','','[]','歷陽崔太守，何日不含情。',144,'全唐诗/poet.tang.28000.json','["歷陽崔太守，何日不含情。", "恩義同鍾李，塤篪實弟兄。", "光塵能混合，擘畫最分明。", "臺閣仁賢譽，閨門孝友聲。", "西方像教毀，南海繡衣行。", "金橐寧迴顧，珠簟肯一棖。", "秪宜裁密詔，何自取專城。", "進退無非道，徊翔必有名。", "好風初婉軟，離思苦縈盈。", "金馬舊遊貴，桐廬春水生。", "雨侵寒牖夢，梅引凍醪傾。", "共祝中興主，高歌唱太平。"]'),
('2eadd251-6ddc-4e50-ba28-602207029aaa','遣興','杜牧','唐','唐诗','tang','','[]','鏡弄白髭鬚，如何作老夫。',48,'全唐诗/poet.tang.28000.json','["鏡弄白髭鬚，如何作老夫。", "浮生長勿勿，兒小且嗚嗚。", "忍過事堪喜，泰來憂勝無。", "治平心徑熟，不遣有窮途。"]'),
('922beb25-8b04-4750-b645-8374d4f8fd03','早秋','杜牧','唐','唐诗','tang','','[]','疎雨洗空曠，秋標驚意新。',48,'全唐诗/poet.tang.28000.json','["疎雨洗空曠，秋標驚意新。", "大熱去酷吏，清風來故人。", "尊酒酌未酌，晚花嚬不嚬。", "銖秤與縷雪，誰覺老陳陳。"]'),
('e74b915f-c7f9-4dda-a24d-937c88208020','秋思','杜牧','唐','唐诗','tang','','[]','熱去解鉗釱，飄蕭秋半時。',48,'全唐诗/poet.tang.28000.json','["熱去解鉗釱，飄蕭秋半時。", "微雨池塘見，好風襟袖知。", "髪短梳未足，枕涼閑且欹。", "平生分過此，何事不參差。"]'),
('dd17e0fb-67dd-48d6-83b0-56acff5988c8','途中一絕','杜牧','唐','唐诗','tang','','[]','鏡中絲髪悲來慣，衣上塵痕拂漸難。',32,'全唐诗/poet.tang.28000.json','["鏡中絲髪悲來慣，衣上塵痕拂漸難。", "惆悵江湖釣竿手，却遮西日向長安。"]'),
('8d2ede80-37d9-4a34-be93-9fce568c910c','春盡途中','杜牧','唐','唐诗','tang','','[]','田園不事來遊宦，故國誰教爾別離。',32,'全唐诗/poet.tang.28000.json','["田園不事來遊宦，故國誰教爾別離。", "獨倚關亭還把酒，一年春盡送春詩。"]'),
('c4acd9b4-09e3-4810-a9fd-9150c7dac5b7','題村舍','杜牧','唐','唐诗','tang','','[]','三樹稚桑春未到，扶床乳女午啼飢。',32,'全唐诗/poet.tang.28000.json','["三樹稚桑春未到，扶床乳女午啼飢。", "潛銷暗鑠歸何處，萬指侯家自不知。"]'),
('07c56081-1024-424f-965b-c3d127864bc4','代人寄遠六言二首 一','杜牧','唐','唐诗','tang','','[]','河橋酒斾風軟，候館梅花雪嬌。',28,'全唐诗/poet.tang.28000.json','["河橋酒斾風軟，候館梅花雪嬌。", "宛陵樓上瞪目，我郎何處情饒。"]'),
('49d60d9c-f57f-4e60-87d4-3b45e0ccd2bb','代人寄遠六言二首 二','杜牧','唐','唐诗','tang','','[]','繡領任垂蓬髻，丁香閑結春梢。',28,'全唐诗/poet.tang.28000.json','["繡領任垂蓬髻，丁香閑結春梢。", "賸肯新年歸否，江南綠草迢迢。"]'),
('36f57a15-2a27-4532-975c-161b1d7a1e58','閨情','杜牧','唐','唐诗','tang','','[]','娟娟却月眉，新鬢學鵶飛。',48,'全唐诗/poet.tang.28000.json','["娟娟却月眉，新鬢學鵶飛。", "暗砌勻檀粉，晴窓畫夾衣。", "袖紅垂寂寞，眉黛歛衣稀。", "還向長陵去，今宵歸不歸。"]'),
('8060dc9f-b2c9-4ccd-9279-0d53bca98c64','舊遊','杜牧','唐','唐诗','tang','','[]','閑吟芍藥詩，惆望久嚬眉。',48,'全唐诗/poet.tang.28000.json','["閑吟芍藥詩，惆望久嚬眉。", "盼眄迴眸遠，纖衫整髻遲。", "重尋春晝夢，笑把淺花枝。", "小市長陵住，非郎誰得知。"]'),
('130fca6a-c2b7-4b57-beee-768e935a0338','寄遠','杜牧','唐','唐诗','tang','','[]','隻影隨驚鴈，單棲鏁畫籠。',24,'全唐诗/poet.tang.28000.json','["隻影隨驚鴈，單棲鏁畫籠。", "向春羅袖薄，誰念舞臺風。"]'),
('9f5d62ed-875d-40ac-88b1-c6336b59ab5b','簾','杜牧','唐','唐诗','tang','','[]','徒云逢剪削，豈謂見偏裝。',72,'全唐诗/poet.tang.28000.json','["徒云逢剪削，豈謂見偏裝。", "鳳節輕雕日，鸞花薄餙香。", "問屏何屈曲，憐帳解周防。", "下漬金階露，斜分碧瓦霜。", "沈沈伴春夢，寂寂侍華堂。", "誰見昭陽殿，真珠十二行。"]'),
('6a1fd7c9-1dc8-4ac5-8058-5aa386dc1856','寄題甘露寺北軒','杜牧','唐','唐诗','tang','','[]','曾向蓬萊宮裏行，北軒闌檻最留情。',64,'全唐诗/poet.tang.28000.json','["曾向蓬萊宮裏行，北軒闌檻最留情。", "孤高堪弄桓伊笛，縹緲宜聞子晉笙。", "天接海門秋水色，煙籠隋苑暮鐘聲。", "他年會著荷衣去，不向山僧說姓名。"]'),
('d0cf18c5-08ff-47c9-8930-f7d58927d9a4','題青雲館','杜牧','唐','唐诗','tang','','[]','虬蟠千仞劇羊腸，天府由來百二強。',64,'全唐诗/poet.tang.28000.json','["虬蟠千仞劇羊腸，天府由來百二強。", "四皓有芝輕漢祖，張儀無地與懷王。", "雲連帳影蘿陰合，枕遶泉聲客夢涼。", "深處會容高尚者，水苗三頃百株桑。"]'),
('d0860fbf-265b-4eb4-a4e3-ff3b82b3aa59','正初奉酬歙州刺史邢羣','杜牧','唐','唐诗','tang','','[]','翠巖千尺倚溪斜，曾得嚴光作釣家。',64,'全唐诗/poet.tang.28000.json','["翠巖千尺倚溪斜，曾得嚴光作釣家。", "越嶂遠分丁字水，臘梅遲見二年花。", "明時刀尺君須用，幽處田園我有涯。", "一壑風烟陽羨里，解龜休去路非賒。"]'),
('7733c279-f1f6-438c-87a8-f494fa8e82c7','江上偶見絕句','杜牧','唐','唐诗','tang','','[]','楚江寒食橘花時，野渡臨風駐綵旗。',32,'全唐诗/poet.tang.28000.json','["楚江寒食橘花時，野渡臨風駐綵旗。", "草色連雲人去住，水紋如縠燕差池。"]'),
('bb1ab7cc-2152-4b7a-97aa-adb03543814d','題木蘭廟','杜牧','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4"]','彎弓征戰作男兒，夢裏曾經與畫眉。',32,'全唐诗/poet.tang.28000.json','["彎弓征戰作男兒，夢裏曾經與畫眉。", "幾度思歸還把酒，拂雲堆上祝明妃。"]'),
('2af955e5-da79-4ddc-8d15-db5a1e05c208','入商山','杜牧','唐','唐诗','tang','','[]','早入商山百里雲，藍溪橋下水聲分。',32,'全唐诗/poet.tang.28000.json','["早入商山百里雲，藍溪橋下水聲分。", "流水舊聲人舊耳，此迴嗚咽不堪聞。"]'),
('6e750cf9-5dd7-4949-92b7-4fce2ed39cc5','偶題','杜牧','唐','唐诗','tang','','[]','甘羅昔作秦丞相，子政曾爲漢輦郎。',32,'全唐诗/poet.tang.28000.json','["甘羅昔作秦丞相，子政曾爲漢輦郎。", "千載更逢王侍讀，當時還道有文章。"]'),
('c8616c0d-3a21-4d1e-8472-9f2baecd3730','送盧秀才一絕','杜牧','唐','唐诗','tang','','[]','春瀨與烟遠，送君孤櫂開。',24,'全唐诗/poet.tang.28000.json','["春瀨與烟遠，送君孤櫂開。", "潺湲如不改，愁更釣魚來。"]'),
('0658bc9e-eae6-4e6e-9516-10598fe4d89a','醉題','杜牧','唐','唐诗','tang','','[]','金鑷洗霜鬢，銀觥敵露桃。',24,'全唐诗/poet.tang.28000.json','["金鑷洗霜鬢，銀觥敵露桃。", "醉頭扶不起，三丈日還高。"]'),
('0141cac7-abc2-4371-8cec-4af251222696','題商山四皓廟一絕','杜牧','唐','唐诗','tang','','[]','呂氏強梁嗣子柔，我於天性豈恩讐。',32,'全唐诗/poet.tang.28000.json','["呂氏強梁嗣子柔，我於天性豈恩讐。", "南軍不袒左邊袖，四老安劉是滅劉。"]'),
('fd27d89f-a7ac-4693-8cac-3e936c03bafd','送隱者一絕','杜牧','唐','唐诗','tang','','["\u9690\u5c45", "\u5199\u4eba", "\u6292\u6000", "\u6000\u624d\u4e0d\u9047", "\u5199\u4eba\u8bd7"]','無媒徑路草蕭蕭，自古雲林遠市朝。',32,'全唐诗/poet.tang.28000.json','["無媒徑路草蕭蕭，自古雲林遠市朝。", "公道世間唯白髮，貴人頭上不曾饒。"]'),
('7a84b81f-8f14-4a52-bade-76474f4a4265','題張處士山莊一絕','杜牧','唐','唐诗','tang','','[]','好鳥疑敲磬，風蟬認軋箏。',24,'全唐诗/poet.tang.28000.json','["好鳥疑敲磬，風蟬認軋箏。", "修篁與嘉樹，偏倚半巖生。"]'),
('52afa82d-db98-41bc-95b0-638668f4b3a0','有懷重送斛斯判官','杜牧','唐','唐诗','tang','','[]','蒼蒼烟月滿川亭，我有勞歌一爲聽。',32,'全唐诗/poet.tang.28000.json','["蒼蒼烟月滿川亭，我有勞歌一爲聽。", "將取離魂隨白騎，三台星裏拜文星。"]'),
('54008cd0-f9bf-424f-bc55-f15c1e9025f3','贈別二首 一','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','娉娉褭褭十三餘，豆蔻梢頭二月初。',32,'全唐诗/poet.tang.28000.json','["娉娉褭褭十三餘，豆蔻梢頭二月初。", "春風十里揚州路，卷上珠簾總不如。"]'),
('a7f425de-143b-493d-bb51-13e27c68e871','贈別二首 二','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u79bb\u522b", "\u4e03\u8a00\u7edd\u53e5", "\u60dc\u522b"]','多情却似總無情，唯覺尊前笑不成。',32,'全唐诗/poet.tang.28000.json','["多情却似總無情，唯覺尊前笑不成。", "蠟燭有心還惜別，替人垂淚到天明。"]'),
('9d6486bc-d78c-4da4-b6e4-d44b964ca41c','寄遠','杜牧','唐','唐诗','tang','','[]','前山極遠碧雲合，清夜一聲白雪微。',32,'全唐诗/poet.tang.28000.json','["前山極遠碧雲合，清夜一聲白雪微。", "欲寄相思千里月，溪邊殘照雨霏霏。"]'),
('b10941a1-5365-4dee-b4dc-01bf00d10b32','少年行','杜牧','唐','唐诗','tang','','[]','官爲駿馬監，職帥羽林兒。',72,'全唐诗/poet.tang.28000.json','["官爲駿馬監，職帥羽林兒。", "兩綬藏不見，落花何處期？", "獵敲白玉鐙，怒袖紫金鎚。", "田竇長留醉，蘇辛曲讓岐。", "豪持出塞節，笑別遠山眉。", "捷報雲臺賀，公卿拜壽巵。"]'),
('624504f6-79e1-4ff4-85ef-38fb864fce36','盆池','杜牧','唐','唐诗','tang','','[]','鑿破蒼苔地，偷他一片天。',24,'全唐诗/poet.tang.28000.json','["鑿破蒼苔地，偷他一片天。", "白雲生鏡裏，明月落堦前。"]'),
('3a624d90-4a1d-4319-bbdd-e470fd96914b','有寄','杜牧','唐','唐诗','tang','','[]','雲闊煙深樹，江澄水浴秋。',24,'全唐诗/poet.tang.28000.json','["雲闊煙深樹，江澄水浴秋。", "美人何處在，明月萬山頭。"]'),
('045c7c1e-9eee-40a0-b81d-6431e8ba457f','斑竹筒簟','杜牧','唐','唐诗','tang','','[]','血染斑斑成錦紋，昔年遺恨至今存。',32,'全唐诗/poet.tang.28000.json','["血染斑斑成錦紋，昔年遺恨至今存。", "分明知是湘妃泣，何忍將身臥淚痕。"]'),
('edd29e7b-b762-43ed-978c-ad693c7ec708','和嚴惲秀才落花','杜牧','唐','唐诗','tang','','[]','共惜流年留不得，且環流水醉流杯。',32,'全唐诗/poet.tang.28000.json','["共惜流年留不得，且環流水醉流杯。", "無情紅豔年年盛，不恨凋零却恨開。"]'),
('f3f5e16e-dc85-4a1d-8668-de42da2b9853','倡樓戲贈','杜牧','唐','唐诗','tang','','[]','細柳橋邊深半春，纈衣簾裏動香塵。',32,'全唐诗/poet.tang.28000.json','["細柳橋邊深半春，纈衣簾裏動香塵。", "無端有寄閑消息，背插金釵笑向人。"]'),
('dfd18bd7-27b8-4502-9d4e-756edc9da381','初上船留寄','杜牧','唐','唐诗','tang','','[]','烟水本好尚，親交何慘悽。',48,'全唐诗/poet.tang.28000.json','["烟水本好尚，親交何慘悽。", "況爲珠履客，即泊錦帆堤。", "沙鴈同船去，田鵶遶岸啼。", "此時還有味，必臥日從西。"]'),
('03fbb30a-6407-405e-aa6a-2ac07781217e','秋岸','杜牧','唐','唐诗','tang','','[]','河岸微退落，柳影微彫疎。',48,'全唐诗/poet.tang.28000.json','["河岸微退落，柳影微彫疎。", "船上聽呼穉，堤南趁漉魚。", "數帆旗去疾，一艇箭迴初。", "曾入相思夢，因憑附遠書。"]'),
('65e14ccb-0e74-4d14-a441-7ea4c600b3b7','過大梁聞河亭方讌贈孫子端','杜牧','唐','唐诗','tang','','[]','梁園縱翫歸應少，賦雪搜才去必頻。',32,'全唐诗/poet.tang.28000.json','["梁園縱翫歸應少，賦雪搜才去必頻。", "板落豈緣無罰酒，不教客右更添人。"]'),
('00832388-93b3-4e79-bc30-5ab2ce6d5ee3','題吳興消暑樓十二韻','杜牧','唐','唐诗','tang','','[]','晴日登攀好，危樓物象饒。',144,'全唐诗/poet.tang.28000.json','["晴日登攀好，危樓物象饒。", "一溪通四境，萬岫饒層霄。", "鳥翼舒華屋，魚鱗棹短橈。", "浪花機乍織，雲葉匠新雕。", "臺榭羅嘉卉，城池敞麗譙。", "蟾蜍來作鑑，螮蝀引成橋。", "燕任隨秋葉，人空集早潮。", "楚鴻行盡直，沙鷺立偏翹。", "暮角淒遊旅，清歌慘泬寥。", "景牽遊目困，愁託酒腸銷。", "遠吹流松韻，殘陽渡柳橋。", "時陪庾公賞，還悟脫煩囂。"]'),
('c1647238-0c30-4e36-a495-f906bf968b6e','奉送中丞姊夫儔自大理卿出鎮江西敘事書懷因成十二韻','杜牧','唐','唐诗','tang','','[]','惟帝憂南紀，搜賢與大藩。',144,'全唐诗/poet.tang.28000.json','["惟帝憂南紀，搜賢與大藩。", "梅仙調步驟，庾亮拂橐鞬。", "一室何勞掃，三章自不冤。", "精明如定國，孤峻似陳蕃。", "灞岸秋猶嫩，藍橋水始喧。", "紅旓罣石壁，黑矟斷雲根。", "滕閣丹霄倚，章江碧玉奔。", "一聲仙妓唱，千里暮江痕。", "私好初童稚，官榮見子孫。", "流年休挂念，萬事至無言。", "玉輦君頻過，馮唐將未論。", "庸書醻萬債，竹塢問樊村。"]'),
('3505ad96-c84a-4b98-a39f-14ba342b75c1','中丞業深韜畧志在功名再奉長句一篇兼有諮勸','杜牧','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','檣似鄧林江拍天，越香巴錦萬千千。',64,'全唐诗/poet.tang.28000.json','["檣似鄧林江拍天，越香巴錦萬千千。", "滕王閣上柘枝鼓，徐孺亭西鐵軸船。", "八部元侯非不貴，萬人師長豈無權。", "要君嚴重疎歡樂，猶有河湟可下鞭。"]'),
('6f2cae42-5acf-4da1-a61f-72419368e255','和裴傑秀才新櫻桃','杜牧','唐','唐诗','tang','','[]','新果真瓊液，人應宴紫蘭。',72,'全唐诗/poet.tang.28000.json','["新果真瓊液，人應宴紫蘭。", "圓疑竊龍頷，色已奪雞冠。", "遠火微微辨，繁星歷歷看。", "茂先知味好，曼倩恨偷難。", "忍用烹酥酪，從將翫玉盤。", "流年如可駐，何必九華丹。"]'),
('6fdcd0fa-27a4-482b-bf8a-eaab0bc8bc42','春思','杜牧','唐','唐诗','tang','','[]','豈君心的的，嗟我淚涓涓。',48,'全唐诗/poet.tang.28000.json','["豈君心的的，嗟我淚涓涓。", "綿羽啼來久，錦鱗書未傳。", "獸壚凝冷焰，羅暮蔽晴煙。", "自是求佳夢，何須訝畫眠。"]'),
('94a19824-e433-4e6a-8f87-4c5a9cfe0ff9','代人作','杜牧','唐','唐诗','tang','','[]','樓高春日早，屏束麝煙堆。',96,'全唐诗/poet.tang.28000.json','["樓高春日早，屏束麝煙堆。", "盼眄凝魂別，依稀夢雨來。", "綠鬟羞妥麼，紅頰思天偎。", "鬬草憐香蕙，簪花間雪梅。", "戌遼雖咽切，遊蜀亦遲迴。", "錦字梭懸壁，琴心月滿臺。", "笑筵凝貝啓，眠箔曉珠開。", "臘破征車動，袍襟對淚裁。"]'),
('365b3c04-4d11-4731-82cc-d76e6c171c09','偶題二首 一','杜牧','唐','唐诗','tang','','[]','勞勞千里身，襟袂滿行塵。',48,'全唐诗/poet.tang.28000.json','["勞勞千里身，襟袂滿行塵。", "深夜懸雙淚，短亭思遠人。", "蒼江程未息，黑水夢何頻。", "明月輕橈去，唯應釣赤鱗。"]'),
('2b30699f-57ee-4173-b04f-68440e5ac8bd','偶題二首 二','杜牧','唐','唐诗','tang','','[]','有恨秋來極，無端別後知。',48,'全唐诗/poet.tang.28000.json','["有恨秋來極，無端別後知。", "夜闌終耿耿，明發竟遲遲。", "信已憑鴻去，歸唯與燕期。", "只因明月見，千里兩相思。"]'),
('887b1c4c-7031-43ee-9bfa-b296ea65e694','冬至日遇京使發寄舍弟','杜牧','唐','唐诗','tang','','[]','遠信初憑雙鯉去，他鄉正遇一陽生。',64,'全唐诗/poet.tang.28000.json','["遠信初憑雙鯉去，他鄉正遇一陽生。", "尊前豈解愁家國，輦下唯能憶弟兄。", "旅館夜憂姜被冷，暮江寒覺晏裘輕。", "竹門風過還惆悵，疑是松窗雪打聲。"]'),
('6ff67319-1420-431b-8919-47d3ce3dc52e','洛下送張曼容赴上黨召','杜牧','唐','唐诗','tang','','[]','歌闋罇殘恨却偏，憑君不用設離筵。',64,'全唐诗/poet.tang.28000.json','["歌闋罇殘恨却偏，憑君不用設離筵。", "未趍雉尾隨元老，且驀羊腸過少年。", "七葉漢貂真密近，一枝詵桂亦徒然。", "羽書正急徵兵地，須遣頭風處處痊。"]'),
('afef2ebf-09f0-4382-bd61-6fd6d976c5c4','宣州留贈','杜牧','唐','唐诗','tang','','[]','紅鉛濕盡半羅裙，洞府人間手欲分。',64,'全唐诗/poet.tang.28000.json','["紅鉛濕盡半羅裙，洞府人間手欲分。", "滿面風流雖似玉，四年夫婿恰如雲。", "當春離恨盃長滿，倚柱關情日漸曛。", "爲報眼波須穩當，五陵遊宕莫知聞。"]'),
('591996f4-bf22-4cdc-9b10-d0e4d76a08e3','寄題宣州開元寺','杜牧','唐','唐诗','tang','','[]','松寺曾同一鶴棲，夜深臺殿月高低。',32,'全唐诗/poet.tang.28000.json','["松寺曾同一鶴棲，夜深臺殿月高低。", "何人爲倚東樓柱，正是千山雪漲溪。"]'),
('9f1ed5a7-7e08-4763-9b30-022940f7873c','贈張祜','杜牧','唐','唐诗','tang','','[]','詩韻一逢君，平生稱所聞。',48,'全唐诗/poet.tang.28000.json','["詩韻一逢君，平生稱所聞。", "粉毫唯畫月，瓊尺只裁雲。", "鯨陣人人懾，秋星歷歷分。", "數篇留別我，羞殺李將軍。"]'),
('c2b0867f-6c2d-459d-be41-e134ab5980c5','殘春獨來南亭因寄張祜','杜牧','唐','唐诗','tang','','[]','暖雲如粉草如茵，獨步長堤不見人。',64,'全唐诗/poet.tang.28000.json','["暖雲如粉草如茵，獨步長堤不見人。", "一嶺桃花紅錦黦，半溪山水碧羅新。", "高枝百舌猶欺鳥，帶葉梨花獨送春。", "仲蔚欲知何處在，苦吟林下拂詩塵。"]'),
('40cc2a73-237a-486c-814d-7ee4b5ebc40f','宣州開元寺南樓','杜牧','唐','唐诗','tang','','[]','小樓纔受一牀橫，終日看山酒滿傾。',32,'全唐诗/poet.tang.28000.json','["小樓纔受一牀橫，終日看山酒滿傾。", "可惜和風夜來雨，醉中虛度打窗聲。"]'),
('e4aa94ca-3755-45ec-9498-c06bb0f3a0dc','寄遠人','杜牧','唐','唐诗','tang','','[]','終日求人卜，迴迴道好音。',24,'全唐诗/poet.tang.28000.json','["終日求人卜，迴迴道好音。", "那時離別後，入夢到如今。"]'),
('b4a303de-5b86-4c01-8ce8-a1dbf72c1809','別沈處士','杜牧','唐','唐诗','tang','','[]','舊事參差夢，新程邐迤秋。',24,'全唐诗/poet.tang.28000.json','["舊事參差夢，新程邐迤秋。", "故人如見憶，時到寺東樓。"]'),
('bacd210b-0cda-4410-abe0-ab047244236f','留贈','杜牧','唐','唐诗','tang','','[]','舞靴應任閑人看，笑臉還須待我開。',32,'全唐诗/poet.tang.28000.json','["舞靴應任閑人看，笑臉還須待我開。", "不用鏡前空有淚，薔薇花謝即歸來。"]'),
('c024c8e8-e428-4e6d-9745-3c2f3d18a0dd','奉和僕射相公春澤稍愆聖君軫慮嘉雪忽降品彙昭蘇即事書成四韻','杜牧','唐','唐诗','tang','','[]','飄來雞樹鳳池邊，漸壓瓊枝凍碧漣。',64,'全唐诗/poet.tang.28000.json','["飄來雞樹鳳池邊，漸壓瓊枝凍碧漣。", "銀闕雙高銀漢裏，玉山橫列玉墀前。", "昭陽殿下風迴急，承露盤中月彩圓。", "上相抽毫歌帝德，一篇風雅美豐年。"]'),
('38191316-4846-4ca6-8ae5-dd6f045c10a1','寄李播評事','杜牧','唐','唐诗','tang','','[]','子列光殊價，明時忍自高。',48,'全唐诗/poet.tang.28000.json','["子列光殊價，明時忍自高。", "寧無好舟檝，不泛惡風濤。", "大翼終難戢，奇鋒且自韜。", "春來煙渚上，幾淨雪霜毫。"]'),
('9c055fb2-6053-4b98-81b3-2d67d66a622e','送牛相出鎮襄州','杜牧','唐','唐诗','tang','','[]','盛時常注意，南雍暫分茅。',72,'全唐诗/poet.tang.28000.json','["盛時常注意，南雍暫分茅。", "紫殿辭明主，巖廊別舊交。", "危幢侵碧霧，寒斾獵紅旓。", "德業懸秦鏡，威聲隱楚郊。", "拜塵先灑淚，成廈昔容巢。", "遙仰沈碑會，鴛鴦玉佩敲。"]'),
('b42edbc6-fb78-402d-93eb-b8ecaa8f2e97','送薛邽二首 一','杜牧','唐','唐诗','tang','','[]','可憐走馬騎驢漢，豈有風光肯占伊。',32,'全唐诗/poet.tang.28000.json','["可憐走馬騎驢漢，豈有風光肯占伊。", "只有三張最惆悵，下山迴馬尚遲遲。"]'),
('4bd29207-6187-45f2-a2ad-f79c03d0f46c','送薛邽二首 二','杜牧','唐','唐诗','tang','','[]','小捷風流已俊才，便將紅粉作金臺。',32,'全唐诗/poet.tang.28000.json','["小捷風流已俊才，便將紅粉作金臺。", "明年未去池陽郡，更乞春時却重來。"]'),
('935bd7bc-a138-4dfb-8b26-f0fb92d6c05d','見穆三十宅中庭海榴花謝','杜牧','唐','唐诗','tang','','[]','矜紅掩素似多才，不待櫻桃不逐梅。',64,'全唐诗/poet.tang.28000.json','["矜紅掩素似多才，不待櫻桃不逐梅。", "春到未曾逢宴賞，雨餘爭解免低徊。", "巧窮南國千般豔，趁得春風二月開。", "堪恨王孫浪遊去，落英狼籍始歸來。"]'),
('744e9a24-dd66-49db-98ca-e4bc6fc9000e','留誨曹師等詩','杜牧','唐','唐诗','tang','','[]','萬物有醜好，各一姿狀分。',72,'全唐诗/poet.tang.28000.json','["萬物有醜好，各一姿狀分。", "唯人即不爾，學與不學論。", "學非探其花，要自撥其根。", "孝友與誠實，而不忘爾言。", "根本既深實，柯葉自滋繁。", "念爾無忽此，期以慶吾門。"]'),
('cde1f648-3c9a-4cf0-bfed-a6d332e68971','洛陽','杜牧','唐','唐诗','tang','','[]','文爭武戰就神功，時似開元天寶中。',64,'全唐诗/poet.tang.28000.json','["文爭武戰就神功，時似開元天寶中。", "已建玄戈收相土，應迴翠帽過離宮。", "侯門草滿宜寒兔，洛浦沙深下塞鴻。", "疑有女娥西望處，上陽煙樹正秋風。"]'),
('44df66a3-8658-4efd-82d8-1c81fa8e17c1','寄唐州李玭尚書','杜牧','唐','唐诗','tang','','[]','累代功勳照世光，奚胡聞道死心降。',64,'全唐诗/poet.tang.28000.json','["累代功勳照世光，奚胡聞道死心降。", "書功筆禿三千管，領節門排十六雙。", "先揖耿弇聲寂寂，今看黃霸事摐摐。", "時人欲識胸襟否，彭蠡秋連萬里江。"]'),
('b1baa48c-1fe5-4baf-ad05-ef892110b9cf','南陵道中','杜牧','唐','唐诗','tang','','["\u6292\u60c5", "\u5b64\u72ec", "\u5199\u666f"]','南陵水面漫悠悠，風緊雲輕欲變秋。',32,'全唐诗/poet.tang.28000.json','["南陵水面漫悠悠，風緊雲輕欲變秋。", "正是客心孤迴處，誰家紅袖凭江樓。"]'),
('856d779c-f973-4f04-89a1-35d661850f18','登九峰樓','杜牧','唐','唐诗','tang','','[]','晴江灩灩含淺沙，高低遶郭滯秋花。',48,'全唐诗/poet.tang.28000.json','["晴江灩灩含淺沙，高低遶郭滯秋花。", "牛歌魚笛山月上，鷺渚鶖梁溪日斜。", "爲郡異鄉徒泥酒，杜陵芳草豈無家。"]'),
('7ccb7b70-88c7-4456-bfc4-a311163907b7','別家','杜牧','唐','唐诗','tang','','[]','初歲嬌兒未識爺，別爺不拜手吒叉。',32,'全唐诗/poet.tang.28000.json','["初歲嬌兒未識爺，別爺不拜手吒叉。", "拊頭一別三千里，何日迎門却到家。"]'),
('1045aa50-9dce-4ad7-98a5-685b20577d2e','歸家','杜牧','唐','唐诗','tang','','[]','穉子牽衣問，歸來何太遲。',24,'全唐诗/poet.tang.28000.json','["穉子牽衣問，歸來何太遲。", "共誰爭歲月，贏得鬢邊絲。"]'),
('af2e6182-d775-47aa-b4d9-9782276dab41','雨','杜牧','唐','唐诗','tang','','[]','連雲接塞添迢遞，灑幕侵燈送寂寥。',32,'全唐诗/poet.tang.28000.json','["連雲接塞添迢遞，灑幕侵燈送寂寥。", "一夜不眠孤客耳，主人牕外有芭蕉。"]'),
('34be7e6b-2b22-4dde-9f70-4c4c353a499d','送人','杜牧','唐','唐诗','tang','','[]','鴛鴦帳裏暖芙蓉，低泣關山幾萬重。',32,'全唐诗/poet.tang.28000.json','["鴛鴦帳裏暖芙蓉，低泣關山幾萬重。", "明鏡半邊釵一股，此生何處不相逢。"]'),
('355ca8d1-8156-405f-bf92-306300aa2950','遣懷','杜牧','唐','唐诗','tang','','[]','道泰時還泰，時來命不來。',24,'全唐诗/poet.tang.28000.json','["道泰時還泰，時來命不來。", "何當離城市，高臥博山隈。"]'),
('1cc2085a-c6d6-47cf-b318-d0b7b5f0f03c','醉贈薛道封','杜牧','唐','唐诗','tang','','[]','飲酒論文四百刻，水分雲隔二三年。',32,'全唐诗/poet.tang.28000.json','["飲酒論文四百刻，水分雲隔二三年。", "男兒事業知公有，賣與明君直幾錢。"]'),
('9bcbe47d-5f86-486f-9331-b5767bd2bdc1','歙州盧中丞見惠名醖','杜牧','唐','唐诗','tang','','[]','誰憐賤子啓窮途，太守封來酒一壺。',64,'全唐诗/poet.tang.28000.json','["誰憐賤子啓窮途，太守封來酒一壺。", "攻破是非渾似夢，削平身世有如無。", "醺醺若借嵇康懶，兀兀仍添甯武愚。", "猶念悲秋更分賜，夾溪紅蓼映風蒲。"]'),
('b6e4d4dd-6e8a-430a-b2ba-7cbf27dae7be','詠襪','杜牧','唐','唐诗','tang','','[]','鈿尺裁量減四分，纖纖玉笋裹輕雲。',32,'全唐诗/poet.tang.28000.json','["鈿尺裁量減四分，纖纖玉笋裹輕雲。", "五陵年少欺他醉，笑把花前出畫裙。"]'),
('3031ec06-0355-494d-92cc-3a8e59c14c0c','宮詞二首 一','杜牧','唐','唐诗','tang','','[]','蟬翼輕綃傅體紅，玉膚如醉向春風。',32,'全唐诗/poet.tang.28000.json','["蟬翼輕綃傅體紅，玉膚如醉向春風。", "深宮鎖閉猶疑惑，更取丹沙試辟宮。"]'),
('7e64a32c-3280-4976-ba88-d1a228252032','宮詞二首 二','杜牧','唐','唐诗','tang','','[]','監宮引出暫開門，隨例須朝不是恩。',32,'全唐诗/poet.tang.28000.json','["監宮引出暫開門，隨例須朝不是恩。", "銀鑰却收金鎖合，月明花落又黃昏。"]'),
('eba9a9be-713d-490f-beeb-ed5207561d49','月','杜牧','唐','唐诗','tang','','[]','三十六宮秋夜深，昭陽歌斷信沈沈。',32,'全唐诗/poet.tang.28000.json','["三十六宮秋夜深，昭陽歌斷信沈沈。", "唯應獨伴陳皇后，照見長門望幸心。"]'),
('33ec79f1-061f-44ef-97f0-3ffaa3e1b3d8','忍死留別獻監鐵裴相公二十叔','杜牧','唐','唐诗','tang','','[]','賢相輔明主，蒼生壽域開。',48,'全唐诗/poet.tang.28000.json','["賢相輔明主，蒼生壽域開。", "青春辭白日，幽壤作黃埃。", "豈是無多士，偏蒙不棄才。", "孤墳三尺土，誰可爲培栽。"]'),
('13456be7-bc92-41c9-ae31-991f5fe92bb5','悲吳王城','杜牧','唐','唐诗','tang','','[]','二月春風江上來，水精波動碎樓臺。',64,'全唐诗/poet.tang.28000.json','["二月春風江上來，水精波動碎樓臺。", "吳王宮殿柳含翠，蘇小宅房花正開。", "解舞細腰何處往，能歌姹女逐誰迴。", "千秋萬古無消息，國作荒原人作灰。"]'),
('0dab2d47-1373-43bb-99b0-06b6d5129945','閨情代作','杜牧','唐','唐诗','tang','','[]','梧桐葉落鴈初歸，迢遞無因寄遠衣。',64,'全唐诗/poet.tang.28000.json','["梧桐葉落鴈初歸，迢遞無因寄遠衣。", "月照石泉金點冷，鳳酣簫管玉聲微。", "佳人刀杵秋風外，蕩子從征夢寐希。", "遙望戌樓天欲曉，滿城鼕鼓白雲飛。"]'),
('c8d3ec3e-a9de-48b3-bbf9-0def81e3e1c6','寄沈褒秀才','杜牧','唐','唐诗','tang','','[]','晴河萬里色如刀，處處浮雲臥碧桃。',64,'全唐诗/poet.tang.28000.json','["晴河萬里色如刀，處處浮雲臥碧桃。", "仙桂茂時金鏡曉，洛波飛處玉容高。", "雄如寶劒衝牛斗，麗似鴛鴦養羽毛。", "他日憶君何處望，九天香滿碧蕭騷。"]'),
('e23c0686-ed4f-49fe-bef0-87d3f0208bc9','入關','杜牧','唐','唐诗','tang','','[]','東西南北數衢通，曾取江西徑過東。',32,'全唐诗/poet.tang.28000.json','["東西南北數衢通，曾取江西徑過東。", "今日更尋南去路，未秋應有北歸鴻。"]'),
('f70b17f7-1b78-4f15-a342-a42d3ff8835f','及第後寄長安故人','杜牧','唐','唐诗','tang','','[]','東都放牓未花開，三十三人走馬迴。',32,'全唐诗/poet.tang.28000.json','["東都放牓未花開，三十三人走馬迴。", "秦地少年多釀酒，已將春色入關來。"]'),
('c1c063c6-ca9b-416b-9bfc-2c86bbb99f15','偶作','杜牧','唐','唐诗','tang','','[]','才子風流詠曉霞，倚樓吟住日初斜。',32,'全唐诗/poet.tang.28000.json','["才子風流詠曉霞，倚樓吟住日初斜。", "驚殺東隣繡牀女，錯將黃暈壓檀花。"]'),
('146a9f1c-7fc6-47b5-be72-f668cfc8373b','贈終南蘭若僧','杜牧','唐','唐诗','tang','','[]','北闕南山是故鄉，兩枝仙桂一時芳。',32,'全唐诗/poet.tang.28000.json','["北闕南山是故鄉，兩枝仙桂一時芳。", "休公都不知名姓，始覺禪門氣味長。"]'),
('92ae04dc-89af-45d6-9e31-204a01df801d','遣懷','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u6292\u6000"]','落魄江南載酒行，楚腰腸斷掌中輕。',32,'全唐诗/poet.tang.28000.json','["落魄江南載酒行，楚腰腸斷掌中輕。", "十年一覺揚州夢，贏得青樓薄倖名。"]'),
('a4e6c0b0-c1d7-4f12-9dd9-f96a10b81550','秋感','杜牧','唐','唐诗','tang','','[]','金風萬里思何盡，玉樹一窓秋影寒。',32,'全唐诗/poet.tang.28000.json','["金風萬里思何盡，玉樹一窓秋影寒。", "獨掩柴門明月下，淚流香袂倚闌干。"]'),
('ef9b9e25-0e0d-4eca-83c6-43d1b4fa241f','贈漁父','杜牧','唐','唐诗','tang','','[]','蘆花深澤靜垂綸，月夕煙朝幾十春。',32,'全唐诗/poet.tang.28000.json','["蘆花深澤靜垂綸，月夕煙朝幾十春。", "自說孤舟寒水畔，不曾逢著獨醒人。"]'),
('ffc847e7-2310-4a97-94e1-0ae702802599','歎花','杜牧','唐','唐诗','tang','','[]','自恨尋芳到已遲，往年曾見未開時。',32,'全唐诗/poet.tang.28000.json','["自恨尋芳到已遲，往年曾見未開時。", "如今風擺花狼籍，綠葉成陰子滿枝。"]'),
('ddc766a7-d68e-4866-8605-c629e84ac134','題劉秀才新竹','杜牧','唐','唐诗','tang','','[]','數莖幽玉色，曉夕翠煙分。',48,'全唐诗/poet.tang.28000.json','["數莖幽玉色，曉夕翠煙分。", "聲破寒窗夢，根穿綠蘚紋。", "漸籠當檻日，欲礙入簾雲。", "不是山陰客，何人愛此君。"]'),
('56da3304-439a-400b-b283-16de3add74ce','山行','杜牧','唐','唐诗','tang','','["\u4e8c\u5e74\u7ea7\u4e0a\u518c", "\u5199\u666f", "\u79cb\u5929", "\u690d\u7269", "\u5c71", "\u8a00\u5fd7"]','遠上寒山石徑斜，白雲生處有人家。',32,'全唐诗/poet.tang.28000.json','["遠上寒山石徑斜，白雲生處有人家。", "停車坐愛楓林晚，霜葉紅於二月花。"]'),
('ea52e3d8-e8b5-4acd-a85f-74d13d22048a','書懷','杜牧','唐','唐诗','tang','','[]','滿眼青山未得過，鏡中無那鬢絲何。',32,'全唐诗/poet.tang.28000.json','["滿眼青山未得過，鏡中無那鬢絲何。", "秖言旋老轉無事，欲到中年事更多。"]'),
('7cc1af10-9062-47ef-aedb-ff11013997c4','紫薇花','杜牧','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u82b1", "\u548f\u7269", "\u5199\u82b1"]','曉迎秋露一枝新，不占園中最上春。',32,'全唐诗/poet.tang.28000.json','["曉迎秋露一枝新，不占園中最上春。", "桃李無言又何在，向風偏笑豔陽人。"]'),
('e7162d8b-3d05-4385-a92a-0a6ddf32e7d0','醉後呈崔大夫','杜牧','唐','唐诗','tang','','[]','謝傅秋涼閱管弦，徒教賤子侍華筵。',32,'全唐诗/poet.tang.28000.json','["謝傅秋涼閱管弦，徒教賤子侍華筵。", "溪頭正雨歸不得，辜負東窓一覺眠。"]'),
('6980e261-1fc5-4972-9b07-650f312434b0','和宣州沈大夫登北樓書懷','杜牧','唐','唐诗','tang','','[]','兵符嚴重辭金馬，星劒光芒射斗牛。',64,'全唐诗/poet.tang.28000.json','["兵符嚴重辭金馬，星劒光芒射斗牛。", "筆落青山飄古韻，帳開紅斾照高秋。", "香連日彩浮綃幕，溪逐歌聲遶畫樓。", "可惜登臨佳麗地，羽儀須去鳳池遊。"]'),
('4dbd4fda-b163-459c-be32-d8a68f109ea0','夜雨','杜牧','唐','唐诗','tang','','[]','九月三十日，雨聲如別秋。',48,'全唐诗/poet.tang.28000.json','["九月三十日，雨聲如別秋。", "無端滿階葉，共白幾人頭。", "點滴侵寒夢，蕭騷著淡愁。", "漁歌聽不唱，蓑濕棹迴舟。"]'),
('f227dee2-18e9-4d48-8e35-f1334c178d14','方響','杜牧','唐','唐诗','tang','','[]','數條秋水挂琅玕，玉手丁當怕夜寒。',32,'全唐诗/poet.tang.28000.json','["數條秋水挂琅玕，玉手丁當怕夜寒。", "曲盡連敲三四下，恐驚珠淚落金盤。"]'),
('62c7187b-f03e-4d9f-b214-4eb888efe7b3','將出關宿層峰驛却寄李諫議','杜牧','唐','唐诗','tang','','[]','孤驛在重阻，雲根掩柴扉。',48,'全唐诗/poet.tang.28000.json','["孤驛在重阻，雲根掩柴扉。", "數聲暮禽切，萬壑秋意歸。", "心馳碧泉澗，目斷青瑣闈。", "明日武關外，夢魂勞遠飛。"]'),
('f0b64169-685b-4a85-b9fa-5d45bb30b487','使回枉唐州崔司馬書兼寄四韻因和','杜牧','唐','唐诗','tang','','[]','清晨候吏把書來，十載離憂得暫開。',64,'全唐诗/poet.tang.28000.json','["清晨候吏把書來，十載離憂得暫開。", "癡叔去時還讀易，仲容多興索銜杯。", "人心計日殷勤望，馬首隨雲早晚迴。", "莫爲霜臺愁歲暮，潛龍須待一聲雷。"]'),
('29031e87-be6f-46b1-9387-e2a9d9083231','郡齋秋夜即事寄斛斯處士許秀才','杜牧','唐','唐诗','tang','','[]','有客誰人肯夜過，獨憐風景奈愁何。',64,'全唐诗/poet.tang.28000.json','["有客誰人肯夜過，獨憐風景奈愁何。", "邊鴻怨處迷霜久，庭樹空來見月多。", "故國杳無千里信，綵弦時伴一聲歌。", "馳心秖待城烏曉，幾對虛簷望白河。"]'),
('353c08bf-bf93-41e2-8c1e-826514703eab','早春題真上人院','杜牧','唐','唐诗','tang','','[]','清羸已近百年身，古寺風煙又一春。',32,'全唐诗/poet.tang.28000.json','["清羸已近百年身，古寺風煙又一春。", "寰海自成戎馬地，唯師曾是太平人。"]'),
('67d883cb-709d-4742-89fe-d98489e24baf','對花微疾不飲呈坐中諸公','杜牧','唐','唐诗','tang','','[]','花前雖病亦提壺，數調持觴興有無。',32,'全唐诗/poet.tang.28000.json','["花前雖病亦提壺，數調持觴興有無。", "盡日臨風羨人醉，雪香空伴白髭鬚。"]'),
('53dc5577-4c52-4f22-bf67-05d23d2be2a8','酬王秀才桃花園見寄','杜牧','唐','唐诗','tang','','[]','桃滿西園淑景催，幾多紅豔淺深開。',32,'全唐诗/poet.tang.28000.json','["桃滿西園淑景催，幾多紅豔淺深開。", "此花不逐溪流出，晉客無因入洞來。"]'),
('a0aaa787-f317-4f0c-9f55-9b9dc8463f0c','走筆送杜十三歸京','杜牧','唐','唐诗','tang','','[]','煙鴻上漢聲聲遠，逸驥尋雲步步高。',32,'全唐诗/poet.tang.28000.json','["煙鴻上漢聲聲遠，逸驥尋雲步步高。", "應笑內兄年六十，郡城閑坐養霜毛。"]'),
('c2a1d27e-cb12-4271-8a72-8b6502fee9d9','送王十至褒中因寄尚書','杜牧','唐','唐诗','tang','','[]','闕下經年別，人間兩地情。',48,'全唐诗/poet.tang.28000.json','["闕下經年別，人間兩地情。", "壇場新漢將，煙月古隋城。", "鴈去梁山遠，雲高楚岫明。", "君家荷藕好，緘恨寄遙程。"]'),
('76fd16e7-c7d2-4fc6-8c62-6e8b218b800c','後池泛舟送王十','杜牧','唐','唐诗','tang','','[]','相送西郊暮景和，青蒼竹外遶寒波。',32,'全唐诗/poet.tang.28000.json','["相送西郊暮景和，青蒼竹外遶寒波。", "爲君蘸甲十分飲，應見離心一倍多。"]'),
('33602a34-aa2e-4929-8a79-11e06a21da22','重送王十','杜牧','唐','唐诗','tang','','[]','執袂還應立馬看，向來離思始知難。',32,'全唐诗/poet.tang.28000.json','["執袂還應立馬看，向來離思始知難。", "鴈飛不見行塵滅，景下山遙極目寒。"]'),
('dfad7953-8549-4d8d-a571-1e1aa1feda0f','洛陽秋夕','杜牧','唐','唐诗','tang','','[]','泠泠寒水帶霜風，更在天橋夜景中。',32,'全唐诗/poet.tang.28000.json','["泠泠寒水帶霜風，更在天橋夜景中。", "清禁漏閑煙樹寂，月輪移在上陽宮。"]'),
('4ffa9bea-4f65-4901-b0a4-601d88e106b9','贈獵騎','杜牧','唐','唐诗','tang','','[]','已落雙鵰血尚新，鳴鞭走馬又翻身。',32,'全唐诗/poet.tang.28000.json','["已落雙鵰血尚新，鳴鞭走馬又翻身。", "憑君莫射南來鴈，恐有家書寄遠人。"]'),
('9f2eb708-7679-453d-91d0-55c84debc2ad','懷吳中馮秀才','杜牧','唐','唐诗','tang','','[]','長洲苑外草蕭蕭，却筭遊程歲月遙。',32,'全唐诗/poet.tang.28000.json','["長洲苑外草蕭蕭，却筭遊程歲月遙。", "唯有別時今不忘，暮煙秋雨過楓橋。"]'),
('a9a4d2fe-dd84-472e-8b48-222754dcd330','寄東塔僧','杜牧','唐','唐诗','tang','','[]','初月微明漏白煙，碧松梢外挂青天。',32,'全唐诗/poet.tang.28000.json','["初月微明漏白煙，碧松梢外挂青天。", "西風靜起傳深夜，應送愁吟入夜禪。"]'),
('d12edd29-d467-4b19-b3f5-533fa5c8d56a','秋夕','杜牧','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','紅燭秋光冷畫屏，輕羅小扇撲流螢。',32,'全唐诗/poet.tang.28000.json','["紅燭秋光冷畫屏，輕羅小扇撲流螢。", "天階夜色涼如水，坐看牽牛織女星。"]'),
('a8be77ff-dde3-4aa7-808f-66ff1bfbd378','瑤瑟','杜牧','唐','唐诗','tang','','[]','玉仙瑤瑟夜珊珊，月過樓西桂燭殘。',32,'全唐诗/poet.tang.28000.json','["玉仙瑤瑟夜珊珊，月過樓西桂燭殘。", "風景人間不如此，動搖湘水徹明寒。"]'),
('1e926c44-9848-4678-ac14-0ea84a50559f','送故人歸山','杜牧','唐','唐诗','tang','','[]','三清洞裏無端別，又拂塵衣欲臥雲。',32,'全唐诗/poet.tang.28000.json','["三清洞裏無端別，又拂塵衣欲臥雲。", "看著挂冠迷處所，北山蘿月在移文。"]'),
('2c4e9bb7-d960-4805-a2a5-a743c48bd9f5','聞角','杜牧','唐','唐诗','tang','','[]','曉樓煙檻出雲霄，景下林塘已寂寥。',32,'全唐诗/poet.tang.28000.json','["曉樓煙檻出雲霄，景下林塘已寂寥。", "城角爲秋悲更遠，護霜雲破海天遙。"]'),
('976afd1d-415d-4389-8678-87707fc981e7','押兵甲發谷口寄諸公','杜牧','唐','唐诗','tang','','[]','曉澗青青桂色孤，楚人隨玉上天衢。',32,'全唐诗/poet.tang.28000.json','["曉澗青青桂色孤，楚人隨玉上天衢。", "水辭谷口山寒少，今日風頭校暖無。"]'),
('1d9b1618-e32a-40c0-abee-7ffc7ed21123','和令狐侍御賞蕙草','杜牧','唐','唐诗','tang','','[]','尋常詩思巧如春，又喜幽亭蕙草新。',32,'全唐诗/poet.tang.28000.json','["尋常詩思巧如春，又喜幽亭蕙草新。", "本是馨香比君子，遶欄今更爲何人。"]'),
('f41835e6-0f1a-4bde-8ff7-f657f5a93d9c','偶題','杜牧','唐','唐诗','tang','','[]','道在人間或可傳，小還輕變已多年。',32,'全唐诗/poet.tang.28000.json','["道在人間或可傳，小還輕變已多年。", "今來海上昇高望，不到蓬萊不是仙。"]'),
('fa7b8a30-a906-4697-9fda-433d36fd829a','三川驛伏覽座主舍人留題','杜牧','唐','唐诗','tang','','[]','舊跡依然已十秋，雪山當面照銀鉤。',32,'全唐诗/poet.tang.28000.json','["舊跡依然已十秋，雪山當面照銀鉤。", "懷恩淚盡霜天曉，一片餘霞映驛樓。"]'),
('b74318ae-8c3e-44cd-9743-c51b02789e0b','陝州醉贈裴四同年','杜牧','唐','唐诗','tang','','[]','淒風洛下同羈思，遲日棠陰得醉歌。',32,'全唐诗/poet.tang.28000.json','["淒風洛下同羈思，遲日棠陰得醉歌。", "自笑與君三歲別，頭銜依舊鬢絲多。"]'),
('049f3daf-df10-4f32-b819-604f5642c64b','破鏡','杜牧','唐','唐诗','tang','','[]','佳人失手鏡初分，何日團圓再會君。',32,'全唐诗/poet.tang.28000.json','["佳人失手鏡初分，何日團圓再會君。", "今朝萬里秋風起，山北山南一片雲。"]'),
('f25016b2-eeed-483c-9f4d-a3c093c77f0f','長安雪後','杜牧','唐','唐诗','tang','','[]','秦陵漢苑參差雪，北闕南山次第春。',32,'全唐诗/poet.tang.28000.json','["秦陵漢苑參差雪，北闕南山次第春。", "車馬滿城原上去，豈知惆悵有閑人。"]');
